module.exports = /*#__PURE__*/JSON.parse('{"translations":{"krv":{"label":"개역한글","note":"성경전서 개역한글판 (대한성서공회, 1961). 저작권 보호기간 만료 공공저작물."},"kids":{"label":"쉬운말","note":"쉬운말 — 어린이용 의역"}},"chapters":[{"chapter":1,"title":"예수님의 사역 시작","verses":{"krv":[{"n":1,"t":"하나님의 아들 예수 그리스도 복음의 시작이라"},{"n":2,"t":"선지자 이사야의 글에 보라 내가 내 사자를 네 앞에 보내노니 저가 네 길을 예비하리라"},{"n":3,"t":"광야에 외치는 자의 소리가 있어 가로되 너희는 주의 길을 예비하라 그의 첩경을 평탄케 하라 기록된 것과 같이"},{"n":4,"t":"세례요한이 이르러 광야에서 죄 사함을 받게 하는 회개의 세례를 전파하니"},{"n":5,"t":"온 유대 지방과 예루살렘 사람이 다 나아가 자기 죄를 자복하고 요단강에서 그에게 세례를 받더라"},{"n":6,"t":"요한은 약대털을 입고 허리에 가죽띠를 띠고 메뚜기와 석청을 먹더라"},{"n":7,"t":"그가 전파하여 가로되 나보다 능력 많으신 이가 내 뒤에 오시나니 나는 굽혀 그의 신들메를 풀기도 감당치 못하겠노라"},{"n":8,"t":"나는 너희에게 물로 세례를 주었거니와 그는 성령으로 너희에게 세례를 주시리라"},{"n":9,"t":"그 때에 예수께서 갈릴리 나사렛으로부터 와서 요단강에서 요한에게 세례를 받으시고"},{"n":10,"t":"곧 물에서 올라 오실쌔 하늘이 갈라짐과 성령이 비둘기 같이 자기에게 내려오심을 보시더니"},{"n":11,"t":"하늘로서 소리가 나기를 너는 내 사랑하는 아들이라 내가 너를 기뻐하노라 하시니라"},{"n":12,"t":"성령이 곧 예수를 광야로 몰아내신지라"},{"n":13,"t":"광야에서 사십일을 계셔서 사단에게 시험을 받으시며 들짐승과 함께 계시니 천사들이 수종들더라"},{"n":14,"t":"요한이 잡힌 후 예수께서 갈릴리에 오셔서 하나님의 복음을 전파하여"},{"n":15,"t":"가라사대 때가 찼고 하나님 나라가 가까왔으니 회개하고 복음을 믿으라 하시더라"},{"n":16,"t":"갈릴리 해변으로 지나가시다가 시몬과 그 형제 안드레가 바다에 그물 던지는 것을 보시니 저희는 어부라"},{"n":17,"t":"예수께서 가라사대 나를 따라 오너라 내가 너희로 사람을 낚는 어부가 되게 하리라 하시니"},{"n":18,"t":"곧 그물을 버려 두고 좇으니라"},{"n":19,"t":"조금 더 가시다가 세베대의 아들 야고보와 그 형제 요한을 보시 니 저희도 배에 있어 그물을 깁는데"},{"n":20,"t":"곧 부르시니 그 아비 세베대를 삯군들과 함께 배에 버려 두고 예수를 따라가니라"},{"n":21,"t":"저희가 가버나움에 들어가니라 예수께서 곧 안식일에 회당에 들어가 가르치시매"},{"n":22,"t":"뭇사람이 그의 교훈에 놀라니 이는 그 가르치시는 것이 권세 있는 자와 같고 서기관들과 같지 아니함일러라"},{"n":23,"t":"마침 저희 회당에 더러운 귀신 들린 사람이 있어 소리질러 가로되"},{"n":24,"t":"나사렛 예수여 우리가 당신과 무슨 상관이 있나이까 우리를 멸하러 왔나이까 나는 당신이 누구인줄 아노니 하나님의 거룩한 자니이다"},{"n":25,"t":"예수께서 꾸짖어 가라사대 잠잠하고 그 사람에게서 나오라 하시니"},{"n":26,"t":"더러운 귀신이 그 사람으로 경련을 일으키게 하고 큰 소리를 지르며 나오는지라"},{"n":27,"t":"다 놀라 서로 물어 가로되 이는 어찜이뇨 권세 있는 새 교훈이로다 더러운 귀신들을 명한즉 순종하는도다 하더라"},{"n":28,"t":"예수의 소문이 곧 온 갈릴리 사방에 퍼지더라"},{"n":29,"t":"회당에서 나와 곧 야고보와 요한과 함께 시몬과 안드레의 집에 들어가시니"},{"n":30,"t":"시몬의 장모가 열병으로 누웠는지라 사람들이 곧 그의 일로 예수께 여짜온대"},{"n":31,"t":"나아가사 그 손을 잡아 일으키시니 열병이 떠나고 여자가 저희에게 수종드니라"},{"n":32,"t":"저물어 해 질 때에 모든 병자와 귀신 들린 자를 예수께 데려오니"},{"n":33,"t":"온 동네가 문앞에 모였더라"},{"n":34,"t":"예수께서 각색 병든 많은 사람을 고치시며 많은 귀신을 내어 쫓으시되 귀신이 자기를 알므로 그 말하는 것을 허락지 아니하시니라"},{"n":35,"t":"새벽 오히려 미명에 예수께서 일어나 나가 한적한 곳으로 가사 거기서 기도하시더니"},{"n":36,"t":"시몬과 및 그와 함께 있는 자들이 예수의 뒤를 따라가"},{"n":37,"t":"만나서 가로되 모든 사람이 주를 찾나이다"},{"n":38,"t":"이르시되 우리가 다른 가까운 마을들로 가자 거기서도 전도하리니 내가 이를 위하여 왔노라 하시고"},{"n":39,"t":"이에 온 갈릴리에 다니시며 저희 여러 회당에서 전도하시고 또 귀신들을 내어 쫓으시더라"},{"n":40,"t":"한 문둥병자가 예수께 와서 꿇어 엎드리어 간구하여 가로되 원하시면 저를 깨끗케 하실 수 있나이다"},{"n":41,"t":"예수께서 민망히 여기사 손을 내밀어 저에게 대시며 가라사대 내가 원하노니 께끗함을 받으라 하신대"},{"n":42,"t":"곧 문둥병이 그 사람에게서 떠나가고 깨끗하여진지라"},{"n":43,"t":"엄히 경계하사 곧 보내시며"},{"n":44,"t":"가라사대 삼가 아무에게 아무 말도 하지 말고 가서 네 몸을 제사장에게 보이고 네 깨끗케 됨을 인하여 모세의 명한 것을 드려 저희에게 증거하라 하셨더니"},{"n":45,"t":"그러나 그 사람이 나가서 이 일을 많이 전파하여 널리 퍼지게 하니 그러므로 예수께서 다시는 드러나게 동네에 들어가지 못하시고 오직 바깥 한적한 곳에 계셨으나 사방에서 그에게로 나아오더라"}],"kids":[{"n":1,"t":"하나님의 아들 예수 그리스도의 복음 이야기가 이렇게 시작돼요."},{"n":2,"t":"예언자 이사야의 글에 이렇게 적혀 있어요. \\"보라, 내가 내 사자를 너보다 먼저 보내. 그가 네 길을 예비할 거야.\\""},{"n":3,"t":"\\"광야에서 외치는 자의 소리가 있어. \'주의 길을 예비하고 그 길을 곧게 하라.\'\\""},{"n":4,"t":"세례 요한이 광야에 나타나서 죄 용서를 위한 회개의 세례를 전했어요."},{"n":5,"t":"온 유대와 예루살렘 사람들이 다 그에게 나아와 자기 죄를 고백하며 요단강에서 세례를 받았어요."},{"n":6,"t":"요한은 낙타털 옷을 입고 허리에 가죽 띠를 두르고, 메뚜기와 들꿀을 먹으며 살았어요."},{"n":7,"t":"요한이 전했어요. \\"나보다 능력이 크신 분이 내 뒤에 오셔. 나는 몸을 굽혀 그분의 신발 끈도 풀어 드릴 자격이 없어.\\""},{"n":8,"t":"\\"나는 너희에게 물로 세례를 주지만 그분은 너희에게 성령으로 세례를 주실 거야.\\""},{"n":9,"t":"그 무렵 예수님이 갈릴리 나사렛에서 오셔서 요단강에서 요한에게 세례를 받으셨어요."},{"n":10,"t":"물에서 올라오실 때, 하늘이 갈라지고 성령이 비둘기처럼 그분 위에 내려오는 것을 보셨어요."},{"n":11,"t":"하늘에서 소리가 들렸어요. \\"너는 내 사랑하는 아들이야. 내가 너를 매우 기뻐해.\\""},{"n":12,"t":"성령이 곧 예수님을 광야로 내모셨어요."},{"n":13,"t":"예수님은 광야에서 사십 일 동안 사탄에게 시험을 받으셨어요. 들짐승과 함께 계셨고 천사들이 그분을 섬겼어요."},{"n":14,"t":"요한이 잡힌 후에 예수님이 갈릴리에 오셔서 하나님의 복음을 전하셨어요."},{"n":15,"t":"\\"때가 찼고 하나님 나라가 가까이 왔어요. 회개하고 복음을 믿어요.\\""},{"n":16,"t":"예수님이 갈릴리 호숫가를 지나가시다가 시몬과 그의 동생 안드레가 호수에 그물을 던지는 것을 보셨어요. 그들은 어부였어요."},{"n":17,"t":"예수님이 \\"나를 따라오너라. 사람을 낚는 어부가 되게 해 줄게\\" 하셨어요."},{"n":18,"t":"그들이 곧 그물을 버리고 예수님을 따랐어요."},{"n":19,"t":"조금 더 가시다가 세베대의 아들 야고보와 그의 동생 요한을 보셨어요. 그들도 배에서 그물을 손질하고 있었어요."},{"n":20,"t":"예수님이 곧 그들을 부르시니, 그들도 자기 아버지 세베대를 일꾼들과 함께 배에 두고 예수님을 따랐어요."},{"n":21,"t":"그들이 가버나움에 들어갔어요. 안식일에 예수님이 곧 회당에 들어가 가르치셨어요."},{"n":22,"t":"사람들이 그분의 가르침에 놀랐어요. 율법 학자들과 달리 권세 있는 분처럼 가르치셨거든요."},{"n":23,"t":"그때 그들 회당에 더러운 영 들린 사람이 있었어요. 그가 소리쳤어요."},{"n":24,"t":"\\"나사렛 예수여, 우리와 무슨 상관이세요? 우리를 멸하러 왔어요? 당신이 누구인지 알아요. 하나님의 거룩하신 분이에요.\\""},{"n":25,"t":"예수님이 꾸짖으셨어요. \\"잠잠하고 그 사람에게서 나오너라.\\""},{"n":26,"t":"더러운 영이 그 사람을 경련시키고 큰 소리를 지르며 나갔어요."},{"n":27,"t":"모두가 놀라서 서로 물었어요. \\"이게 어찌된 일이야? 권세 있는 새 가르침이다! 더러운 영에게도 명령하시니 따르네.\\""},{"n":28,"t":"예수님의 소문이 곧 갈릴리 온 지역에 퍼졌어요."},{"n":29,"t":"회당에서 나오자마자 야고보와 요한과 함께 시몬과 안드레의 집으로 가셨어요."},{"n":30,"t":"시몬의 장모가 열병으로 누워 있었어요. 사람들이 그 일을 예수님께 말씀드렸어요."},{"n":31,"t":"예수님이 가서 그녀의 손을 잡고 일으키시자 열이 떠나갔고, 그녀가 그들을 섬겼어요."},{"n":32,"t":"저녁이 되어 해가 질 때, 사람들이 모든 병자와 귀신 들린 사람을 예수님께 데리고 왔어요."},{"n":33,"t":"온 동네 사람들이 문 앞에 모였어요."},{"n":34,"t":"예수님은 여러 가지 병을 앓는 많은 사람들을 고치시고 많은 귀신을 쫓아내셨어요. 그리고 귀신들이 말하는 것을 허락하지 않으셨어요. 그들이 예수님을 알았기 때문이에요."},{"n":35,"t":"이른 새벽에 예수님이 일어나 한적한 곳으로 가셔서 거기서 기도하셨어요."},{"n":36,"t":"시몬과 일행이 예수님을 찾으러 왔어요."},{"n":37,"t":"예수님을 만나 \\"모든 사람이 주님을 찾아요\\" 하고 말했어요."},{"n":38,"t":"예수님이 \\"가까운 다른 동네들로 가자. 거기서도 전하고 싶어. 이를 위해 내가 왔거든\\" 하셨어요."},{"n":39,"t":"예수님이 갈릴리 곳곳을 다니시며 그들의 회당에서 전하시고 귀신들을 쫓아내셨어요."},{"n":40,"t":"나병 환자 한 사람이 와서 무릎을 꿇고 청했어요. \\"원하시면 저를 깨끗하게 하실 수 있어요.\\""},{"n":41,"t":"예수님이 불쌍히 여겨 손을 내밀어 그를 만지며 \\"원해. 깨끗해져라\\" 하셨어요."},{"n":42,"t":"곧 나병이 떠나가고 그가 깨끗해졌어요."},{"n":43,"t":"예수님이 엄히 경고하시고 곧 보내며,"},{"n":44,"t":"\\"아무에게도 말하지 마. 가서 제사장에게 네 몸을 보이고 모세가 명령한 것을 드려서 그들에게 증거가 되게 해\\" 하셨어요."},{"n":45,"t":"그러나 그 사람이 나가서 이 일을 많이 알리고 퍼뜨려, 예수님이 더 이상 동네에 드러내 놓고 들어가시지 못하고 바깥 한적한 곳에 머무셨어요. 그래도 사람들이 사방에서 그분께 나아왔어요."}]}},{"chapter":2,"title":"죄를 사하시는 권세","verses":{"krv":[{"n":1,"t":"수일후에 예수께서 다시 가버나움에 들어가시니 집에 계신 소문이 들린지라"},{"n":2,"t":"많은 사람이 모여서 문 앞에라도 용신할 수 없게 되었는데 예수께서 저희에게 도를 말씀하시더니"},{"n":3,"t":"사람들이 한 중풍병자를 네 사람에게 메워 가지고 예수께로 올새"},{"n":4,"t":"무리를 인하여 예수께 데려갈 수 없으므로 그 계신 곳의 지붕을 뜯어 구멍을 내고 중풍병자의 누운 상을 달아내리니"},{"n":5,"t":"예수께서 저희의 믿음을 보시고 중풍병자에게 이르시되 소자야 네 죄 사함을 받았느니라 하시니"},{"n":6,"t":"어떤 서기관들이 거기 앉아서 마음에 의논하기를"},{"n":7,"t":"이 사람이 어찌 이렇게 말하는가 참람하도다 오직 하나님 한 분 외에는 누가 능히 죄를 사하겠느냐"},{"n":8,"t":"저희가 속으로 이렇게 의논하는 줄을 예수께서 곧 중심에 아시고 이르시되 어찌하여 이것을 마음에 의논하느냐"},{"n":9,"t":"중풍병자에게 네 죄 사함을 받았느니라 하는 말과 일어나 네 상을 가지고 걸어가라 하는 말이 어느 것이 쉽겠느냐"},{"n":10,"t":"그러나 인자가 땅에서 죄를 사하는 권세가 있는 줄을 너희로 알게 하려하노라 하시고 중풍병자에게 말씀하시되"},{"n":11,"t":"내가 네게 이르노니 일어나 네 상을 가지고 집으로 가라 하시니"},{"n":12,"t":"그가 일어나 곧 상을 가지고 모든 사람 앞에서 나가거늘 저희가 다 놀라 영광을 하나님께 돌리며 가로되 우리가 이런 일을 도무지 보지 못하였다 하더라"},{"n":13,"t":"예수께서 다시 바닷가에 나가시매 무리가 다 나아왔거늘 예수께서 저희를 가르치시니라"},{"n":14,"t":"또 지나가시다가 알패오의 아들 레위가 세관에 앉아 있는 것을 보시고 저에게 이르시되 나를 좇으라 하시니 일어나 좇으니라"},{"n":15,"t":"그의 집에 앉아 잡수실 때에 많은 세리와 죄인들이 예수와 그 제자들과 함께 앉았으니 이는 저희가 많이 있어서 예수를 좇음이러라"},{"n":16,"t":"바리새인의 서기관들이 예수께서 죄인과 세리들과 함께 잡수시는 것을 보고 그 제자들에게 이르되 어찌하여 세리와 죄인들과 함께 먹는가"},{"n":17,"t":"예수께서 들으시고 저희에게 이르시되 건강한 자에게는 의원이 쓸데 없고 병든 자에게라야 쓸데 있느니라 내가 의원을 부르러 온것이 아니요 죄인을 부르러 왔노라 하시니라"},{"n":18,"t":"요한의 제자들과 바리새인들이 금식하고 있는지라 혹이 예수께 와서 말하되 요한의 제자들과 바리새인의 제자들은 금식하는데 어찌하여 당신의 제자들은 금식하지 아니하나이까"},{"n":19,"t":"예수께서 저희에게 이르시되 혼인집 손님들이 신랑과 함께 있을 때에 금식할 수 있느냐 신랑과 함께 있을 동안에는 금식할 수 없나니"},{"n":20,"t":"그러나 신랑을 빼앗길 날이 이르리니 그 날에는 금식할 것이니라"},{"n":21,"t":"생베 조각을 낡은 옷에 붙이는 자가 없나니 만일 그렇게 하면 기운 새것이 낡은 그것을 당기어 해어짐이 더하게 되느니라"},{"n":22,"t":"새 포도주를 낡은 가죽 부대에 넣는 자가 없나니 만일 그렇게 하면 새 포도주가 부대를 터뜨려 포도주와 부대를 버리게 되리라 오직 새 포도주는 새 부대에 넣느니라 하시니라"},{"n":23,"t":"안식일에 예수께서 밀밭 사이로 지나가실쌔 그 제자들이 길을 열며 이삭을 자르니"},{"n":24,"t":"바리새인들이 예수께 말하되 보시오 저희가 어찌하여 안식일에 하지 못할 일을 하나이까"},{"n":25,"t":"예수께서 가라사대 다윗이 자기와 및 함께한 자들이 핍절되어 시장할 때에 한 일을 읽지 못하였느냐"},{"n":26,"t":"그가 아비아달 대제사장 때에 하나님의 전에 들어가서 제사장 외에는 먹지 못하는 진설병을 먹고 함께한자들에게도 주지 아니하였느냐"},{"n":27,"t":"또 가라사대 안식일은 사람을 위하여 있는 것이요 사람이 안식일을 위하여 있는 것이 아니니"},{"n":28,"t":"이러므로 인자는 안식일에도 주인이니라"}],"kids":[{"n":1,"t":"며칠 후 예수님이 다시 가버나움에 들어가시니, 그분이 집에 계신다는 소식이 퍼졌어요."},{"n":2,"t":"많은 사람이 모여 문 앞까지 발 디딜 틈도 없었어요. 예수님은 그들에게 말씀을 전하셨어요."},{"n":3,"t":"네 사람이 한 중풍 환자를 메고 예수님께 왔어요."},{"n":4,"t":"무리 때문에 가까이 갈 수 없자, 예수님 계신 곳 위 지붕을 뜯고 구멍을 내어 그 사람이 누운 자리를 달아 내렸어요."},{"n":5,"t":"예수님이 그들의 믿음을 보시고 중풍 환자에게 \\"얘야, 네 죄가 용서되었다\\" 하셨어요."},{"n":6,"t":"거기 앉아 있던 율법 학자 몇이 속으로 생각했어요."},{"n":7,"t":"\\"이 사람이 어찌 이렇게 말하나? 하나님을 모독하는 거야. 하나님 한 분 외에 누가 죄를 용서할 수 있어?\\""},{"n":8,"t":"예수님이 그들의 생각을 곧 영으로 아시고 말씀하셨어요. \\"왜 이런 생각을 마음에 품니?\\""},{"n":9,"t":"\\"중풍 환자에게 \'네 죄가 용서되었다\' 하는 것과 \'일어나 네 자리를 들고 걸어라\' 하는 것 중 어느 것이 더 쉽니?\\""},{"n":10,"t":"\\"그러나 사람의 아들이 땅에서 죄를 용서할 권세가 있는 줄을 너희가 알게 할게.\\" 그러고 중풍 환자에게,"},{"n":11,"t":"\\"내가 말한다. 일어나 네 자리를 들고 집으로 가라\\" 하셨어요."},{"n":12,"t":"그가 일어나 곧 자리를 들고 모두 앞에서 나갔어요. 모두 놀라며 하나님께 영광을 돌리고 \\"이런 일은 본 적이 없다\\" 하고 말했어요."},{"n":13,"t":"예수님이 다시 호숫가로 나가셨어요. 많은 사람이 그분께 나오니, 가르치셨어요."},{"n":14,"t":"지나가시다가 알패오의 아들 레위가 세관에 앉아 있는 것을 보시고 \\"나를 따르라\\" 하셨어요. 그가 일어나 따랐어요."},{"n":15,"t":"예수님이 레위의 집에서 식사하실 때 많은 세리와 죄인들이 예수님과 제자들과 함께 앉았어요. 따르는 사람이 많았거든요."},{"n":16,"t":"바리새인 율법 학자들이 예수님이 죄인과 세리들과 함께 잡수시는 것을 보고 제자들에게 \\"왜 그가 세리와 죄인과 함께 먹니?\\" 하고 말했어요."},{"n":17,"t":"예수님이 듣고 \\"건강한 사람에게는 의사가 필요 없고 병든 사람에게 필요해. 나는 의인을 부르러 온 게 아니라 죄인을 부르러 왔다\\" 하셨어요."},{"n":18,"t":"요한의 제자들과 바리새인들이 금식하고 있었어요. 그들이 와서 \\"왜 요한의 제자들과 바리새인의 제자들은 금식하는데 주님의 제자들은 안 해요?\\" 하고 물었어요."},{"n":19,"t":"예수님이 답하셨어요. \\"신랑 친구들이 신랑이 함께 있을 때 금식할 수 있겠니? 신랑이 함께 있는 동안은 금식할 수 없어.\\""},{"n":20,"t":"\\"그러나 신랑을 빼앗길 날이 올 거야. 그때는 그들이 금식할 거야.\\""},{"n":21,"t":"\\"낡은 옷에 새 천 조각을 대고 깁는 사람은 없어. 그러면 새 천이 그 옷에서 떨어져 나가 찢어진 곳이 더 커져.\\""},{"n":22,"t":"\\"새 포도주를 낡은 가죽 주머니에 넣지도 않아. 그러면 주머니가 터져 포도주도 주머니도 못쓰게 돼. 새 포도주는 새 주머니에 넣어야 해.\\""},{"n":23,"t":"안식일에 예수님이 밀밭을 지나가실 때 제자들이 가면서 이삭을 자르기 시작했어요."},{"n":24,"t":"바리새인들이 \\"보세요, 그들이 안식일에 해서는 안 될 일을 해요\\" 하고 말했어요."},{"n":25,"t":"예수님이 \\"다윗이 자기와 일행이 배고팠을 때 한 일을 너희가 읽지 못했니?\\""},{"n":26,"t":"\\"아비아달 대제사장 때에 그가 하나님의 집에 들어가 제사장 외에는 먹어선 안 되는 진설병을 먹고 일행에게도 주지 않았니?\\""},{"n":27,"t":"\\"안식일은 사람을 위해 있는 거야. 사람이 안식일을 위해 있는 게 아니야.\\""},{"n":28,"t":"\\"그러므로 사람의 아들은 안식일에도 주인이다\\" 하셨어요."}]}},{"chapter":3,"title":"열두 제자를 부르심","verses":{"krv":[{"n":1,"t":"예수께서 다시 회당에 들어가시니 한편 손 마른 사람이 거기 있는지라"},{"n":2,"t":"사람들이 예수를 송사하려 하여 안식일에 그 사람을 고치시는가 엿보거늘"},{"n":3,"t":"예수께서 손 마른 사람에게 이르시되 한가운데 일어서라 하시고"},{"n":4,"t":"저희에게 이르시되 안식일에 선을 행하는 것과 악을 행하는 것, 생명을 구하는 것과 죽이는 것, 어느 것이 옳으냐 하시니 저희가 잠잠하거늘"},{"n":5,"t":"저희 마음의 완악함을 근심하사 노하심으로 저희를 둘러 보시고 그 사람에게 이르시되 네 손을 내밀라 하시니 그가 내밀매 그 손이 회복되었더라"},{"n":6,"t":"바리새인들이 나가서 곧 헤롯당과 함께 어떻게 하여 예수를 죽일꼬 의논하니라"},{"n":7,"t":"예수께서 제자들과 함께 바다로 물러가시니 갈릴리에서 큰 무리가 좇으며"},{"n":8,"t":"유대와 예루살렘과 이두매와 요단강 건너편과 또 두로와 시돈 근처에서 허다한 무리가 그의 하신 큰 일을 듣고 나아오는지라"},{"n":9,"t":"예수께서 무리의 에워싸 미는 것을 면키 위하여 작은 배를 등대하도록 제자들에게 명하셨으니"},{"n":10,"t":"이는 많은 사람을 고치셨으므로 병에 고생하는 자들이 예수를 만지고자 하여 핍근히 함이더라"},{"n":11,"t":"더러운 귀신들도 어느 때든지 예수를 보면 그 앞에 엎드려 부르 짖어 가로되 당신은 하나님의 아들이니이다 하니"},{"n":12,"t":"예수께서 자기를 나타내지 말라고 많이 경계하시니라"},{"n":13,"t":"또 산에 오르사 자기의 원하는 자들을 부르시니 나아온지라"},{"n":14,"t":"이에 열 둘을 세우셨으니 이는 자기와 함께 있게 하시고 또 보내사 전도도 하며"},{"n":15,"t":"귀신을 내어쫓는 권세도 있게 하려 하심이러라"},{"n":16,"t":"이 열 둘을 세우셨으니 시몬에게는 베드로란 이름을 더하셨고"},{"n":17,"t":"또 세베대의 아들 야고보와 야고보의 형제 요한이니 이 둘에게는 보아너게 곧 우뢰의 아들이란 이름을 더하셨으며"},{"n":18,"t":"또 안드레와 빌립과 바돌로매와 마태와 도마와 알패오의 아들 야고보와 및 다대오와 가나안인 시몬이며"},{"n":19,"t":"또 가룟 유다니 이는 예수를 판 자러라"},{"n":20,"t":"집에 들어가시니 무리가 다시 모이므로 식사할 겨를도 없는지라"},{"n":21,"t":"예수의 친속들이 듣고 붙들러 나오니 이는 그가 미쳤다 함일러라"},{"n":22,"t":"예루살렘에서 내려온 서기관들은 저가 바알세불을 지폈다 하며 또 귀신의 왕을 힘입어 귀신을 쫓아낸다 하니"},{"n":23,"t":"예수께서 저희를 불러다가 비유로 말씀하시되 사단이 어찌 사단을 쫓아낼 수 있느냐"},{"n":24,"t":"또 만일 나라가 스스로 분쟁하면 그 나라가 설 수 없고"},{"n":25,"t":"만일 집이 스스로 분쟁하면 그 집이 설 수 없고"},{"n":26,"t":"만일 사단이 자기를 거스려 일어나 분쟁하면 설 수 없고 이에 망하느니라"},{"n":27,"t":"사람이 먼저 강한 자를 결박지 않고는 그 강한 자의 집에 들어가 세간을 늑탈치 못하리니 결박한 후에야 그 집을 늑탈하리라"},{"n":28,"t":"내가 진실로 너희에게 이르노니 사람의 모든 죄와 무릇 훼방하는 훼방은 사하심을 얻되"},{"n":29,"t":"누구든지 성령을 훼방하는 자는 사하심을 영원히 얻지 못하고 영원한 죄에 처하느니라 하시니"},{"n":30,"t":"이는 저희가 말하기를 더러운 귀신이 들렸다 함이러라"},{"n":31,"t":"때에 예수의 모친과 동생들이 와서 밖에 서서 사람을 보내어 예수를 부르니"},{"n":32,"t":"무리가 예수를 둘러 앉았다가 여짜오되 보소서 당신의 모친과 동생들과 누이들이 밖에서 찾나이다"},{"n":33,"t":"대답하시되 누가 내 모친이며 동생들이냐 하시고"},{"n":34,"t":"둘러 앉은 자들을 둘러 보시며 가라사대 내 모친과 내 동생들을 보라"},{"n":35,"t":"누구든지 하나님의 뜻대로 하는 자는 내 형제요 자매요 모친이니라"}],"kids":[{"n":1,"t":"예수님이 다시 회당에 들어가셨어요. 거기 한 손이 마른 사람이 있었어요."},{"n":2,"t":"사람들이 예수님이 안식일에 그를 고치시는지 지켜보았어요. 고소거리를 찾으려고요."},{"n":3,"t":"예수님이 손 마른 사람에게 \\"가운데 일어서라\\" 하셨어요."},{"n":4,"t":"그러고 그들에게 \\"안식일에 선을 행하는 것과 악을 행하는 것, 생명을 구하는 것과 죽이는 것 중 어느 것이 옳니?\\" 하셨어요. 그들이 잠잠했어요."},{"n":5,"t":"예수님이 화를 내며 둘러보시고 그들의 마음이 굳은 것을 슬퍼하시며 그 사람에게 \\"손을 펴라\\" 하셨어요. 그가 폈고 손이 회복됐어요."},{"n":6,"t":"바리새인들이 곧 나가서 헤롯파 사람들과 함께 어떻게 예수님을 죽일까 의논했어요."},{"n":7,"t":"예수님이 제자들과 함께 호수로 가셨어요. 갈릴리에서 큰 무리가 따라왔어요."},{"n":8,"t":"유대, 예루살렘, 이두매와 요단강 건너편, 두로와 시돈 근처에서도 큰 무리가 예수님의 하시는 일을 듣고 나아왔어요."},{"n":9,"t":"예수님은 무리가 자기를 밀치지 않게 작은 배 한 척을 준비해 두라고 제자들에게 말씀하셨어요."},{"n":10,"t":"많은 사람을 고치셨기에 병든 사람들이 그분을 만지려고 밀려왔거든요."},{"n":11,"t":"더러운 영들이 그분을 보고 엎드려 \\"당신은 하나님의 아들이세요!\\" 하고 외쳤어요."},{"n":12,"t":"예수님은 자기를 나타내지 말라고 엄히 경고하셨어요."},{"n":13,"t":"예수님이 산에 올라가셔서 자기가 원하시는 사람들을 부르시니 그들이 그분께 나아왔어요."},{"n":14,"t":"예수님이 열둘을 세우셨는데 그들을 사도라고 부르셨어요. 그들이 자기와 함께 있게 하시고 전도하러 보내시며,"},{"n":15,"t":"귀신을 쫓아내는 권세도 주셨어요."},{"n":16,"t":"열둘은 베드로라는 이름을 주신 시몬,"},{"n":17,"t":"세베대의 아들 야고보와 그의 동생 요한(이들에게 \'천둥의 아들들\'이라는 뜻의 보아너게라는 이름을 주셨어요),"},{"n":18,"t":"안드레, 빌립, 바돌로매, 마태, 도마, 알패오의 아들 야고보, 다대오, 가나안 사람 시몬,"},{"n":19,"t":"그리고 예수님을 넘긴 가룟 유다예요."},{"n":20,"t":"예수님이 집에 들어가시자 또 무리가 모여 식사할 틈도 없었어요."},{"n":21,"t":"그분의 가족이 듣고 예수님을 데리러 나섰어요. \\"그가 미쳤다\\" 하는 말 때문이에요."},{"n":22,"t":"예루살렘에서 내려온 율법 학자들은 \\"그가 바알세불에 들렸어. 귀신의 우두머리 힘으로 귀신을 쫓아내는 거야\\" 하고 말했어요."},{"n":23,"t":"예수님이 그들을 부르시고 비유로 말씀하셨어요. \\"사탄이 어떻게 사탄을 쫓아낼 수 있겠니?\\""},{"n":24,"t":"\\"나라가 스스로 분쟁하면 그 나라는 설 수 없어.\\""},{"n":25,"t":"\\"집이 스스로 분쟁하면 그 집도 설 수 없어.\\""},{"n":26,"t":"\\"사탄이 스스로 일어나 분쟁하면 설 수 없고 끝이야.\\""},{"n":27,"t":"\\"누가 강한 사람의 집에 들어가 그의 물건을 빼앗으려면 먼저 그를 묶지 않고 어떻게 그 집을 털 수 있겠니?\\""},{"n":28,"t":"\\"진정으로 말한다. 사람이 짓는 모든 죄와 모독은 용서받을 수 있어.\\""},{"n":29,"t":"\\"그러나 누구든지 성령을 모독하는 사람은 영원히 용서를 받지 못하고 영원한 죄에 처해.\\""},{"n":30,"t":"이는 \\"그가 더러운 영에 들렸다\\" 하고 말했기 때문이에요."},{"n":31,"t":"예수님의 어머니와 형제들이 와서 밖에 서서 사람을 보내 예수님을 불렀어요."},{"n":32,"t":"무리가 예수님을 둘러 앉아 있다가 \\"보세요, 어머니와 형제들이 밖에서 찾으세요\\" 하고 말했어요."},{"n":33,"t":"예수님이 \\"누가 내 어머니와 형제들이니?\\" 하셨어요."},{"n":34,"t":"둘러 앉은 사람들을 보시며 \\"보라, 내 어머니와 형제들이다.\\""},{"n":35,"t":"\\"누구든지 하나님의 뜻을 행하는 사람이 내 형제고 자매고 어머니다\\" 하셨어요."}]}},{"chapter":4,"title":"씨 뿌리는 비유와 풍랑을 잠재우심","verses":{"krv":[{"n":1,"t":"예수께서 다시 바닷가에서 가르치시니 큰 무리가 모여 들거늘 예수께서 배에 올라 바다에 떠 앉으시고 온 무리는 바다 곁 육지에 있더라"},{"n":2,"t":"이에 예수께서 여러가지를 비유로 가르치시니 그 가르치시는 중에 저희에게 이르시되"},{"n":3,"t":"들으라 씨를 뿌리는 자가 뿌리러 나가서"},{"n":4,"t":"뿌릴쌔 더러는 길 가에 떨어지매 새들이 와서 먹어 버렸고"},{"n":5,"t":"더러는 흙이 얇은 돌밭에 떨어지매 흙이 깊지 아니하므로 곧 싹이 나오나"},{"n":6,"t":"해가 돋은 후에 타져서 뿌리가 없으므로 말랐고"},{"n":7,"t":"더러는 가시떨기에 떨어지매 가시가 자라 기운을 막으므로 결실치 못하였고"},{"n":8,"t":"더러는 좋은 땅에 떨어지매 자라 무성하여 결실하였으니 삼십배와 육십배와 백배가 되었느니라 하시고"},{"n":9,"t":"또 이르시되 들을 귀 있는 자는 들으라 하시니라"},{"n":10,"t":"예수께서 홀로 계실 때에 함께한 사람들이 열 두 제자로 더불어 그 비유들을 묻자오니"},{"n":11,"t":"이르시되 하나님 나라의 비밀을 너희에게는 주었으나 외인에게는 모든 것을 비유로 하나니"},{"n":12,"t":"이는 저희로 보기는 보아도 알지 못하며 듣기는 들어도 깨닫지 못하게 하여 돌이켜 죄 사함을 얻지 못하게 하려 함이니라 하시고"},{"n":13,"t":"또 가라사대 너희가 이 비유를 알지 못할진대 어떻게 모든 비유를 알겠느뇨"},{"n":14,"t":"뿌리는 자는 말씀을 뿌리는 것이라"},{"n":15,"t":"말씀이 길 가에 뿌리웠다는 것은 이들이니 곧 말씀을 들었을 때에 사단이 즉시 와서 저희에게 뿌리운 말씀을 빼앗는 것이요"},{"n":16,"t":"또 이와 같이 돌밭에 뿌리웠다는 것은 이들이니 곧 말씀을 들을 때에 즉시 기쁨으로 받으나"},{"n":17,"t":"그 속에 뿌리가 없어 잠간 견디다가 말씀을 인하여 환난이나 핍박이 일어나는 때에는 곧 넘어지는 자요"},{"n":18,"t":"또 어떤이는 가시떨기에 뿌리우는 자니 이들은 말씀을 듣되"},{"n":19,"t":"세상의 염려와 재리의 유혹과 기타 욕심이 들어와 말씀을 막아 결실치 못하게 되는 자요"},{"n":20,"t":"좋은 땅에 뿌리웠다는 것은 곧 말씀을 듣고 받아 삼십배와 육십배와 백배의 결실을 하는 자니라"},{"n":21,"t":"또 저희에게 이르시되 사람이 등불을 가져오는 것은 말 아래나 평상 아래나 두려 함이냐 등경 위에 두려 함이 아니냐"},{"n":22,"t":"드러내려 하지 않고는 숨긴 것이 없고 나타내려 하지 않고는 감추인 것이 없느니라"},{"n":23,"t":"들을 귀 있는 자는 들으라"},{"n":24,"t":"또 가라사대 너희가 무엇을 듣는가 스스로 삼가라 너희의 헤아리는 그 헤아림으로 너희가 헤아림을 받을것이요 또 더 받으리니"},{"n":25,"t":"있는 자는 받을 것이요 없는 자는 그 있는 것까지 빼앗기리라"},{"n":26,"t":"또 가라사대 하나님의 나라는 사람이 씨를 땅에 뿌림과 같으니"},{"n":27,"t":"저가 밤낮 자고 깨고 하는 중에 씨가 나서 자라되 그 어떻게 된 것을 알지 못하느니라"},{"n":28,"t":"땅이 스스로 열매를 맺되 처음에는 싹이요 다음에는 이삭이요 그 다음에는 이삭에 충실한 곡식이라"},{"n":29,"t":"열매가 익으면 곧 낫을 대나니 이는 추수 때가 이르렀음이니라"},{"n":30,"t":"또 가라사대 우리가 하나님의 나라를 어떻게 비하며 또 무슨 비유로 나타낼꼬"},{"n":31,"t":"겨자씨 한 알과 같으니 땅에 심길 때에는 땅위의 모든 씨보다 작은 것이로되"},{"n":32,"t":"심긴 후에는 자라서 모든 나물보다 커지며 큰 가지를 내니 공중의 새들이 그 그늘에 깃들일 만큼 되느니라"},{"n":33,"t":"예수께서 이러한 많은 비유로 저희가 알아 들을 수 있는대로 말씀을 가르치시되"},{"n":34,"t":"비유가 아니면 말씀하지 아니하시고 다만 혼자 계실 때에 그 제자들에게 모든것을 해석 하시더라"},{"n":35,"t":"그날 저물 때에 제자들에게 이르시되 우리가 저편으로 건너가자 하시니"},{"n":36,"t":"저희가 무리를 떠나 예수를 배에 계신 그대로 모시고 가매 다른 배들도 함께 하더니"},{"n":37,"t":"큰 광풍이 일어나며 물결이 부딪혀 배에 들어와 배에 가득하게 되었더라"},{"n":38,"t":"예수께서는 고물에서 베개를 베시고 주무시더니 제자들이 깨우며 가로되 선생님이여 우리의 죽게 된것을 돌아보지 아니하시나이까 하니"},{"n":39,"t":"예수께서 깨어 바람을 꾸짖으시며 바다더러 이르시되 잠잠하라 고요하라 하시니 바람이 그치고 아주 잔잔하여 지더라"},{"n":40,"t":"이에 제자들에게 이르시되 어찌하여 이렇게 무서워하느냐 너희가 어찌 믿음이 없느냐 하시니"},{"n":41,"t":"저희가 심히 두려워하여 서로 말하되 저가 뉘기에 바람과 바다라도 순종하는고 하였더라"}],"kids":[{"n":1,"t":"예수님이 다시 호숫가에서 가르치셨어요. 큰 무리가 모이니, 그분이 배에 올라 앉으셨고 무리는 호숫가에 있었어요."},{"n":2,"t":"예수님이 비유로 많은 것을 가르치시며 말씀하셨어요."},{"n":3,"t":"\\"들어 봐! 농부가 씨를 뿌리러 나갔어.\\""},{"n":4,"t":"\\"씨를 뿌릴 때 어떤 것은 길가에 떨어져 새들이 와서 먹어 버렸어.\\""},{"n":5,"t":"\\"어떤 것은 흙이 깊지 않은 돌밭에 떨어져 흙이 얕아 곧 싹이 났지만,\\""},{"n":6,"t":"\\"해가 뜨자 탔고 뿌리가 없어 말라 버렸어.\\""},{"n":7,"t":"\\"어떤 것은 가시덤불에 떨어져 가시가 자라 막아서 열매를 맺지 못했어.\\""},{"n":8,"t":"\\"또 어떤 것은 좋은 땅에 떨어져 자라며 열매를 맺어 삼십 배, 육십 배, 백 배가 되었어.\\""},{"n":9,"t":"\\"귀 있는 사람은 들어라.\\""},{"n":10,"t":"예수님이 혼자 계실 때 둘레에 있던 사람들과 열두 제자가 비유를 물었어요."},{"n":11,"t":"예수님이 \\"하나님 나라의 비밀이 너희에게는 주어졌지만 바깥 사람들에게는 모든 것이 비유로 주어져,\\""},{"n":12,"t":"\\"이는 그들이 보아도 알지 못하고 들어도 깨닫지 못하게 함이야. 그들이 돌이켜 용서받지 못하도록.\\" 하셨어요."},{"n":13,"t":"예수님이 \\"이 비유를 모르니? 그러면 모든 비유를 어떻게 알겠니?\\""},{"n":14,"t":"\\"농부는 말씀을 뿌리는 거야.\\""},{"n":15,"t":"\\"길가에 있는 사람들은 말씀을 듣자마자 사탄이 와서 그들에게 뿌려진 말씀을 빼앗아 가는 거야.\\""},{"n":16,"t":"\\"돌밭에 뿌려진 사람들은 말씀을 들으면 곧 기쁨으로 받지만,\\""},{"n":17,"t":"\\"속에 뿌리가 없어 잠시뿐이고 환난이나 박해가 말씀 때문에 일어나면 곧 넘어져.\\""},{"n":18,"t":"\\"가시덤불에 뿌려진 사람들은 말씀을 듣는데,\\""},{"n":19,"t":"\\"세상의 걱정과 재물의 유혹과 다른 욕심이 들어와 말씀을 막아 열매를 맺지 못해.\\""},{"n":20,"t":"\\"좋은 땅에 뿌려진 사람들은 말씀을 듣고 받아 삼십 배, 육십 배, 백 배의 열매를 맺어.\\""},{"n":21,"t":"\\"등불을 가져다가 그릇 아래나 침대 아래 둘 사람이 있니? 등잔대 위에 두지 않니?\\""},{"n":22,"t":"\\"감춰진 것은 드러나기 위해 있고, 숨겨진 것은 알려지기 위해 있어.\\""},{"n":23,"t":"\\"귀 있는 사람은 들어라.\\""},{"n":24,"t":"\\"무엇을 듣는지 조심해. 너희가 재는 그 잣대로 너희도 받을 거고 더 받게 될 거야.\\""},{"n":25,"t":"\\"있는 사람은 더 받을 거고 없는 사람은 있는 것까지 빼앗길 거야.\\""},{"n":26,"t":"또 말씀하셨어요. \\"하나님의 나라는 마치 사람이 땅에 씨를 뿌려 놓은 것과 같아.\\""},{"n":27,"t":"\\"그가 자고 일어나고 밤낮을 지내는 동안 씨가 어떻게 싹나서 자라는지 알지 못하지만 자라.\\""},{"n":28,"t":"\\"땅이 스스로 열매를 내. 처음에는 싹, 그 다음에 이삭, 그 다음에 이삭 속 잘 여문 알맹이가 돼.\\""},{"n":29,"t":"\\"열매가 익으면 곧 낫을 대. 추수 때가 됐기 때문이야.\\""},{"n":30,"t":"또 말씀하셨어요. \\"하나님의 나라를 어떻게 비유할까? 어떤 비유로 나타낼까?\\""},{"n":31,"t":"\\"겨자씨와 같아. 땅에 심을 때는 모든 씨보다 작지만,\\""},{"n":32,"t":"\\"심긴 후에는 자라서 모든 풀보다 커져 큰 가지를 내니 공중의 새들이 그 그늘에 깃들 수 있어.\\""},{"n":33,"t":"예수님이 이렇게 많은 비유로 그들이 들을 수 있는 만큼 말씀하셨어요."},{"n":34,"t":"비유 없이는 그들에게 말씀하지 않으셨고, 제자들에게는 따로 모든 것을 풀어 주셨어요."},{"n":35,"t":"그날 저녁에 예수님이 \\"저편으로 건너가자\\" 하셨어요."},{"n":36,"t":"제자들이 무리를 두고 예수님이 계신 그대로 배에 모셨고 다른 배들도 함께 있었어요."},{"n":37,"t":"큰 폭풍이 일어 파도가 배에 부딪쳐 물이 배에 가득 찼어요."},{"n":38,"t":"예수님은 고물 베개를 베고 주무시고 계셨어요. 제자들이 깨우며 \\"선생님, 우리가 죽게 됐는데도 신경 안 쓰세요?\\" 하고 말했어요."},{"n":39,"t":"예수님이 일어나 바람을 꾸짖으시고 바다에 \\"고요히 잠잠해져라\\" 하시자, 바람이 그치고 아주 잔잔해졌어요."},{"n":40,"t":"예수님이 그들에게 \\"왜 그렇게 무서워하니? 너희에게 아직도 믿음이 없니?\\" 하셨어요."},{"n":41,"t":"그들이 매우 두려워서 서로 말했어요. \\"이분이 누구신가? 바람과 바다도 그분께 순종하잖아!\\""}]}},{"chapter":5,"title":"귀신들린 사람과 야이로의 딸","verses":{"krv":[{"n":1,"t":"예수께서 바다 건너편 거라사인의 지방에 이르러"},{"n":2,"t":"배에서 나오시매 곧 더러운 귀신 들린 사람이 무덤 사이에서 나와 예수를 만나다"},{"n":3,"t":"그 사람은 무덤 사이에 거처하는데 이제는 아무나 쇠사슬로도 맬 수 없게 되었으니"},{"n":4,"t":"이는 여러번 고랑과 쇠사슬에 매였어도 쇠사슬을 끊고 고랑을 깨뜨렸음이러라 그리하여 아무도 저를 제어할 힘이 없는지라"},{"n":5,"t":"밤낮 무덤 사이에서나 산에서나 늘 소리지르며 돌로 제 몸을 상하고 있었더라"},{"n":6,"t":"그가 멀리서 예수를 보고 달려와 절하며"},{"n":7,"t":"큰 소리로 부르짖어 가로되 지극히 높으신 하나님의 아들 예수여 나와 당신과 무슨 상관이 있나이까 원컨대 하나님 앞에 맹세하고 나를 괴롭게 마옵소서 하니"},{"n":8,"t":"이는 예수께서 이미 저에게 이르시기를 더러운 귀신아 그 사람에게서 나오라 하셨음이라"},{"n":9,"t":"이에 물으시되 네 이름이 무엇이냐 가로되 내 이름은 군대니 우리가 많음이니이다 하고"},{"n":10,"t":"자기를 이 지방에서 내어 보내지 마시기를 간절히 구하더니"},{"n":11,"t":"마침 거기 돼지의 큰 떼가 산 곁에서 먹고 있는지라"},{"n":12,"t":"이에 간구하여 가로되 우리를 돼지에게로 보내어 들어가게 하소서 하니"},{"n":13,"t":"허락하신대 더러운 귀신들이 나와서 돼지에게로 들어가니 거의 이천 마리 되는 떼가 바다를 향하여 비탈로 내리달아 바다에서 몰사하거늘"},{"n":14,"t":"치던 자들이 도망하여 읍내와 촌에 고하니 사람들이 그 어떻게 된것을 보러 와서"},{"n":15,"t":"예수께 이르러 그 귀신 들렸던 자 곧 군대 지폈던 자가 옷을 입고 정신이 온전하여 앉은 것을 보고 두려워하더라"},{"n":16,"t":"이에 귀신 들렸던 자의 당한 것과 돼지의 일을 본 자들이 저희에게 고하매"},{"n":17,"t":"저희가 예수께 그 지경에서 떠나시기를 간구하더라"},{"n":18,"t":"예수께서 배에 오르실 때에 귀신 들렸던 사람이 함께 있기를 간구하였으나"},{"n":19,"t":"허락지 아니하시고 저에게 이르시되 집으로 돌아가 주께서 네게 어떻게 큰 일을 행하사 너를 불쌍히 여기신 것을 네 친속에게 고하라 하신대"},{"n":20,"t":"그가 가서 예수께서 자기에게 어떻게 큰 일 행하신 것을 데가볼리에 전파하니 모든 사람이 기이히 여기더라"},{"n":21,"t":"예수께서 배를 타시고 다시 저편으로 건너 가시매 큰 무리가 그에게로 모이거늘 이에 바닷가에 계시더니"},{"n":22,"t":"회당장 중 하나인 야이로라 하는 이가 와서 예수를 보고 발 아래 엎드리어"},{"n":23,"t":"많이 간구하여 가로되 내 어린 딸이 죽게 되었사오니 오셔서 그 위에 손을 얹으사 그로 구원을 얻어 살게 하소서 하거늘"},{"n":24,"t":"이에 그와 함께 가실쌔 큰 무리가 따라가며 에워싸 밀더라"},{"n":25,"t":"열 두 해를 혈루증으로 앓는 한 여자가 있어"},{"n":26,"t":"많은 의원에게 많은 괴로움을 받았고 있던 것도 다 허비하였으되 아무 효험이 없고 도리어 더 중하여졌던 차에"},{"n":27,"t":"예수의 소문을 듣고 무리 가운데 섞여 뒤로 와서 그의 옷에 손을 대니"},{"n":28,"t":"이는 내가 그의 옷에만 손을 대어도 구원을 얻으리라 함일러라"},{"n":29,"t":"이에 그의 혈루 근원이 곧 마르매 병이 나은 줄을 몸에 깨달으니라"},{"n":30,"t":"예수께서 그 능력이 자기에게서 나간 줄을 곧 스스로 아시고 무리 가운데서 돌이켜 말씀하시되 누가 내 옷에 손을 대었느냐 하시니"},{"n":31,"t":"제자들이 여짜오되 무리가 에워싸 미는 것을 보시며 누가 내게 손을 대었느냐 물으시나이까 하되"},{"n":32,"t":"예수께서 이 일 행한 여자를 보려고 둘러 보시니"},{"n":33,"t":"여자가 제게 이루어진 일을 알고 두려워하여 떨며 와서 그 앞에 엎드려 모든 사실을 여짜온대"},{"n":34,"t":"예수께서 가라사대 딸아 네 믿음이 너를 구원하였으니 평안히 가라 네 병에서 놓여 건강할지어다"},{"n":35,"t":"아직 말씀하실 때에 회당장의 집에서 사람들이 와서 가로되 당신의 딸이 죽었나이다 어찌하여 선생을 더 괴롭게 하나이까"},{"n":36,"t":"예수께서 그 하는 말을 곁에서 들으시고 회당장에게 이르시되 두려워 말고 믿기만 하라 하시고"},{"n":37,"t":"베드로와 야고보와 야고보의 형제 요한 외에 아무도 따라옴을 허치 아니하시고"},{"n":38,"t":"회당장의 집에 함께 가사 훤화함과 사람들의 울며 심히 통곡함을 보시고"},{"n":39,"t":"들어가서 저희에게 이르시되 너희가 어찌하여 훤화하며 우느냐 이 아이가 죽은 것이 아니라 잔다 하시니"},{"n":40,"t":"저희가 비웃더라 예수께서 저희를 다 내어 보내신 후에 아이의 부모와 또 자기와 함께 한 자들을 데리시고 아이 있는 곳에 들어가사"},{"n":41,"t":"그 아이의 손을 잡고 가라사대 달리다굼 하시니 번역하면 곧 소녀야 내가 네게 말하노니 일어나라 하심이라"},{"n":42,"t":"소녀가 곧 일어나서 걸으니 나이 열 두살이라 사람들이 곧 크게 놀라고 놀라거늘"},{"n":43,"t":"예수께서 이 일을 아무도 알지 못하게 하라고 저희를 많이 경계하시고 이에 소녀에게 먹을 것을 주라 하시니라"}],"kids":[{"n":1,"t":"그들이 호수 건너편 거라사인의 지방으로 갔어요."},{"n":2,"t":"예수님이 배에서 내리시자 더러운 영 들린 사람이 무덤에서 곧 나와 예수님을 맞이했어요."},{"n":3,"t":"그는 무덤 사이에 살았는데 아무도 그를 사슬로도 묶지 못했어요."},{"n":4,"t":"그는 여러 번 발과 사슬에 묶였지만 사슬을 끊고 발의 차꼬도 부숴 버려서 아무도 그를 길들일 수 없었어요."},{"n":5,"t":"그가 밤낮 무덤과 산에서 소리치며 돌로 자기 몸을 상하게 했어요."},{"n":6,"t":"그가 멀리서 예수님을 보고 달려와 절했어요."},{"n":7,"t":"큰 소리로 \\"지극히 높으신 하나님의 아들 예수여, 나와 무슨 상관이세요? 하나님께 맹세하건대 나를 괴롭히지 마세요\\" 하고 외쳤어요."},{"n":8,"t":"이는 예수님이 \\"더러운 영아, 그 사람에게서 나오너라\\" 하셨기 때문이에요."},{"n":9,"t":"예수님이 \\"네 이름이 뭐냐?\\" 하시자 그가 \\"내 이름은 군대예요. 우리가 많기 때문이에요\\" 하고 답했어요."},{"n":10,"t":"그가 그 지역에서 자기를 보내지 말아 달라고 간청했어요."},{"n":11,"t":"그 산 근처에 큰 돼지 떼가 풀을 뜯고 있었어요."},{"n":12,"t":"모든 영들이 청했어요. \\"우리를 저 돼지에게 보내 들어가게 해 주세요.\\""},{"n":13,"t":"예수님이 허락하시자 더러운 영들이 나가 돼지에게 들어갔어요. 돼지 떼 약 이천 마리가 비탈에서 호수로 달려 내려가 물에 빠져 죽었어요."},{"n":14,"t":"돼지 치던 사람들이 도망쳐 동네와 들에 알리니, 사람들이 무슨 일인지 보러 왔어요."},{"n":15,"t":"그들이 예수님께 와서 군대 귀신 들렸던 사람이 옷을 입고 정신을 차리고 앉아 있는 것을 보고 두려워했어요."},{"n":16,"t":"본 사람들이 귀신 들렸던 사람에게 일어난 일과 돼지에 대해서도 그들에게 말해 주었어요."},{"n":17,"t":"그들이 예수님께 자기 지역에서 떠나 달라고 청하기 시작했어요."},{"n":18,"t":"예수님이 배에 오르실 때 귀신 들렸던 사람이 함께 있게 해 달라고 청했어요."},{"n":19,"t":"예수님이 허락하지 않으시고 \\"네 집으로 돌아가 주께서 너에게 얼마나 큰일을 하셨는지, 또 어떻게 자비를 베푸셨는지 알려라\\" 하셨어요."},{"n":20,"t":"그가 떠나 데가볼리에서 예수님이 자기에게 행하신 큰일을 전하니, 모두 놀랐어요."},{"n":21,"t":"예수님이 다시 배로 건너편으로 가셨을 때 호숫가에 큰 무리가 모였어요."},{"n":22,"t":"회당장 중 한 사람 야이로라는 사람이 와서 예수님 발 앞에 엎드려,"},{"n":23,"t":"\\"제 어린 딸이 다 죽어 가요. 오셔서 손을 얹어 주세요. 살아 낫게 해 주세요\\" 하고 청했어요."},{"n":24,"t":"예수님이 함께 가셨어요. 큰 무리가 따르며 예수님을 밀쳤어요."},{"n":25,"t":"십이 년 동안 피를 흘리는 병으로 고생하던 한 여자가 있었어요."},{"n":26,"t":"많은 의사에게 많은 괴로움을 당했고 가진 것을 다 썼지만 도움을 받지 못하고 도리어 더 나빠졌어요."},{"n":27,"t":"그녀가 예수님에 대해 듣고 무리 속에서 뒤로 와서 그분의 옷자락을 만졌어요."},{"n":28,"t":"\\"내가 그분의 옷자락만 만져도 나을 거야\\" 하고 생각했거든요."},{"n":29,"t":"곧 피가 멈추고 자기 몸이 그 병에서 나은 것을 알았어요."},{"n":30,"t":"예수님이 곧 자기에게서 능력이 나간 것을 아시고 무리 가운데 돌아서서 \\"누가 내 옷에 손을 댔니?\\" 하고 물으셨어요."},{"n":31,"t":"제자들이 \\"무리가 주님을 밀치는 것을 보면서 \'누가 내게 손을 댔니?\' 하세요?\\" 하고 답했어요."},{"n":32,"t":"예수님은 둘러보며 그 일을 한 사람을 찾으셨어요."},{"n":33,"t":"그 여자가 자기에게 일어난 일을 알고 두려워 떨며 와서 예수님 앞에 엎드려 모든 사실을 말했어요."},{"n":34,"t":"예수님이 \\"딸아, 네 믿음이 너를 구원했다. 평안히 가서 네 병에서 자유로워라\\" 하셨어요."},{"n":35,"t":"예수님이 아직 말씀하실 때 회당장의 집에서 사람이 와서 \\"따님이 죽었어요. 더 이상 선생님을 괴롭히지 마세요\\" 하고 말했어요."},{"n":36,"t":"예수님이 그 말을 듣고 회당장에게 \\"두려워하지 마. 믿기만 해\\" 하셨어요."},{"n":37,"t":"예수님은 베드로와 야고보와 그의 동생 요한 외에는 아무도 따라오게 하지 않으셨어요."},{"n":38,"t":"회당장의 집에 이르러 시끄럽게 울고 통곡하는 것을 보시고,"},{"n":39,"t":"들어가시며 \\"왜 시끄럽게 울고 있니? 아이가 죽은 게 아니라 자고 있는 거야\\" 하셨어요."},{"n":40,"t":"그들이 비웃었어요. 예수님이 모두 내보내시고 아이의 부모와 함께 한 사람들만 데리고 아이가 있는 곳에 들어가셨어요."},{"n":41,"t":"아이의 손을 잡으시고 \\"달리다굼!\\" 하셨는데, 풀이하면 \\"소녀야, 내가 너에게 말한다, 일어나라\\"예요."},{"n":42,"t":"곧 소녀가 일어나 걸었어요. 그녀는 열두 살이었어요. 사람들이 깜짝 놀랐어요."},{"n":43,"t":"예수님은 이 일을 아무도 알지 못하게 엄히 명하시고, 그녀에게 먹을 것을 주라고 하셨어요."}]}},{"chapter":6,"title":"오병이어와 물 위를 걸으심","verses":{"krv":[{"n":1,"t":"예수께서 거기를 떠나사 고향으로 가시니 제자들도 좇으니라"},{"n":2,"t":"안식일이 되어 회당에서 가르치시니 많은 사람이 듣고 놀라 가로되 이 사람이 어디서 이런 것을 얻었느뇨 이 사람의 받은 지혜와 그 손으로 이루어지는 이런 권능이 어찌 됨이뇨"},{"n":3,"t":"이 사람이 마리아의 아들 목수가 아니냐 야고보와 요셉과 유다와시몬의 형제가 아니냐 그 누이들이 우리와 함께 여기 있지 아니하냐 하고 예수를 배척한지라"},{"n":4,"t":"예수께서 저희에게 이르시되 선지자가 자기 고향과 자기 친척과 자기 집 외에서는 존경을 받지 않음이 없느니라 하시며"},{"n":5,"t":"거기서는 아무 권능도 행하실 수 없어 다만 소수의 병인에게 안수하여 고치실 뿐이었고"},{"n":6,"t":"저희의 믿지 않음을 이상히 여기셨더라 이에 모든 촌에 두루 다니시며 가르치시더라"},{"n":7,"t":"열 두 제자를 부르사 둘씩 둘씩 보내시며 더러운 귀신을 제어하는 권세를 주시고"},{"n":8,"t":"명하시되 여행을 위하여 지팡이 외에는 양식이나 주머니나 전대의 돈이나 아무 것도 가지지 말며"},{"n":9,"t":"신만 신고 두 벌 옷도 입지 말라 하시고"},{"n":10,"t":"또 가라사대 어디서든지 뉘 집에 들어가거든 그곳을 떠나기까지 거기 유하라"},{"n":11,"t":"어느 곳에서든지 너희를 영접지 아니하고 너희 말을 듣지도 아니하거든 거기서 나갈 때에 발 아래 먼지를 떨어버려 저희에게 증거를 삼으라 하시니"},{"n":12,"t":"제자들이 나가서 회개하라 전파하고"},{"n":13,"t":"많은 귀신을 쫓아내며 많은 병인에게 기름을 발라 고치더라"},{"n":14,"t":"이에 예수의 이름이 드러난지라 헤롯왕이 듣고 가로되 이는 세례 요한이 죽은 자 가운데서 살아났도다 그러므로 이런 능력이 그 속에서 운동하느니라 하고"},{"n":15,"t":"어떤이는 이가 엘리야라 하고 또 어떤이는 이가 선지자니 옛 선지자 중의 하나와 같다 하되"},{"n":16,"t":"헤롯은 듣고 가로되 내가 목 베인 요한 그가 살아났다 하더라"},{"n":17,"t":"전에 헤롯이 자기가 동생 빌립의 아내 헤로디아에게 장가 든고로 이 여자를 위하여 사람을 보내어 요한을 잡아 옥에 가두었으니"},{"n":18,"t":"이는 요한이 헤롯에게 말하되 동생의 아내를 취한 것이 옳지 않다 하였음이라"},{"n":19,"t":"헤로디아가 요한을 원수로 여겨 죽이고자 하였으되 하지 못한 것은"},{"n":20,"t":"헤롯이 요한을 의롭고 거룩한 사람으로 알고 두려워하여 보호하며 또 그의 말을 들을 때에 크게 번민을 느끼면서도 달게 들음이러라"},{"n":21,"t":"마침 기회 좋은 날이 왔으니 곧 헤롯이 자기 생일에 대신들과 천부장들과 갈릴리의 귀인들로 더불어 잔치할쌔"},{"n":22,"t":"헤로디아의 딸이 친히 들어와 춤을 추어 헤롯과 및 함께 앉은 자들을 기쁘게 한지라 왕이 그 여아에게 이르되 무엇이든지 너 원하는 것을 내게 구하라 내가 주리라 하고"},{"n":23,"t":"또 맹세하되 무엇이든지 네가 내게 구하면 내 나라의 절반까지라도 주리라 하거늘"},{"n":24,"t":"저가 나가서 그 어미에게 말하되 내가 무엇을 구하리이까 그 어미가 가로되 세례 요한의 머리를 구하라 하니"},{"n":25,"t":"저가 곧 왕에게 급히 들어가 구하여 가로되 세례 요한의 머리를 소반에 담아 곧 내게 주기를 원하옵나이다 한대"},{"n":26,"t":"왕이 심히 근심하나 자기의 맹세한 것과 그 앉은 자들을 인하여 저를 거절할 수 없는지라"},{"n":27,"t":"왕이 곧 시위병 하나를 보내어 요한의 머리를 가져오라 명하니 그 사람이 나가 옥에서 요한을 목 베어"},{"n":28,"t":"그 머리를 소반에 담아다가 여아에게 주니 여아가 이것을 그 어미에게 주니라"},{"n":29,"t":"요한의 제자들이 듣고 와서 시체를 가져다가 장사하니라"},{"n":30,"t":"사도들이 예수께 모여 자기들의 행한 것과 가르친 것을 낱낱이 고하니"},{"n":31,"t":"이르시되 너희는 따로 한적한 곳에 와서 잠간 쉬어라 하시니 이는 오고 가는 사람이 많아 음식 먹을 겨를도 없음이라"},{"n":32,"t":"이에 배를 타고 따로 한적한 곳에 갈쌔"},{"n":33,"t":"그 가는 것을 보고 많은 사람이 저희인줄 안지라 모든 고을로부터 도보로 그 곳에 달려와 저희보다 먼저 갔더라"},{"n":34,"t":"예수께서 나오사 큰 무리를 보시고 그 목자 없는 양 같음을 인하여 불쌍히 여기사 이에 여러 가지로 가르치시더라"},{"n":35,"t":"때가 저물어가매 제자들이 예수께 나아와 여짜오되 이곳은 빈 들이요 때도 저물어가니"},{"n":36,"t":"무리를 보내어 두루 촌과 마을로 가서 무엇을 사 먹게 하옵소서"},{"n":37,"t":"대답하여 가라사대 너희가 먹을 것을 주라 하시니 여짜오되 우리가 가서 이백 데나리온의 떡을 사다 먹이리이까"},{"n":38,"t":"이르시되 너희에게 떡 몇 개나 있느냐 가서 보라 하시니 알아보고 가로되 떡 다섯 개와 물고기 두 마리가 있더이다 하거늘"},{"n":39,"t":"제자들을 명하사 그 모든 사람으로 떼를 지어 푸른 잔디 위에 앉게 하시니"},{"n":40,"t":"떼로 혹 백씩, 혹 오십씩 앉은지라"},{"n":41,"t":"예수께서 떡 다섯개와 물고기 두 마리를 가지사 하늘을 우러러 축사하시고 떡을 떼어 제자들에게 주어 사람들 앞에 놓게 하시고 또 물고기 두 마리도 모든 사람에게 나누어 주시매"},{"n":42,"t":"다 배불리 먹고"},{"n":43,"t":"남은 떡 조각과 물고기를 열 두 바구니에 차게 거두었으며"},{"n":44,"t":"떡을 먹은 남자가 오천명이었더라"},{"n":45,"t":"예수께서 즉시 제자들을 재촉하사 자기가 무리를 보내는 동안에 배 타고 앞서 건너편 벳새다로 가게 하시고"},{"n":46,"t":"무리를 작별하신 후에 기도하러 산으로 가시다"},{"n":47,"t":"저물매 배는 바다 가운데 있고 예수는 홀로 뭍에 계시다가"},{"n":48,"t":"바람이 거스리므로 제자들의 괴로이 노 젓는 것을 보시고 밤 사경 즈음에 바다 위로 걸어서 저희에게 오사 지나가려고 하시매"},{"n":49,"t":"제자들이 그의 바다 위로 걸어 오심을 보고 유령인가 하여 소리 지르니"},{"n":50,"t":"저희가 다 예수를 보고 놀람이라 이에 예수께서 곧 더불어 말씀하여 가라사대 안심하라 내니 두려워 말라 하시고"},{"n":51,"t":"배에 올라 저희에게 가시니 바람이 그치는지라 제자들이 마음에 심히 놀라니"},{"n":52,"t":"이는 저희가 그 떡 떼시던 일을 깨닫지 못하고 도리어 그 마음이 둔하여졌음이러라"},{"n":53,"t":"건너가 게네사렛 땅에 이르러 대고"},{"n":54,"t":"배에서 내리니 사람들이 곧 예수신 줄을 알고"},{"n":55,"t":"그 온 지방으로 달려 돌아 다니며 예수께서 어디 계시단 말을 듣는대로 병든 자를 침상채로 메고 나아오니"},{"n":56,"t":"아무데나 예수께서 들어가시는 마을이나 도시나 촌에서 병자를 시장에 두고 예수의 옷가에라도 손을 대게 하시기를 간구하니 손을 대는 자는 다 성함을 얻으니라"}],"kids":[{"n":1,"t":"예수님이 거기서 떠나 자기 동네로 가시니 제자들이 따랐어요."},{"n":2,"t":"안식일에 회당에서 가르치셨어요. 많은 사람이 듣고 놀라며 \\"이 사람이 이것들을 어디서 얻었지? 그가 받은 지혜는 어떤 지혜야? 그의 손으로 이런 능력이 나오니!\\""},{"n":3,"t":"\\"그는 목수이고 마리아의 아들이며 야고보, 요셉, 유다, 시몬의 형제가 아니야? 그의 누이들도 다 우리와 함께 있잖아?\\" 하며 그를 거부했어요."},{"n":4,"t":"예수님이 \\"예언자는 자기 동네와 친척과 자기 집 외에는 무시당하지 않는다\\" 하셨어요."},{"n":5,"t":"거기서 예수님이 아무 능력도 행하실 수 없었고 다만 병자 몇에게 손을 얹어 고치셨어요."},{"n":6,"t":"그들의 불신을 이상히 여기시고 동네들을 돌아다니며 가르치셨어요."},{"n":7,"t":"예수님이 열두 제자를 부르시고 둘씩 보내시며 더러운 영을 다스리는 권세를 주셨어요."},{"n":8,"t":"여행 길에 지팡이 외에는 아무것도 가지지 말라고 명하시고 떡도, 배낭도, 돈주머니에 돈도 가지지 말고,"},{"n":9,"t":"신발은 신고 옷 두 벌은 입지 말라 하셨어요."},{"n":10,"t":"예수님이 \\"어디든 한 집에 들어가거든 그 동네를 떠날 때까지 거기 머물러라.\\""},{"n":11,"t":"\\"어디서나 너희를 받지 않고 너희 말을 듣지 않거든 거기서 나갈 때 너희 발 아래 먼지를 떨어 그들에게 증거 삼아라\\" 하셨어요."},{"n":12,"t":"제자들이 가서 회개하라고 전했어요."},{"n":13,"t":"많은 귀신을 쫓아내고 많은 병자에게 기름을 바르고 고쳤어요."},{"n":14,"t":"헤롯 왕이 예수님의 이름을 듣게 됐어요. 사람들이 \\"세례 요한이 죽은 자 가운데서 살아났어. 그래서 이런 능력이 그에게서 나타나는 거야\\" 하고 말했거든요."},{"n":15,"t":"다른 사람들은 \\"엘리야야\\" 하고, 또 다른 사람들은 \\"옛 예언자 중 하나야\\" 하고 말했어요."},{"n":16,"t":"헤롯이 듣고 \\"내가 목 벤 요한이 살아났어\\" 하고 말했어요."},{"n":17,"t":"헤롯이 자기 동생 빌립의 아내 헤로디아 때문에 사람을 보내 요한을 잡아 묶어 감옥에 가두었어요. 그 여자와 결혼했기 때문이에요."},{"n":18,"t":"요한이 헤롯에게 \\"동생의 아내를 데리고 사는 것은 옳지 않아요\\" 하고 말했거든요."},{"n":19,"t":"헤로디아가 요한을 미워하고 죽이려 했지만 못했어요."},{"n":20,"t":"헤롯이 요한을 의롭고 거룩한 사람으로 알고 두려워하며 그를 보호했고, 그의 말을 들을 때 많이 당황했지만 즐겨 들었거든요."},{"n":21,"t":"마침내 기회가 왔어요. 헤롯의 생일에 그가 자기 대신과 천부장과 갈릴리의 귀인들에게 잔치를 베풀었어요."},{"n":22,"t":"헤로디아의 딸이 들어와 춤추어 헤롯과 함께 앉은 사람들을 기쁘게 했어요. 왕이 그 소녀에게 \\"무엇이든 원하는 것을 청해라. 내가 줄게\\" 하고,"},{"n":23,"t":"\\"네가 무엇을 청하든 내 나라의 반까지 주겠다\\" 하고 맹세했어요."},{"n":24,"t":"소녀가 나가서 어머니에게 \\"무엇을 청할까요?\\" 하고 묻자, 어머니가 \\"세례 요한의 머리\\" 하고 답했어요."},{"n":25,"t":"소녀가 곧 급히 왕에게 가서 \\"세례 요한의 머리를 쟁반에 담아 곧 주세요\\" 하고 청했어요."},{"n":26,"t":"왕이 매우 슬펐지만 맹세와 함께 앉은 사람들 때문에 거절할 수 없었어요."},{"n":27,"t":"왕이 곧 호위병을 보내 요한의 머리를 가져오라고 명령했어요. 호위병이 가서 감옥에서 그의 목을 베고,"},{"n":28,"t":"머리를 쟁반에 담아 가져다 소녀에게 주니, 소녀가 어머니에게 가져갔어요."},{"n":29,"t":"요한의 제자들이 듣고 와서 시신을 가져다가 무덤에 두었어요."},{"n":30,"t":"사도들이 예수님께 모여 그들이 한 일과 가르친 모든 것을 보고했어요."},{"n":31,"t":"예수님이 \\"너희만 따로 한적한 곳에 가서 잠시 쉬어라\\" 하셨어요. 오고 가는 사람이 많아 먹을 틈도 없었거든요."},{"n":32,"t":"그들이 배를 타고 한적한 곳으로 갔어요."},{"n":33,"t":"많은 사람들이 가는 것을 보고 알아채서, 모든 동네에서 그곳으로 걸어 모여 예수님 일행보다 먼저 거기에 갔어요."},{"n":34,"t":"예수님이 배에서 내리시고 큰 무리를 보시고 그들이 목자 없는 양 같아 불쌍히 여기시고 많은 것을 가르치셨어요."},{"n":35,"t":"날이 많이 저물자 제자들이 와서 \\"이곳은 한적한 곳이고 시간이 많이 늦었어요.\\""},{"n":36,"t":"\\"무리를 보내 둘레 농장이나 동네에 가서 자기들이 먹을 것을 사 먹게 하세요\\" 하고 말했어요."},{"n":37,"t":"예수님이 \\"너희가 먹을 것을 줘\\" 하셨어요. 그들이 \\"우리가 가서 이백 데나리온의 빵을 사다 그들에게 먹이라는 말씀이세요?\\" 하고 답했어요."},{"n":38,"t":"예수님이 \\"너희에게 빵이 몇 개 있니? 가서 봐\\" 하셨어요. 알아본 후 \\"다섯 개와 물고기 두 마리요\\" 하고 답했어요."},{"n":39,"t":"예수님이 모든 사람을 푸른 풀밭에 떼를 지어 앉히라고 하셨어요."},{"n":40,"t":"사람들이 백 명씩, 오십 명씩 모여 앉았어요."},{"n":41,"t":"예수님이 다섯 개의 빵과 두 마리의 물고기를 가지시고 하늘을 우러러 축복하시고 빵을 떼어 제자들에게 주어 그들 앞에 놓게 하셨고, 두 마리의 물고기도 모두에게 나누셨어요."},{"n":42,"t":"모두 먹고 배불렀어요."},{"n":43,"t":"빵 조각과 물고기를 거두니 열두 바구니에 가득했어요."},{"n":44,"t":"빵을 먹은 남자가 오천 명이었어요."},{"n":45,"t":"예수님이 곧 제자들을 재촉하여 배에 태우고 자기보다 먼저 건너편 벳새다로 가게 하시고, 그동안 무리를 보내셨어요."},{"n":46,"t":"그들을 떠나보내신 후 예수님은 기도하시려고 산으로 가셨어요."},{"n":47,"t":"저녁이 되어 배는 호수 한가운데 있었고 예수님은 홀로 육지에 계셨어요."},{"n":48,"t":"바람이 거슬러 부니 제자들이 노 젓기에 시달리는 것을 보고, 새벽 사 경쯤 예수님이 호수 위를 걸어 그들에게 오시며 지나가시려 했어요."},{"n":49,"t":"제자들이 예수님이 호수 위를 걷는 것을 보고 유령인 줄로 알고 소리쳤어요."},{"n":50,"t":"모두 그분을 보고 두려워했어요. 예수님이 곧 그들에게 말씀하셨어요. \\"안심해. 나야. 두려워하지 마.\\""},{"n":51,"t":"예수님이 배에 함께 오르시자 바람이 그쳤어요. 제자들이 마음으로 매우 놀랐어요."},{"n":52,"t":"그들이 빵 사건을 깨닫지 못했기 때문이에요. 그들의 마음이 굳어 있었어요."},{"n":53,"t":"건너가 게네사렛 땅에 닿아 배를 매었어요."},{"n":54,"t":"배에서 내리자 사람들이 곧 예수님을 알아보고,"},{"n":55,"t":"온 지역을 뛰어다니며 어디든 예수님이 계신 곳마다 병자들을 침대에 메어 데려오기 시작했어요."},{"n":56,"t":"동네든 도시든 시골이든 어디든 들어가시는 곳마다 사람들이 병자들을 시장에 두고 그분의 옷자락이라도 만지게 해 달라고 청했어요. 그것을 만진 사람마다 다 나았어요."}]}},{"chapter":7,"title":"사람을 더럽히는 것","verses":{"krv":[{"n":1,"t":"바리새인들과 또 서기관 중 몇이 예루살렘에서 와서 예수께 모였다가"},{"n":2,"t":"그의 제자 중 몇 사람의 부정한 손 곧 씻지 아니한 손으로 떡 먹는 것을 보았더라"},{"n":3,"t":"(바리새인들과 모든 유대인들이 장로들의 유전을 지키어 손을 부지런히 씻지 않으면 먹지 아니하며"},{"n":4,"t":"또 시장에서 돌아 와서는 물을 뿌리지 않으면 먹지 아니하며 그외에도 여러가지를 지키어 오는 것이 있으니 잔과 주발과 놋그릇을 씻음이러라)"},{"n":5,"t":"이에 바리새인들과 서기관들이 예수께 묻되 어찌하여 당신의 제 자들은 장로들의 유전을 준행치 아니하고 부정한 손으로 떡을 먹나이까"},{"n":6,"t":"가라사대 이사야가 너희 외식하는 자에 대하여 잘 예언하였도다 기록하였으되 이 백성이 입술로는 나를 존경하되 마음은 내게서 멀도다"},{"n":7,"t":"사람의 계명으로 교훈을 삼아 가르치니 나를 헛되이 경배하는도다 하였느니라"},{"n":8,"t":"너희가 하나님의 계명은 버리고 사람의 유전을 지키느니라"},{"n":9,"t":"또 가라사대 너희가 너희 유전을 지키려고 하나님의 계명을 잘 저버리는도다"},{"n":10,"t":"모세는 네 부모를 공경하라 하고 또 아비나 어미를 훼방하는 자는 반드시 죽으리라 하였거늘"},{"n":11,"t":"너희는 가로되 사람이 아비에게나 어미에게나 말하기를 내가 드려 유익하게 할 것이 고르반 곧 하나님께 드림이 되었다고 하기만 하면 그만이라 하고"},{"n":12,"t":"제 아비나 어미에게 다시 아무 것이라도 하여 드리기를 허하지 아니하여"},{"n":13,"t":"너희의 전한 유전으로 하나님의 말씀을 폐하며 또 이같은 일을 많이 행하느니라 하시고"},{"n":14,"t":"무리를 다시 불러 이르시되 너희는 다 내 말을 듣고 깨달으라"},{"n":15,"t":"무엇이든지 밖에서 사람에게로 들어가는 것은 능히 사람을 더럽게 하지 못하되"},{"n":16,"t":"사람 안에서 나오는 것이 사람을 더럽게 하는 것이니라 하시고"},{"n":17,"t":"무리를 떠나 집으로 들어가시니 제자들이 그 비유를 묻자온대"},{"n":18,"t":"예수께서 이르시되 너희도 이렇게 깨달음이 없느냐 무엇이든지 밖에서 들어가는 것이 능히 사람을 더럽게 하지 못함을 알지 못하느냐"},{"n":19,"t":"이는 마음에 들어가지 아니하고 배에 들어가 뒤로 나감이니라 하심으로 모든 식물을 깨끗하다 하셨느니라"},{"n":20,"t":"또 가라사대 사람에게서 나오는 그것이 사람을 더럽게 하느니라"},{"n":21,"t":"속에서 곧 사람의 마음에서 나오는 것은 악한 생각 곧 음란과 도적질과 살인과"},{"n":22,"t":"간음과 탐욕과 악독과 속임과 음탕과 흘기는 눈과 훼방과 교만과 광패니"},{"n":23,"t":"이 모든 악한 것이 다 속에서 나와서 사람을 더럽게 하느니라"},{"n":24,"t":"예수께서 일어나사 거기를 떠나 두로 지경으로 가서 한 집에 들어가 아무도 모르게 하시려하나 숨길 수 없더라"},{"n":25,"t":"이에 더러운 귀신 들린 어린 딸을 둔 한 여자가 예수의 소문을 듣고 곧 와서 그 발 아래 엎드리니"},{"n":26,"t":"그 여자는 헬라인이요 수로보니게 족속이라 자기 딸에게서 귀신 쫓아 주시기를 간구하거늘"},{"n":27,"t":"예수께서 이르시되 자녀로 먼저 배불리 먹게 할지니 자녀의 떡을 취하여 개들에게 던짐이 마땅치 아니하니라"},{"n":28,"t":"여자가 대답하여 가로되 주여 옳소이다마는 상 아래 개들도 아이들의 먹던 부스러기를 먹나이다"},{"n":29,"t":"예수께서 가라사대 이 말을 하였으니 돌아가라 귀신이 네 딸에게서 나갔느니라 하시매"},{"n":30,"t":"여자가 집에 돌아가 본즉 아이가 침상에 누웠고 귀신이 나갔더라"},{"n":31,"t":"예수께서 다시 두로 지경에서 나와 시돈을 지나고 데가볼리 지경을 통과하여 갈릴리 호수에 이르시매"},{"n":32,"t":"사람들이 귀먹고 어눌한 자를 데리고 예수께 나아와 안수하여 주시기를 간구하거늘"},{"n":33,"t":"예수께서 그 사람을 따로 데리고 무리를 떠나사 손가락을 그의 양 귀에 넣고 침 뱉아 그의 혀에 손을 대시며"},{"n":34,"t":"하늘을 우러러 탄식하시며 그에게 이르시되 에바다 하시니 이는 열리라는 뜻이라"},{"n":35,"t":"그의 귀가 열리고 혀의 맺힌 것이 곧 풀려 말이 분명하더라"},{"n":36,"t":"예수께서 저희에게 경계하사 아무에게라도 이르지 말라 하시되 경계하실수록 저희가 더욱 널리 전파하니"},{"n":37,"t":"사람들이 심히 놀라 가로되 그가 다 잘 하였도다 귀머거리도 듣게 하고 벙어리도 말하게 한다 하니라"}],"kids":[{"n":1,"t":"바리새인들과 예루살렘에서 온 율법 학자 몇 사람이 예수님께 모였어요."},{"n":2,"t":"그들이 보니 예수님의 제자 중 어떤 사람들이 부정한 손, 곧 씻지 않은 손으로 빵을 먹었어요."},{"n":3,"t":"바리새인과 모든 유대인은 조상의 전통을 지켜 손을 꼭 씻지 않으면 먹지 않고,"},{"n":4,"t":"시장에서 돌아오면 몸을 씻지 않고는 먹지 않고, 잔과 그릇과 동그릇을 씻는 다른 많은 전통을 지키고 있었어요."},{"n":5,"t":"바리새인들과 율법 학자들이 \\"왜 주님의 제자들은 장로들의 전통대로 행하지 않고 부정한 손으로 빵을 먹어요?\\" 하고 물었어요."},{"n":6,"t":"예수님이 \\"이사야가 너희 위선자에 대해 잘 예언했어. \'이 백성이 입술로는 나를 공경하지만 그 마음은 나에게서 멀다.\\""},{"n":7,"t":"\\"사람의 가르침을 교훈으로 가르치니 헛되이 나를 예배한다.\'\\""},{"n":8,"t":"\\"너희가 하나님의 계명은 버리고 사람의 전통을 지킨다\\" 하셨어요."},{"n":9,"t":"\\"너희가 너희 전통을 지키려고 하나님의 계명을 잘도 어겨!\\""},{"n":10,"t":"\\"모세는 \'네 부모를 공경하라\' 하고 \'아버지나 어머니를 욕하는 사람은 반드시 죽임을 당하리라\' 했어.\\""},{"n":11,"t":"\\"그런데 너희는 \'누가 아버지나 어머니에게 「내게서 받을 것이 고르반(곧 하나님께 드림이다)이 되었다」 하면\',\\""},{"n":12,"t":"\\"그가 자기 아버지나 어머니에게 다시는 아무것도 하지 않게 두니,\\""},{"n":13,"t":"\\"너희가 너희 전통으로 하나님의 말씀을 폐하고 이와 같은 일을 많이 행해\\" 하셨어요."},{"n":14,"t":"예수님이 다시 무리를 부르시고 \\"너희가 다 듣고 깨달아라.\\""},{"n":15,"t":"\\"바깥에서 사람에게 들어가는 것은 그를 더럽히지 못해. 그러나 사람에게서 나오는 것이 사람을 더럽혀.\\""},{"n":16,"t":"\\"귀 있는 사람은 들어라\\" 하셨어요."},{"n":17,"t":"예수님이 무리를 떠나 집에 들어가시자 제자들이 그 비유에 대해 물었어요."},{"n":18,"t":"예수님이 \\"너희도 그리 깨달음이 없니? 바깥에서 들어가는 것이 사람을 더럽힐 수 없는 줄을 모르니?\\""},{"n":19,"t":"\\"이는 마음에 들어가지 않고 배에 들어가 변소로 나가는 거야.\\" 이는 모든 음식이 깨끗하다고 하신 거예요."},{"n":20,"t":"또 말씀하셨어요. \\"사람에게서 나오는 것이 사람을 더럽혀.\\""},{"n":21,"t":"\\"안에서, 곧 사람의 마음에서 악한 생각, 음행, 도둑질, 살인,\\""},{"n":22,"t":"\\"간음, 탐욕, 악독, 속임, 방탕, 시기, 모독, 교만, 어리석음이 나와.\\""},{"n":23,"t":"\\"이 모든 악은 안에서 나와 사람을 더럽혀.\\""},{"n":24,"t":"예수님이 거기서 일어나 두로 지역으로 가셔서 한 집에 들어가 아무도 알지 못하게 하셨지만 숨길 수 없었어요."},{"n":25,"t":"더러운 영이 들린 어린 딸을 둔 한 여자가 듣고 와서 예수님 발 앞에 엎드렸어요."},{"n":26,"t":"이 여자는 헬라인이고 수로보니게 출신이었어요. 그녀가 자기 딸에게서 귀신을 쫓아 달라고 청했어요."},{"n":27,"t":"예수님이 \\"먼저 자녀들을 배부르게 하라. 자녀의 빵을 가져다 강아지에게 던지는 것은 옳지 않다\\" 하셨어요."},{"n":28,"t":"그녀가 \\"맞아요, 주님. 그러나 상 아래 강아지도 자녀의 부스러기를 먹어요\\" 하고 답했어요."},{"n":29,"t":"예수님이 \\"이 말을 했으니 가라. 귀신이 네 딸에게서 나갔다\\" 하셨어요."},{"n":30,"t":"그녀가 집에 가 보니 아이가 침대에 누워 있고 귀신이 나갔어요."},{"n":31,"t":"예수님이 두로 지역에서 나가서 시돈을 거쳐 데가볼리 지방을 지나 갈릴리 호수로 오셨어요."},{"n":32,"t":"사람들이 귀먹고 말 더듬는 사람을 데려와 그에게 손을 얹어 달라고 청했어요."},{"n":33,"t":"예수님이 그를 무리에서 따로 데리고 가셔서 손가락을 그의 귀에 넣으시고 침을 뱉어 그의 혀에 손을 대시고,"},{"n":34,"t":"하늘을 우러러 한숨을 쉬시며 \\"에바다!\\" 하셨어요. 풀이하면 \\"열려라!\\"예요."},{"n":35,"t":"곧 그의 귀가 열리고 혀가 풀려 똑똑히 말했어요."},{"n":36,"t":"예수님이 아무에게도 말하지 말라 명하셨지만 명할수록 그들이 더 널리 전했어요."},{"n":37,"t":"사람들이 매우 놀라며 \\"그분이 모든 것을 잘하셨네. 귀먹은 사람도 듣게 하시고 말 못하는 사람도 말하게 하시네\\" 하고 말했어요."}]}},{"chapter":8,"title":"베드로의 고백과 십자가 예고","verses":{"krv":[{"n":1,"t":"그 즈음에 또 큰 무리가 있어 먹을 것이 없는지라 예수께서 제자들을 불러 이르시되"},{"n":2,"t":"내가 무리를 불쌍히 여기노라 저희가 나와 함께 있은지 이미 사흘이매 먹을 것이 없도다"},{"n":3,"t":"만일 내가 저희를 굶겨 집으로 보내면 길에서 기진하리라 그 중에는 멀리서 온 사람도 있느니라"},{"n":4,"t":"제자들이 대답하되 이 광야에서 어디서 떡을 얻어 이 사람들로 배부르게 할 수 있으리이까"},{"n":5,"t":"예수께서 물으시되 너희에게 떡 몇개나 있느냐 가로되 일곱이로소이다 하거늘"},{"n":6,"t":"예수께서 무리를 명하사 땅에 앉게 하시고 떡 일곱 개를 가지사 축사하시고 떼어 제자들에게 주어 그 앞에 놓게 하시니 제자들이 무리 앞에 놓더라"},{"n":7,"t":"또 작은 생선 두어 마리가 있는지라 이에 축복하시고 명하사 이것도 그 앞에 놓게 하시니"},{"n":8,"t":"배불리 먹고 남은 조각 일곱 광주리를 거두었으며"},{"n":9,"t":"사람은 약 사천명이었더라 예수께서 저희를 흩어 보내시고"},{"n":10,"t":"곧 제자들과 함께 배에 오르사 달마누다 지방으로 가시니라"},{"n":11,"t":"바리새인들이 나와서 예수께 힐난하며 그를 시험하여 하늘로서 오는 표적을 구하거늘"},{"n":12,"t":"예수께서 마음 속에 깊이 탄식하시며 가라사대 어찌하여 이 세대가 표적을 구하느냐 내가 진실로 너희에게 이르노니 이 세대에게 표적을 주시지 아니하리라 하시고"},{"n":13,"t":"저희를 떠나 다시 배에 올라 건너편으로 가시니라"},{"n":14,"t":"제자들이 떡 가져 오기를 잊었으매 배에 떡 한 개 밖에 저희에게 없더라"},{"n":15,"t":"예수께서 경계하여 가라사대 삼가 바리새인들의 누룩과 헤롯의 누룩을 주의하라 하신대"},{"n":16,"t":"제자들이 서로 의논하기를 이는 우리에게 떡이 없음이로다 하거 늘"},{"n":17,"t":"예수께서 아시고 이르시되 너희가 어찌 떡이 없음으로 의논하느냐 아직도 알지 못하며 깨닫지 못하느냐 너희 마음이 둔하냐"},{"n":18,"t":"너희가 눈이 있어도 보지 못하며 귀가 있어도 듣지 못하느냐 또 기억지 못하느냐"},{"n":19,"t":"내가 떡 다섯 개를 오천명에게 떼어 줄 때에 조각 몇 바구니를 거두었더냐 가로되 열 둘이니이다"},{"n":20,"t":"또 일곱 개를 사천명에게 떼어 줄 때에 조각 몇 광주리를 거두었더냐 가로되 일곱이니이다"},{"n":21,"t":"가라사대 아직도 깨닫지 못하느냐 하시니라"},{"n":22,"t":"벳새다에 이르매 사람들이 소경 하나를 데리고 예수께 나아와 손대시기를 구하거늘"},{"n":23,"t":"예수께서 소경의 손을 붙드시고 마을 밖으로 데리고 나가사 눈에 침을 뱉으시며 그에게 안수하시고 무엇이 보이느냐 물으시니"},{"n":24,"t":"우러러보며 가로되 사람들이 보이나이다 나무 같은 것들의 걸어 가는 것을 보나이다 하거늘"},{"n":25,"t":"이에 그 눈에 다시 안수하시매 저가 주목하여 보더니 나아서 만물을 밝히 보는지라"},{"n":26,"t":"예수께서 그 사람을 집으로 보내시며 가라사대 마을에도 들어가지 말라 하시니라"},{"n":27,"t":"예수와 제자들이 가이사랴 빌립보 여러 마을로 나가실쌔 노중에서 제자들에게 물어 가라사대 사람들이 나를 누구라고 하느냐"},{"n":28,"t":"여짜와 가로되 세례 요한이라 하고 더러는 엘리야, 더러는 선지자 중의 하나라 하나이다"},{"n":29,"t":"또 물으시되 너희는 나를 누구라 하느냐 베드로가 대답하여 가로되 주는 그리스도시니이다 하매"},{"n":30,"t":"이에 자기의 일을 아무에게도 말하지 말라 경계하시고"},{"n":31,"t":"인자가 많은 고난을 받고 장로들과 대제사장들과 서기관들에게 버린바 되어 죽임을 당하고 사흘만에 살아나야 할 것을 비로소 저희에게 가르치시되"},{"n":32,"t":"드러내놓고 이 말씀을 하시니 베드로가 예수를 붙들고 간하매"},{"n":33,"t":"예수께서 돌이키사 제자들을 보시며 베드로를 꾸짖어 가라사대 사단아 내 뒤로 물러가라 네가 하나님의 일을 생각지 아니하고 도리어 사람의 일을 생각하는도다 하시고"},{"n":34,"t":"무리와 제자들을 불러 이르시되 아무든지 나를 따라 오려거든 자기를 부인하고 자기 십자가를 지고 나를 좇을 것이니라"},{"n":35,"t":"누구든지 제 목숨을 구원코자 하면 잃을 것이요 누구든지 나와 복음을 위하여 제 목숨을 잃으면 구원하리라"},{"n":36,"t":"사람이 만일 온 천하를 얻고도 제 목숨을 잃으면 무엇이 유익하리요"},{"n":37,"t":"사람이 무엇을 주고 제 목숨을 바꾸겠느냐"},{"n":38,"t":"누구든지 이 음란하고 죄 많은 세대에서 나와 내 말을 부끄러워 하면 인자도 아버지의 영광으로 거룩한 천사들과 함께 올 때에 그 사람을 부끄러워하리라"}],"kids":[{"n":1,"t":"그 무렵 또 큰 무리가 있었어요. 그들에게 먹을 것이 없자 예수님이 제자들을 부르시고,"},{"n":2,"t":"\\"내가 무리를 불쌍히 여긴다. 사흘이나 나와 함께 있었는데 먹을 것이 없어.\\""},{"n":3,"t":"\\"그들을 굶겨 보내면 길에서 지칠 거야. 그중 더러는 멀리서 왔어\\" 하셨어요."},{"n":4,"t":"제자들이 \\"이 광야에서 어디서 빵을 얻어 이 사람들을 배부르게 할까요?\\" 하고 답했어요."},{"n":5,"t":"예수님이 \\"너희에게 빵이 몇 개 있니?\\" 하시니, 그들이 \\"일곱이요\\" 하고 답했어요."},{"n":6,"t":"예수님이 무리를 땅에 앉으라 하시고 일곱 개의 빵을 가지시고 감사하시고 떼어 제자들에게 주어 무리에게 나누게 하셨어요."},{"n":7,"t":"또 작은 물고기 몇 마리가 있었어요. 축복하시고 그것들도 나누게 하셨어요."},{"n":8,"t":"모두 먹고 배불렀어요. 남은 조각을 일곱 바구니에 거두었어요."},{"n":9,"t":"먹은 사람이 약 사천 명이었어요. 예수님이 그들을 보내셨어요."},{"n":10,"t":"예수님이 곧 제자들과 함께 배에 올라 달마누다 지역으로 가셨어요."},{"n":11,"t":"바리새인들이 와서 예수님과 따지며 시험하려고 하늘에서 표적을 요구했어요."},{"n":12,"t":"예수님이 마음으로 깊이 한숨을 쉬시며 \\"왜 이 세대가 표적을 구하지? 진정으로 말한다. 이 세대에 표적이 주어지지 않을 거야\\" 하셨어요."},{"n":13,"t":"그들을 떠나 다시 배에 올라 건너편으로 가셨어요."},{"n":14,"t":"제자들이 빵을 가져오는 것을 잊어버려서 배에 빵 한 개밖에 없었어요."},{"n":15,"t":"예수님이 \\"조심해. 바리새인의 누룩과 헤롯의 누룩을 조심해\\" 하셨어요."},{"n":16,"t":"제자들이 서로 \\"우리가 빵을 가져오지 않아서 그러는 거야\\" 하고 의논했어요."},{"n":17,"t":"예수님이 아시고 \\"왜 너희가 빵이 없다고 의논하니? 아직 알지 못하고 깨닫지 못하니? 너희 마음이 굳어졌니?\\""},{"n":18,"t":"\\"눈이 있어도 보지 못하고 귀가 있어도 듣지 못하니? 기억하지 못하니?\\""},{"n":19,"t":"\\"내가 빵 다섯 개로 오천 명을 먹였을 때 너희가 거둔 조각이 몇 바구니였니?\\" 그들이 \\"열두요\\" 하고 답했어요."},{"n":20,"t":"\\"빵 일곱 개로 사천 명일 때 거둔 것은 몇 바구니였니?\\" 그들이 \\"일곱이요\\" 했어요."},{"n":21,"t":"예수님이 \\"아직도 깨닫지 못하니?\\" 하셨어요."},{"n":22,"t":"그들이 벳새다에 갔어요. 사람들이 한 맹인을 예수님께 데리고 와서 만져 달라고 청했어요."},{"n":23,"t":"예수님이 맹인의 손을 잡고 동네 밖으로 데리고 가시고 그의 눈에 침을 뱉고 손을 얹으시고 \\"무엇이 보이니?\\" 하고 물으셨어요."},{"n":24,"t":"그가 \\"사람들이 보여요. 나무처럼 걸어다녀요\\" 하고 답했어요."},{"n":25,"t":"예수님이 다시 그의 눈에 손을 얹으셨어요. 그가 보니 회복되어 모든 것을 똑똑히 보았어요."},{"n":26,"t":"예수님이 그를 집으로 보내며 \\"동네에 들어가지 마라\\" 하셨어요."},{"n":27,"t":"예수님이 제자들과 함께 가이사랴 빌립보 동네들로 나가셨어요. 길에서 제자들에게 \\"사람들이 나를 누구라고 하니?\\" 하고 물으셨어요."},{"n":28,"t":"그들이 \\"세례 요한이라고도 하고 엘리야, 또는 예언자 중 하나라고도 해요\\" 하고 답했어요."},{"n":29,"t":"예수님이 \\"너희는 나를 누구라고 하니?\\" 하시니, 베드로가 \\"주님은 그리스도세요\\" 하고 답했어요."},{"n":30,"t":"예수님이 자기에 대해 아무에게도 말하지 말라고 엄히 분부하셨어요."},{"n":31,"t":"그리고 사람의 아들이 많은 고난을 받고 장로들과 대제사장들과 율법 학자들에게 거부당하고 죽임을 당하고 사흘 후에 다시 살아나야 한다고 그들에게 가르치기 시작하셨어요."},{"n":32,"t":"예수님이 이 말씀을 드러내 놓고 하셨어요. 베드로가 예수님을 따로 데려가 말리기 시작했어요."},{"n":33,"t":"예수님이 돌아서서 제자들을 보시고 베드로를 꾸짖으셨어요. \\"사탄아, 내 뒤로 물러가라. 너는 하나님의 일이 아니라 사람의 일을 생각하는구나.\\""},{"n":34,"t":"예수님이 무리와 제자들을 부르시고 \\"누구든지 나를 따라오려거든 자기를 부인하고 자기 십자가를 지고 나를 따르라.\\""},{"n":35,"t":"\\"누구든지 자기 목숨을 구하려는 사람은 잃고, 나와 복음을 위해 자기 목숨을 잃는 사람은 구할 거야.\\""},{"n":36,"t":"\\"사람이 온 세상을 얻고도 자기 영혼을 잃으면 무슨 유익이 있겠니?\\""},{"n":37,"t":"\\"사람이 자기 영혼과 무엇을 바꾸겠니?\\""},{"n":38,"t":"\\"이 음란하고 죄 많은 세대에서 누구든지 나와 내 말을 부끄러워하면 사람의 아들도 자기 아버지의 영광으로 거룩한 천사들과 함께 올 때 그를 부끄러워할 거야\\" 하셨어요."}]}},{"chapter":9,"title":"변화산과 어린아이","verses":{"krv":[{"n":1,"t":"또 저희에게 이르시되 내가 진실로 너희에게 이르노니 여기 섰는 사람중에 죽기 전에 하나님의 나라가 권능으로 임하는 것을 볼 자들도 있느니라 하시니라"},{"n":2,"t":"엿새 후에 예수께서 베드로와 야고보와 요한을 데리시고 따로 높은 산에 올라 가셨더니 저희 앞에서 변형되사"},{"n":3,"t":"그 옷이 광채가 나며 세상에서 빨래하는 자가 그렇게 희게 할 수 없을만큼 심히 희어졌더라"},{"n":4,"t":"이에 엘리야가 모세와 함께 저희에게 나타나 예수로 더불어 말씀하거늘"},{"n":5,"t":"베드로가 예수께 고하되 랍비여 우리가 여기 있는 것이 좋사오니 우리가 초막 셋을 짓되 하나는 주를 위하여, 하나는 모세를 위하여, 하나는 엘리야를 위하여 하사이다 하니"},{"n":6,"t":"이는 저희가 심히 무서워하므로 저가 무슨 말을 할는지 알지 못함이더라"},{"n":7,"t":"마침 구름이 와서 저희를 덮으며 구름 속에서 소리가 나되 이는 내 사랑하는 아들이니 너희는 저의 말을 들으라 하는지라"},{"n":8,"t":"문득 둘러보니 아무도 보이지 아니하고 오직 예수와 자기들 뿐이었더라"},{"n":9,"t":"저희가 산에서 내려 올 때에 예수께서 경계하시되 인자가 죽은 자 가운데서 살아날 때까지는 본 것을 아무에게도 이르지 말라 하시니"},{"n":10,"t":"저희가 이 말씀을 마음에 두며 서로 문의하되 죽은 자 가운데서 살아나는 것이 무엇일까 하고"},{"n":11,"t":"이에 예수께 묻자와 가로되 어찌하여 서기관들이 엘리야가 먼저 와야 하리라 하나이까"},{"n":12,"t":"가라사대 엘리야가 과연 먼저 와서 모든 것을 회복하거니와 어찌 인자에 대하여 기록하기를 많은 고난을 받고 멸시를 당하리라 하였느냐"},{"n":13,"t":"그러나 내가 너희에게 이르노니 엘리야가 왔으되 기록된 바와 같이 사람들이 임의로 대우하였느니라 하시니라"},{"n":14,"t":"저희가 이에 제자들에게 와서 보니 큰 무리가 둘렀고 서기관들이 더불어 변론하더니"},{"n":15,"t":"온 무리가 곧 예수를 보고 심히 놀라며 달려와 문안하거늘"},{"n":16,"t":"예수께서 물으시되 너희가 무엇을 저희와 변론하느냐"},{"n":17,"t":"무리 중에 하나가 대답하되 선생님 벙어리 귀신 들린 내 아들을 선생님께 데려 왔나이다"},{"n":18,"t":"귀신이 어디서든지 저를 잡으면 거꾸러져 거품을 흘리며 이를 갈며 그리고 파리하여 가는지라 내가 선생의 제자들에게 내어쫓아 달라 하였으나 저희가 능히 하지 못하더이다"},{"n":19,"t":"대답하여 가라사대 믿음이 없는 세대여 내가 얼마나 너희와 함께 있으며 얼마나 너희를 참으리요 그를 내게로 데려오라 하시매"},{"n":20,"t":"이에 데리고 오니 귀신이 예수를 보고 곧 그 아이로 심히 경련을 일으키게 하는지라 저가 땅에 엎드러져 굴며 거품을 흘리더라"},{"n":21,"t":"예수께서 그 아비에게 물으시되 언제부터 이렇게 되었느냐 하시니 가로되 어릴 때부터니이다"},{"n":22,"t":"귀신이 저를 죽이려고 불과 물에 자주 던졌나이다 그러나 무엇을 하실 수 있거든 우리를 불쌍히 여기사 도와 주옵소서"},{"n":23,"t":"예수께서 이르시되 할 수 있거든이 무슨 말이냐 믿는 자에게는 능치 못할 일이 없느니라 하시니"},{"n":24,"t":"곧 그 아이의 아비가 소리를 질러 가로되 내가 믿나이다 나의 믿음 없는 것을 도와 주소서 하더라"},{"n":25,"t":"예수께서 무리의 달려 모이는 것을 보시고 그 더러운 귀신을 꾸짖어 가라사대 벙어리 되고 귀먹은 귀신아 내가 네게 명하노니 그 아이에게서 나오고 다시 들어가지 말라 하시매"},{"n":26,"t":"귀신이 소리지르며 아이로 심히 경련을 일으키게 하고 나가니 그 아이가 죽은 것 같이 되어 많은 사람이 말하기를 죽었다 하나"},{"n":27,"t":"예수께서 그 손을 잡아 일으키시니 이에 일어서니라"},{"n":28,"t":"집에 들어가시매 제자들이 종용히 묻자오되 우리는 어찌하여 능히 그 귀신을 쫓아 내지 못하였나이까"},{"n":29,"t":"이르시되 기도 외에 다른 것으로는 이런 유가 나갈 수 없느니라 하시니라"},{"n":30,"t":"그곳을 떠나 갈릴리 가운데로 지날쌔 예수께서 아무에게도 알리고자 아니하시니"},{"n":31,"t":"이는 제자들을 가르치시며 또 인자가 사람들의 손에 넘기워 죽임을 당하고 죽은지 삼 일만에 살아나리라는 것을 말씀하시는 연고더라"},{"n":32,"t":"그러나 제자들은 이 말씀을 깨닫지 못하고 묻기도 무서워하더라"},{"n":33,"t":"가버나움에 이르러 집에 계실쌔 제자들에게 물으시되 너희가 노중에서 서로 토론한 것이 무엇이냐 하시되"},{"n":34,"t":"저희가 잠잠하니 이는 노중에서 서로 누가 크냐 하고 쟁론하였음이라"},{"n":35,"t":"예수께서 앉으사 열 두 제자를 불러서 이르시되 아무든지 첫째가 되고자 하면 뭇사람의 끝이 되며 뭇사람을 섬기는 자가 되어야 하리라 하시고"},{"n":36,"t":"어린 아이 하나를 데려다가 그들 가운데 세우시고 안으시며 제자들에게 이르시되"},{"n":37,"t":"누구든지 내 이름으로 이런 어린 아이 하나를 영접하면 곧 나를 영접함이요 누구든지 나를 영접하면 나를 영접함이 아니요 나를 보내신 이를 영접함이니라"},{"n":38,"t":"요한이 예수께 여짜오되 선생님 우리를 따르지 않는 어떤 자가 주의 이름으로 귀신을 내어 쫓는 것을 우리가 보고 우리를 따르지 아니하므로 금하였나이다"},{"n":39,"t":"예수께서 가라사대 금하지 말라 내 이름을 의탁하여 능한 일을 행하고 즉시로 나를 비방할 자가 없느니라"},{"n":40,"t":"우리를 반대하지 않는 자는 우리를 위하는 자니라"},{"n":41,"t":"누구든지 너희를 그리스도에게 속한 자라 하여 물 한 그릇을 주면 내가 진실로 너희에게 이르노니 저가 결단코 상을 잃지 않으리라"},{"n":42,"t":"또 누구든지 나를 믿는 이 소자 중 하나를 실족케 하면 차라리 연자 맷돌을 그 목에 달리우고 바다에 던지움이 나으리라"},{"n":43,"t":"만일 네 손이 너를 범죄케 하거든 찍어버리라 불구자로 영생에 들어가는 것이 두 손을 가지고 지옥 꺼지지 않는 불에 들어가는 것보다 나으니라"},{"n":44,"t":"(없 음)"},{"n":45,"t":"만일 네 발이 너를 범죄케 하거든 찍어 버리라 절뚝발이로 영생에 들어가는 것이 두 발을 가지고 지옥에 던지우는 것보다 나으니라"},{"n":46,"t":"(없 음)"},{"n":47,"t":"만일 네 눈이 너를 범죄케 하거든 빼어버리라 한 눈으로 하나님의 나라에 들어가는 것이 두 눈을 가지고 지옥에 던지우는 것보다 나으니라"},{"n":48,"t":"거기는 구더기도 죽지 않고 불도 꺼지지 아니하느니라"},{"n":49,"t":"사람마다 불로서 소금 치듯함을 받으리라"},{"n":50,"t":"소금은 좋은 것이로되 만일 소금이 그 맛을 잃으면 무엇으로 이를 짜게 하리요 너희 속에 소금을 두고 서로 화목하라 하시니라"}],"kids":[{"n":1,"t":"예수님이 \\"진정으로 말한다. 여기 서 있는 사람들 중에 죽기 전에 하나님 나라가 권능으로 임하는 것을 볼 사람들이 있다\\" 하셨어요."},{"n":2,"t":"엿새 후에 예수님이 베드로와 야고보와 요한을 데리고 따로 높은 산에 올라가셨어요. 그들 앞에서 모습이 변하셨어요."},{"n":3,"t":"옷이 빛나고 매우 희어져 세상 어느 빨래꾼도 그렇게 희게 할 수 없을 정도였어요."},{"n":4,"t":"엘리야와 모세가 그들에게 나타나 예수님과 함께 이야기하고 있었어요."},{"n":5,"t":"베드로가 예수님께 \\"랍비여, 우리가 여기 있는 게 좋겠어요. 초막 셋을 짓겠어요. 하나는 주님 것, 하나는 모세 것, 하나는 엘리야 것이요\\" 하고 말했어요."},{"n":6,"t":"이는 그들이 매우 두려워했기 때문에 무슨 말을 해야 할지 몰랐기 때문이에요."},{"n":7,"t":"구름이 와서 그들을 덮고 구름 속에서 소리가 들렸어요. \\"이는 내 사랑하는 아들이다. 너희는 그의 말을 들어라.\\""},{"n":8,"t":"갑자기 둘러보니 그들 자신과 예수님 외에는 아무도 보이지 않았어요."},{"n":9,"t":"산에서 내려올 때 예수님이 그들에게 사람의 아들이 죽은 자 가운데서 살아나기 전까지 본 것을 아무에게도 말하지 말라고 엄히 명하셨어요."},{"n":10,"t":"그들이 그 말씀을 기억했지만 죽은 자 가운데서 살아난다는 말씀이 무슨 뜻인지 서로 물었어요."},{"n":11,"t":"그들이 예수님께 \\"왜 율법 학자들은 엘리야가 먼저 와야 한다고 해요?\\" 하고 물었어요."},{"n":12,"t":"예수님이 \\"엘리야가 먼저 와서 모든 것을 회복할 거야. 그리고 사람의 아들에 대해 어떻게 기록되었니? 많은 고난을 받고 멸시당해야 한다고 했어.\\""},{"n":13,"t":"\\"그러나 내가 너희에게 말한다. 엘리야는 이미 왔고 사람들이 자기들 원하는 대로 그에게 행했어. 그에 대해 기록된 대로 됐다\\" 하셨어요."},{"n":14,"t":"예수님이 제자들에게 와서 보시니 큰 무리가 그들을 둘러싸고 율법 학자들이 그들과 다투고 있었어요."},{"n":15,"t":"모든 무리가 예수님을 보고 깜짝 놀라며 달려와서 인사했어요."},{"n":16,"t":"예수님이 \\"너희가 무엇을 따지고 있니?\\" 하고 물으셨어요."},{"n":17,"t":"무리 중 한 사람이 \\"선생님, 말 못하게 하는 영이 들린 제 아들을 데려왔어요.\\""},{"n":18,"t":"\\"어디서나 그 영이 그를 잡으면 땅에 던지고, 그가 거품을 흘리고 이를 갈고 굳어져요. 제자들에게 쫓아 달라고 했지만 못 했어요.\\""},{"n":19,"t":"예수님이 \\"믿음 없는 세대여, 내가 언제까지 너희와 함께 있을까? 언제까지 너희를 참을까? 그를 내게 데려와\\" 하셨어요."},{"n":20,"t":"그들이 그를 데려왔어요. 영이 예수님을 보자 곧 아이를 심하게 경련시켜 땅에 넘어져 거품을 흘리며 구르게 했어요."},{"n":21,"t":"예수님이 \\"이 일이 그에게 일어난 지 얼마나 됐니?\\" 하고 아버지에게 물으시니 \\"어릴 때부터요.\\""},{"n":22,"t":"\\"여러 번 그를 죽이려고 불과 물에 던졌어요. 그러나 무엇이든 하실 수 있으면 우리를 불쌍히 여겨 도와주세요\\" 하고 답했어요."},{"n":23,"t":"예수님이 \\"\'할 수 있으면\'이라니? 믿는 사람에게는 모든 일이 가능하다\\" 하셨어요."},{"n":24,"t":"곧 그 아이의 아버지가 외쳐 \\"내가 믿어요! 내 믿음 없음을 도와주세요!\\" 하고 말했어요."},{"n":25,"t":"예수님이 무리가 달려 모이는 것을 보고 더러운 영을 꾸짖으셨어요. \\"말 못하고 듣지 못하는 영아, 내가 너에게 명한다. 그에게서 나오고 다시는 들어가지 마라.\\""},{"n":26,"t":"영이 외치고 심히 경련을 일으키게 한 후에 나갔어요. 아이가 죽은 사람처럼 되어 많은 사람이 \\"죽었다\\" 하고 말했어요."},{"n":27,"t":"예수님이 그의 손을 잡아 일으키시니 그가 일어났어요."},{"n":28,"t":"예수님이 집에 들어가시자 제자들이 따로 \\"왜 우리는 그것을 쫓아내지 못했어요?\\" 하고 물었어요."},{"n":29,"t":"예수님이 \\"이런 종류는 기도가 아니면 다른 것으로 쫓을 수 없어\\" 하셨어요."},{"n":30,"t":"거기서 떠나 갈릴리를 지나가실 때 예수님은 아무도 알지 못하기를 원하셨어요."},{"n":31,"t":"이는 제자들에게 가르치며 \\"사람의 아들이 사람들의 손에 넘겨질 거고 그들이 죽일 거야. 죽은 지 사흘 만에 살아날 거야\\" 하셨기 때문이에요."},{"n":32,"t":"제자들은 그 말씀을 깨닫지 못했고 묻기를 두려워했어요."},{"n":33,"t":"예수님이 가버나움에 가셔서 집에 계실 때 제자들에게 \\"길에서 무엇을 의논했니?\\" 하고 물으셨어요."},{"n":34,"t":"그들은 잠잠했어요. 길에서 누가 큰지 서로 다투었기 때문이에요."},{"n":35,"t":"예수님이 앉으셔서 열둘을 부르시고 \\"누구든지 첫째가 되려면 모든 사람의 끝이 되고 모두를 섬기는 사람이 되어야 한다\\" 하셨어요."},{"n":36,"t":"어린아이 하나를 데려다가 그들 가운데 세우시고 안으시며 말씀하셨어요."},{"n":37,"t":"\\"누구든지 내 이름으로 이런 어린아이 하나를 영접하는 사람은 나를 영접하는 거야. 누구든지 나를 영접하면 나를 영접하는 게 아니라 나를 보내신 분을 영접하는 거야.\\""},{"n":38,"t":"요한이 \\"선생님, 어떤 사람이 주님의 이름으로 귀신을 쫓아내는 것을 봤어요. 우리를 따르지 않기에 막았어요\\" 하고 말했어요."},{"n":39,"t":"예수님이 \\"막지 마라. 내 이름으로 능력을 행하고 곧 나를 비난할 사람은 없어.\\""},{"n":40,"t":"\\"우리를 반대하지 않는 사람은 우리를 위하는 사람이야.\\""},{"n":41,"t":"\\"누구든지 너희가 그리스도의 사람이라는 이유로 시원한 물 한 잔을 너희에게 주면 진정으로 말한다. 그 사람은 결코 자기 상을 잃지 않을 거야.\\""},{"n":42,"t":"\\"누구든지 나를 믿는 이 작은 사람 중 하나를 걸려 넘어지게 하면 큰 맷돌을 그의 목에 매고 바다에 던져지는 게 나아.\\""},{"n":43,"t":"\\"네 손이 너를 죄짓게 하거든 잘라 버려. 두 손을 가지고 지옥, 꺼지지 않는 불에 들어가는 것보다 한 손을 가지고 생명에 들어가는 게 나아.\\""},{"n":44,"t":"\\"거기에는 그들의 구더기도 죽지 않고 불도 꺼지지 않아.\\""},{"n":45,"t":"\\"네 발이 너를 죄짓게 하거든 잘라 버려. 두 발로 지옥에 던져지는 것보다 절름발이로 생명에 들어가는 게 나아.\\""},{"n":46,"t":"\\"거기에는 그들의 구더기도 죽지 않고 불도 꺼지지 않아.\\""},{"n":47,"t":"\\"네 눈이 너를 죄짓게 하거든 빼어 버려. 두 눈으로 지옥에 던져지는 것보다 한 눈으로 하나님 나라에 들어가는 게 나아.\\""},{"n":48,"t":"\\"거기에는 그들의 구더기도 죽지 않고 불도 꺼지지 않아.\\""},{"n":49,"t":"\\"모든 사람이 불로 소금 치듯 다스려질 거야.\\""},{"n":50,"t":"\\"소금은 좋아. 그러나 소금이 짠맛을 잃으면 무엇으로 짜게 만들겠니? 너희 속에 소금을 가지고 서로 화목하라.\\""}]}},{"chapter":10,"title":"부자 청년과 섬김의 길","verses":{"krv":[{"n":1,"t":"예수께서 거기서 떠나 유대 지경과 요단강 건너편으로 가시니 무리가 다시 모여 들거늘 예수께서 다시 전례대로 가르치시더니"},{"n":2,"t":"바리새인들이 예수께 나아와 그를 시험하여 묻되 사람이 아내를 내어버리는 것이 옳으니이까"},{"n":3,"t":"대답하여 가라사대 모세가 어떻게 너희에게 명하였느냐"},{"n":4,"t":"가로되 모세는 이혼 증서를 써주어 내어 버리기를 허락하였나이다"},{"n":5,"t":"예수께서 저희에게 이르시되 너희 마음의 완악함을 인하여 이 명령을 기록하였거니와"},{"n":6,"t":"창조시로부터 저희를 남자와 여자로 만드셨으니"},{"n":7,"t":"이러므로 사람이 그 부모를 떠나서"},{"n":8,"t":"그 둘이 한 몸이 될지니라 이러한즉 이제 둘이 아니요 한 몸이니"},{"n":9,"t":"그러므로 하나님이 짝지어 주신 것을 사람이 나누지 못할찌니라 하시더라"},{"n":10,"t":"집에서 제자들이 다시 이일을 묻자온대"},{"n":11,"t":"이르시되 누구든지 그 아내를 내어버리고 다른데 장가 드는 자는 본처에게 간음을 행함이요"},{"n":12,"t":"또 아내가 남편을 버리고 다른데로 시집 가면 간음을 행함이니라"},{"n":13,"t":"사람들이 예수의 만져 주심을 바라고 어린 아이들을 데리고 오매 제자들이 꾸짖거늘"},{"n":14,"t":"예수께서 보시고 분히 여겨 이르시되 어린 아이들의 내게 오는 것을 용납하고 금하지 말라 하나님의 나라가 이런 자의 것이니라"},{"n":15,"t":"내가 진실로 너희에게 이르노니 누구든지 하나님의 나라를 어린 아이와 같이 받들지 않는 자는 결단코 들어가지 못하리라 하시고"},{"n":16,"t":"그 어린 아이들을 안고 저희 위에 안수하시고 축복하시니라"},{"n":17,"t":"예수께서 길에 나가실쌔 한 사람이 달려와서 꿇어 앉아 묻자 오되 선한 선생님이여 내가 무엇을 하여야 영생을 얻으리이까"},{"n":18,"t":"예수께서 이르시되 네가 어찌하여 나를 선하다 일컫느냐 하나님 한분 외에는 선한 이가 없느니라"},{"n":19,"t":"네가 계명을 아나니 살인하지 말라 간음하지 말라 도적질 하지말라 거짓증거하지 말라 속여 취하지 말라 네 부모를 공경하라 하였느니라"},{"n":20,"t":"여짜오되 선생님이여 이것은 내가 어려서부터 다 지키었나이다"},{"n":21,"t":"예수께서 그를 보시고 사랑하라 가라사대 네게 오히려 한 가지 부족한 것이 있으니 가서 네 있는 것을 다 팔아 가난한 자들을 주라 그리하면 하늘에서 보화가 네게 있으리라 그리고 와서 나를 좇으라 하시니"},{"n":22,"t":"그 사람은 재물이 많은고로 이 말씀을 인하여 슬픈 기색을 띠고 근심하며 가니라"},{"n":23,"t":"예수께서 둘러 보시고 제자들에게 이르시되 재물이 있는 자는 하나님의 나라에 들어가기가 심히 어렵도다 하시니"},{"n":24,"t":"제자들이 그 말씀에 놀라는지라 예수께서 다시 대답하여 가라사대 얘들아 하나님의 나라에 들어가기가 어떻게 어려운지"},{"n":25,"t":"약대가 바늘귀로 나가는 것이 부자가 하나님의 나라에 들어가는 것보다 쉬우니라 하신대"},{"n":26,"t":"제자들이 심히 놀라 서로 말하되 그런즉 누가 구원을 얻을 수 있는가 하니"},{"n":27,"t":"예수께서 저희를 보시며 가라사대 사람으로는 할 수 없으되 하나님으로는 그렇지 아니하니 하나님으로서는 다 하실 수 있느니라"},{"n":28,"t":"베드로가 여짜와 가로되 보소서 우리가 모든 것을 버리고 주를 좇았나이다"},{"n":29,"t":"예수께서 가라사대 내가 진실로 너희에게 이르노니 나와 및 복음을 위하여 집이나 형제나 자매나 어미나 아비나 자식이나 전토를 버린 자는"},{"n":30,"t":"금세에 있어 집과 형제와 자매와 모친과 자식과 전토를 백배나 받되 핍박을 겸하여 받고 내세에 영생을 받지 못할 자가 없느니라"},{"n":31,"t":"그러나 먼저 된 자로서 나중 되고 나중 된 자로서 먼저 될 자가 많으니라"},{"n":32,"t":"예루살렘으로 올라가는 길에 예수께서 제자들 앞에 서서 가시는데 저희가 놀라고 좇는 자들은 두려워하더라 이에 다시 열 두 제자를 데리시고 자기의 당할 일을 일러 가라사대"},{"n":33,"t":"보라 우리가 예루살렘에 올라가노니 인자가 대제사장들과 서기관들에게 넘기우매 저희가 죽이기로 결안하고 이방인들에게 넘겨주겠고"},{"n":34,"t":"그들은 능욕하며 침 뱉으며 채찍질하고 죽일 것이니 저는 삼일만에 살아나리라 하시니라"},{"n":35,"t":"세베대의 아들 야고보와 요한이 주께 나아와 여짜오되 선생님이 여 무엇이든지 우리의 구하는 바를 우리에게 하여주시기를 원하옵나이다"},{"n":36,"t":"이르시되 너희에게 무엇을 하여주기를 원하느냐"},{"n":37,"t":"여짜오되 주의 영광 중에서 우리를 하나는 주의 우편에 하나는 좌편에 앉게 하여 주옵소서"},{"n":38,"t":"예수께서 가라사대 너희 구하는 것을 너희가 알지 못하는도다 너희가 나의 마시는 잔을 마시며 나의 받는 세례를 받을 수 있느냐"},{"n":39,"t":"저희가 말하되 할 수 있나이다 예수께서 이르시되 너희가 나의 마시는 잔을 마시며 나의 받는 세례를 받으려니와"},{"n":40,"t":"내 좌우편에 앉는 것은 나의 줄 것이 아니라 누구를 위하여 예비되었든지 그들이 얻을 것이니라"},{"n":41,"t":"열 제자가 듣고 야고보와 요한에 대하여 분히 여기거늘"},{"n":42,"t":"예수께서 불러다가 이르시되 이방인의 소위 집권자들이 저희를 임의로 주관하고 그 대인들이 저희에게 권세를 부리는 줄을 너희가 알거니와"},{"n":43,"t":"너희 중에는 그렇지 아니하니 너희 중에 누구든지 크고자 하는 자는 너희를 섬기는 자가 되고"},{"n":44,"t":"너희 중에 누구든지 으뜸이 되고자 하는 자는 모든 사람의 종이 되어야 하리라"},{"n":45,"t":"인자의 온 것은 섬김을 받으려 함이 아니라 도리어 섬기려 하고 자기 목숨을 많은 사람의 대속물로 주려 함이니라"},{"n":46,"t":"저희가 여리고에 이르렀더니 예수께서 제자들과 허다한 무리와 함께 여리고에서 나가실 때에 디매오의 아들인 소경 거지 바디매오가 길 가에 앉았다가"},{"n":47,"t":"나사렛 예수시란 말을 듣고 소리질러 가로되 다윗의 자손 예수여 나를 불쌍히 여기소서 하거늘"},{"n":48,"t":"많은 사람이 꾸짖어 잠잠하라 하되 그가 더욱 심히 소리질러 가로되 다윗의 자손이여 나를 불쌍히 여기소서 하는지라"},{"n":49,"t":"예수께서 머물러 서서 저를 부르라 하시니 저희가 그 소경을 부르며 이르되 안심하고 일어나라 너를 부르신다 하매"},{"n":50,"t":"소경이 겉옷을 내어버리고 뛰어 일어나 예수께 나아오거늘"},{"n":51,"t":"예수께서 일러 가라사대 네게 무엇을 하여주기를 원하느냐 소경이 가로되 선생님이여 보기를 원하나이다"},{"n":52,"t":"예수께서 이르시되 가라 네 믿음이 너를 구원하였느니라 하시니 저가 곧 보게 되어 예수를 길에서 좇으니라"}],"kids":[{"n":1,"t":"예수님이 거기서 일어나 유대 지역과 요단강 건너편으로 가셨어요. 무리가 다시 그분께 모였고 예수님은 늘 하시던 대로 그들을 가르치셨어요."},{"n":2,"t":"바리새인들이 와서 시험하려고 \\"사람이 아내를 버리는 것이 합법인가요?\\" 하고 물었어요."},{"n":3,"t":"예수님이 \\"모세가 너희에게 어떻게 명령했니?\\" 하셨어요."},{"n":4,"t":"그들이 \\"모세는 이혼증서를 쓰고 버리는 것을 허락했어요\\" 하고 답했어요."},{"n":5,"t":"예수님이 \\"너희 마음이 굳어서 모세가 이 계명을 기록한 거야.\\""},{"n":6,"t":"\\"창조 처음에 하나님이 그들을 남자와 여자로 만드셨어.\\""},{"n":7,"t":"\\"이런 이유로 사람이 부모를 떠나 그의 아내와 합하여,\\""},{"n":8,"t":"\\"둘이 한 몸이 될 거야. 그래서 둘이 아니고 한 몸이야.\\""},{"n":9,"t":"\\"그러므로 하나님이 짝지어 주신 것을 사람이 갈라놓지 마라\\" 하셨어요."},{"n":10,"t":"집에서 제자들이 그 일에 대해 다시 물었어요."},{"n":11,"t":"예수님이 \\"누구든 자기 아내를 버리고 다른 여자와 결혼하면 아내에게 간음하는 것이고,\\""},{"n":12,"t":"\\"아내가 남편을 버리고 다른 남자와 결혼해도 간음하는 거야\\" 하셨어요."},{"n":13,"t":"사람들이 예수님이 만져 주시도록 어린아이들을 데려왔는데 제자들이 그들을 꾸짖었어요."},{"n":14,"t":"예수님이 보시고 화내시며 \\"어린아이들을 내게 오게 두고 막지 마라. 하나님 나라는 이런 사람들의 것이야.\\""},{"n":15,"t":"\\"진정으로 말한다. 누구든지 하나님의 나라를 어린아이처럼 받지 않으면 결코 그곳에 들어가지 못해\\" 하셨어요."},{"n":16,"t":"예수님이 어린아이들을 안고 손을 얹어 축복하셨어요."},{"n":17,"t":"예수님이 길에 나가실 때 한 사람이 달려와 무릎을 꿇고 \\"선한 선생님, 영생을 얻으려면 무엇을 해야 해요?\\" 하고 물었어요."},{"n":18,"t":"예수님이 \\"왜 나를 선하다 하니? 선한 분은 한 분, 곧 하나님 외에 없어.\\""},{"n":19,"t":"\\"계명을 알지. 살인하지 말라, 간음하지 말라, 도둑질하지 말라, 거짓 증언하지 말라, 속이지 말라, 네 부모를 공경하라\\" 하셨어요."},{"n":20,"t":"그가 \\"선생님, 어릴 때부터 이 모든 것을 다 지켰어요\\" 하고 답했어요."},{"n":21,"t":"예수님이 그를 사랑스럽게 보시고 \\"네게 한 가지가 부족하다. 가서 네가 가진 것을 다 팔아 가난한 사람에게 주라. 하늘에 보물이 있을 거야. 그리고 와서 나를 따르라\\" 하셨어요."},{"n":22,"t":"그 말씀에 그가 슬퍼하며 떠났어요. 재산이 많았기 때문이에요."},{"n":23,"t":"예수님이 둘러보시고 제자들에게 \\"재물이 있는 사람이 하나님의 나라에 들어가기가 얼마나 어려운지!\\" 하셨어요."},{"n":24,"t":"제자들이 그 말씀에 놀라니, 예수님이 다시 \\"얘들아, 하나님의 나라에 들어가기가 얼마나 어려운지!\\""},{"n":25,"t":"\\"부자가 하나님의 나라에 들어가는 것보다 낙타가 바늘귀로 가는 것이 더 쉬워\\" 하셨어요."},{"n":26,"t":"제자들이 더 놀라며 서로 \\"그러면 누가 구원받을 수 있어?\\" 하고 말했어요."},{"n":27,"t":"예수님이 그들을 보시고 \\"사람으로는 할 수 없지만 하나님께는 그렇지 않아. 하나님께는 모든 것이 가능해\\" 하셨어요."},{"n":28,"t":"베드로가 \\"보세요, 우리는 모든 것을 버리고 주님을 따랐어요\\" 하고 말하기 시작했어요."},{"n":29,"t":"예수님이 \\"진정으로 말한다. 누구든지 나와 복음을 위해 집이나 형제나 자매나 어머니나 아버지나 자녀나 토지를 버린 사람은,\\""},{"n":30,"t":"\\"이 세상에서 박해와 함께 집과 형제와 자매와 어머니와 자녀와 토지를 백 배나 받고, 오는 세상에서는 영생을 받지 못할 사람이 없어.\\""},{"n":31,"t":"\\"먼저 된 사람으로서 나중 되고, 나중 된 사람으로서 먼저 될 사람이 많을 거야\\" 하셨어요."},{"n":32,"t":"그들이 예루살렘으로 올라가는 길에 있었어요. 예수님이 앞서가시니 제자들은 놀라고 따르는 사람들은 두려워했어요. 예수님이 다시 열두 제자를 데리고 자기에게 일어날 일을 말씀하셨어요."},{"n":33,"t":"\\"보라, 우리가 예루살렘에 올라간다. 사람의 아들이 대제사장과 율법 학자들에게 넘겨질 거야. 그들이 그를 사형에 처하고 이방인에게 넘길 거야.\\""},{"n":34,"t":"\\"그들이 그를 조롱하고 침 뱉고 채찍질하고 죽일 거야. 그러나 그가 사흘 후에 살아날 거야.\\""},{"n":35,"t":"세베대의 두 아들 야고보와 요한이 예수님께 와서 \\"선생님, 우리가 청하는 것은 무엇이든 해 주시기를 원해요\\" 하고 말했어요."},{"n":36,"t":"예수님이 \\"무엇을 해 주기를 원하니?\\" 하셨어요."},{"n":37,"t":"그들이 \\"주님의 영광 가운데서 하나는 주님의 오른쪽에, 하나는 왼쪽에 앉게 해 주세요\\" 하고 답했어요."},{"n":38,"t":"예수님이 \\"너희가 무엇을 구하는지 모르는구나. 내가 마시려는 잔을 마시며 내가 받는 세례를 받을 수 있겠니?\\" 하셨어요."},{"n":39,"t":"그들이 \\"할 수 있어요\\" 하고 답하니, 예수님이 \\"내가 마시려는 잔을 너희가 마시고 내가 받는 세례를 받을 거다.\\""},{"n":40,"t":"\\"그러나 내 오른쪽과 왼쪽에 앉는 것은 내가 줄 게 아니라 준비된 사람들의 것이야\\" 하셨어요."},{"n":41,"t":"열 제자가 듣고 야고보와 요한에게 화가 났어요."},{"n":42,"t":"예수님이 그들을 부르시고 \\"이방인의 통치자라 하는 사람들이 그들을 다스리고 큰 사람들이 권세를 부리는 줄 너희가 알지.\\""},{"n":43,"t":"\\"너희 가운데서는 그렇지 않아. 누구든지 너희 중에 크게 되려는 사람은 너희의 종이 되고,\\""},{"n":44,"t":"\\"누구든지 너희 중에 첫째가 되려는 사람은 모든 사람의 종이 되어야 해.\\""},{"n":45,"t":"\\"사람의 아들도 섬김을 받으러 온 게 아니라 섬기러 왔고 자기 목숨을 많은 사람의 대속물로 주려 왔어\\" 하셨어요."},{"n":46,"t":"그들이 여리고에 갔어요. 예수님이 제자들과 큰 무리와 함께 여리고에서 나오실 때, 디매오의 아들 맹인 거지 바디매오가 길가에 앉아 있었어요."},{"n":47,"t":"나사렛 예수라는 말을 듣고 외치기 시작했어요. \\"다윗의 자손 예수여, 저를 불쌍히 여겨 주세요!\\""},{"n":48,"t":"많은 사람이 그에게 잠잠하라고 꾸짖었지만 그가 더 크게 \\"다윗의 자손이여, 저를 불쌍히 여겨 주세요!\\" 하고 외쳤어요."},{"n":49,"t":"예수님이 멈춰 서서 \\"그를 부르라\\" 하셨어요. 사람들이 맹인에게 \\"기뻐해. 일어나. 너를 부르신다\\" 하고 말했어요."},{"n":50,"t":"그가 겉옷을 던지고 일어나 예수님께 갔어요."},{"n":51,"t":"예수님이 \\"내가 너에게 무엇을 해 주기를 원하니?\\" 하시니 맹인이 \\"랍오니, 보기를 원해요\\" 하고 답했어요."},{"n":52,"t":"예수님이 \\"가라. 네 믿음이 너를 구원했다\\" 하셨어요. 그가 곧 보고 예수님을 길에서 따라갔어요."}]}},{"chapter":11,"title":"예루살렘 입성과 성전 청결","verses":{"krv":[{"n":1,"t":"저희가 예루살렘에 가까이 와서 감람산 벳바게와 베다니에 이르렀을 때에 예수께서 제자 중 둘을 보내시며"},{"n":2,"t":"이르시되 너희 맞은편 마을로 가라 그리로 들어가면 곧 아직 아무 사람도 타 보지 않은 나귀 새끼의 매여 있는 것을 보리니 풀어 끌고 오너라"},{"n":3,"t":"만일 누가 너희에게 왜 이리 하느냐 묻거든 주가 쓰시겠다하라 그리하면 즉시 이리로 보내리라 하시니"},{"n":4,"t":"제자들이 가서 본즉 나귀 새끼가 문앞 거리에 매여 있는지라 그것을 푸니"},{"n":5,"t":"거기 섰는 사람 중 어떤이들이 가로되 나귀 새끼를 풀어 무엇하 려느냐 하매"},{"n":6,"t":"제자들이 예수의 이르신대로 말한대 이에 허락하는지라"},{"n":7,"t":"나귀 새끼를 예수께로 끌고 와서 자기들의 겉옷을 그 위에 걸쳐 두매 예수께서 타시니"},{"n":8,"t":"많은 사람은 자기 겉옷과 다른이들은 밭에서 벤 나무가지를 길에 펴며"},{"n":9,"t":"앞에서 가고 뒤에서 따르는 자들이 소리지르되 호산나 찬송하리로다 주의 이름으로 오시는이여"},{"n":10,"t":"찬송하리로다 오는 우리 조상 다윗의 나라여 가장 높은 곳에서 호산나 하더라"},{"n":11,"t":"예수께서 예루살렘에 이르러 성전에 들어가사 모든 것을 둘러 보시고 때가 이미 저물매 열 두 제자를 데리시고 베다니에 나가시다"},{"n":12,"t":"이튿날 저희가 베다니에서 나왔을 때에 예수께서 시장하신지라"},{"n":13,"t":"멀리서 잎사귀 있는 한 무화과나무를 보시고 혹 그 나무에 무엇이 있을까 하여 가셨더니 가서 보신즉 잎사귀 외에 아무 것도 없더라 이는 무화과의 때가 아님이라"},{"n":14,"t":"예수께서 나무에게 일러 가라사대 이제부터 영원토록 사람이 네게서 열매를 따 먹지 못하리라 하시니 제자들이 이를 듣더라"},{"n":15,"t":"저희가 예루살렘에 들어가니라 예수께서 성전에 들어가사 성전 안에서 매매하는 자들을 내어 쫓으시며 돈 바꾸는 자들의 상과 비둘기 파는 자들의 의자를 둘러 엎으시며"},{"n":16,"t":"아무나 기구를 가지고 성전 안으로 지나다님을 허치 아니하시고"},{"n":17,"t":"이에 가르쳐 이르시되 기록된바 내 집은 만민의 기도하는 집이라 칭함을 받으리라고 하지 아니하였느냐 너희는 강도의 굴혈을 만들었도다 하시매"},{"n":18,"t":"대제사장들과 서기관들이 듣고 예수를 어떻게 멸할까 하고 꾀하니 이는 무리가 다 그의 교훈을 기이히 여기므로 그를 두려워함일러라"},{"n":19,"t":"매양 저물매 저희가 성밖으로 나가더라"},{"n":20,"t":"저희가 아침에 지나갈 때에 무화과나무가 뿌리로부터 마른 것을 보고"},{"n":21,"t":"베드로가 생각이 나서 여짜오되 랍비여 보소서 저주하신 무화과 나무가 말랐나이다"},{"n":22,"t":"예수께서 대답하여 저희에게 이르시되 하나님을 믿으라"},{"n":23,"t":"내가 진실로 너희에게 이르노니 누구든지 이 산더러 들리어 바다에 던지우라 하며 그 말하는 것이 이룰줄 믿고 마음에 의심치 아니하면 그대로 되리라"},{"n":24,"t":"그러므로 내가 너희에게 말하노니 무엇이든지 기도하고 구하는 것은 받은 줄로 믿으라 그리하면 너희에게 그대로 되리라"},{"n":25,"t":"서서 기도할 때에 아무에게나 혐의가 있거든 용서하라 그리하여야 하늘에 계신 너희 아버지도 너희 허물을 사하여 주시리라 하셨더라"},{"n":26,"t":"(없 음)"},{"n":27,"t":"저희가 다시 예루살렘에 들어가니라 예수께서 성전에서 걸어다니실 때에 대제사장들과 서기관들과 장로들이 나아와"},{"n":28,"t":"가로되 무슨 권세로 이런 일을 하느뇨 누가 이런 일 할 이 권세를 주었느뇨"},{"n":29,"t":"예수께서 가라사대 나도 한 말을 너희에게 물으리니 대답하라 그리하면 나도 무슨 권세로 이런 일을 하는지 이르리라"},{"n":30,"t":"요한의 세례가 하늘로서냐 사람에게로서냐 내게 대답하라"},{"n":31,"t":"저희가 서로 의논하여 가로되 만일 하늘로서라 하면 어찌하여 저를 믿지 아니하였느냐 할 것이니"},{"n":32,"t":"그러면 사람에게로서라 할까 하였으나 모든 사람이 요한을 참 선지자로 여기므로 저희가 백성을 무서워하는지라"},{"n":33,"t":"이에 예수께 대답하여 가로되 우리가 알지 못하노라 하니 예수께서 가라사대 나도 무슨 권세로 이런 일을 하는지 너희에게 이르지 아니하리라 하시니라"}],"kids":[{"n":1,"t":"그들이 예루살렘에 가까이 와서 감람산 곁 벳바게와 베다니에 이르렀을 때, 예수님이 제자 둘을 보내며,"},{"n":2,"t":"\\"맞은편 동네로 가라. 들어가면 곧 아무도 탄 적이 없는 나귀 새끼가 매여 있을 거야. 풀어서 끌고 와.\\""},{"n":3,"t":"\\"누가 \'왜 이 일을 하니?\' 하거든 \'주께서 쓰십니다. 곧 다시 보내실 거예요\' 하고 말해라\\" 하셨어요."},{"n":4,"t":"그들이 가서 문 밖 길에 매인 나귀 새끼를 발견하고 풀었어요."},{"n":5,"t":"거기 서 있던 사람들이 \\"왜 나귀 새끼를 푸니?\\" 하고 물었어요."},{"n":6,"t":"제자들이 예수님이 말씀하신 대로 답하니 그들이 허락했어요."},{"n":7,"t":"그들이 나귀 새끼를 예수님께 끌고 와서 자기 옷을 그 위에 펴니 예수님이 타셨어요."},{"n":8,"t":"많은 사람이 자기 옷을 길에 폈고, 다른 사람들은 들에서 가지를 베어 폈어요."},{"n":9,"t":"앞서 가는 사람들과 뒤따르는 사람들이 외쳤어요. \\"호산나! 주의 이름으로 오시는 분에게 복이 있다!\\""},{"n":10,"t":"\\"우리 조상 다윗의 오는 나라에 복이 있다! 가장 높은 곳에서 호산나!\\""},{"n":11,"t":"예수님이 예루살렘에 들어가 성전에 들어가셔서 모든 것을 둘러보시고, 시간이 늦었기에 열두 제자와 함께 베다니로 가셨어요."},{"n":12,"t":"이튿날 그들이 베다니에서 나갈 때 예수님이 배가 고프셨어요."},{"n":13,"t":"멀리서 잎이 무성한 무화과나무를 보시고 혹시 열매가 있을까 하고 가셨지만 잎사귀 외에 아무것도 없었어요. 무화과 철이 아니었거든요."},{"n":14,"t":"예수님이 그것에게 \\"이제부터 영원히 너에게서 아무도 열매를 먹지 못할 거다\\" 하셨어요. 제자들이 들었어요."},{"n":15,"t":"그들이 예루살렘에 갔어요. 예수님이 성전에 들어가 거기서 사고파는 사람들을 내쫓고, 돈 바꾸는 사람들의 상과 비둘기 파는 사람들의 의자를 둘러엎으셨어요."},{"n":16,"t":"그리고 누구든 물건을 가지고 성전을 지나가지 못하게 하셨어요."},{"n":17,"t":"예수님이 가르치며 \\"기록되었다. \'내 집은 모든 민족의 기도하는 집이라 불릴 거다.\' 그런데 너희가 그것을 강도의 굴로 만들었구나\\" 하셨어요."},{"n":18,"t":"대제사장과 율법 학자들이 듣고 어떻게 그를 멸할까 의논했어요. 그들이 예수님을 두려워한 것은 온 무리가 그분의 가르침에 놀랐기 때문이에요."},{"n":19,"t":"저녁이 되자 예수님이 도시 밖으로 나가셨어요."},{"n":20,"t":"아침에 지나가다가 무화과나무가 뿌리부터 마른 것을 보았어요."},{"n":21,"t":"베드로가 기억하고 \\"랍비여, 보세요. 저주하신 무화과나무가 말랐어요\\" 하고 말했어요."},{"n":22,"t":"예수님이 \\"하나님을 믿어라.\\""},{"n":23,"t":"\\"진정으로 말한다. 누구든지 이 산에게 \'들려서 바다에 던져져라\' 하고 마음에 의심하지 않고 말한 대로 될 줄 믿으면 그렇게 될 거야.\\""},{"n":24,"t":"\\"그러므로 내가 너희에게 말한다. 너희가 기도하며 구하는 것은 무엇이든 받은 줄로 믿으면 너희에게 될 거야.\\""},{"n":25,"t":"\\"너희가 서서 기도할 때 누구를 거슬러 무엇이 있거든 용서해. 하늘에 계신 너희 아버지께서도 너희 잘못을 용서해 주실 거야.\\""},{"n":26,"t":"\\"너희가 용서하지 않으면 하늘에 계신 너희 아버지도 너희 잘못을 용서하지 않으실 거야.\\""},{"n":27,"t":"그들이 다시 예루살렘에 갔어요. 예수님이 성전에 다니실 때 대제사장과 율법 학자와 장로들이 와서,"},{"n":28,"t":"\\"무슨 권세로 이런 일을 하나요? 누가 이런 권세를 주었나요?\\" 하고 물었어요."},{"n":29,"t":"예수님이 \\"나도 한 가지 물을 게 있어. 너희가 답하면 내가 무슨 권세로 이런 일을 하는지 말해 줄게.\\""},{"n":30,"t":"\\"요한의 세례가 하늘로부터냐, 사람에게서냐? 내게 답해 봐\\" 하셨어요."},{"n":31,"t":"그들이 서로 의논하며 \\"하늘로부터라 하면 \'왜 그를 믿지 않았느냐?\' 할 거야.\\""},{"n":32,"t":"\\"\'사람에게서다\' 하기에는…\\" 그들이 무리를 두려워했어요. 모두 요한을 정말 예언자로 여겼기 때문이에요."},{"n":33,"t":"그들이 \\"모르겠어요\\" 하고 답하니 예수님이 \\"나도 무슨 권세로 이런 일을 하는지 너희에게 말하지 않겠다\\" 하셨어요."}]}},{"chapter":12,"title":"큰 계명과 과부의 헌금","verses":{"krv":[{"n":1,"t":"예수께서 비유로 저희에게 말씀하시되 한 사람이 포도원을 만들고 산울로 두르고 즙 짜는 구유 자리를 파고 망대를 짓고 농부들에게 세로 주고 타국에 갔더니"},{"n":2,"t":"때가 이르매 농부들에게 포도원 소출 얼마를 받으려고 한 종을 보내니"},{"n":3,"t":"저희가 종을 잡아 심히 때리고 거저 보내었거늘"},{"n":4,"t":"다시 다른 종을 보내니 그의 머리에 상처를 내고 능욕하였거늘"},{"n":5,"t":"또 다른 종을 보내니 저희가 그를 죽이고 또 그외 많은 종들도 혹은 때리고 혹은 죽인지라"},{"n":6,"t":"오히려 한 사람이 있으니 곧 그의 사랑하는 아들이라 최후로 이를 보내며 가로되 내 아들은 공경하리라 하였더니"},{"n":7,"t":"저 농부들이 서로 말하되 이는 상속자니 자 죽이자 그러면 그 유업이 우리 것이 되리라 하고"},{"n":8,"t":"이에 잡아 죽여 포도원 밖에 내어던졌느니라"},{"n":9,"t":"포도원 주인이 어떻게 하겠느뇨 와서 그 농부들을 진멸하고 포도원을 다른 사람들에게 주리라"},{"n":10,"t":"너희가 성경에 건축자들의 버린 돌이 모퉁이의 머릿돌이 되었나니"},{"n":11,"t":"이것은 주로 말미암아 된 것이요 우리 눈에 기이하도다 함을 읽어 보지도 못하였느냐 하시니라"},{"n":12,"t":"저희가 예수의 이 비유는 자기들을 가리켜 말씀하심인줄 알고 잡고자 하되 무리를 두려워하여 예수를 버려두고 가니라"},{"n":13,"t":"저희가 예수의 말씀을 책잡으려 하여 바리새인과 헤롯당 중에서 사람을 보내매"},{"n":14,"t":"와서 가로되 선생님이여 우리가 아노니 당신은 참되시고 아무라도 꺼리는 일이 없으시니 이는 사람을 외모로 보지 않고 오직 참으로써 하나님의 도를 가르치심이니이다 가이사에게 세를 바치는 것이 가하니이까 불가하니이까"},{"n":15,"t":"우리가 바치리이까 말리이까한대 예수께서 그 외식함을 아시고 이르시되 어찌하여 나를 시험하느냐 데나리온 하나를 가져다가 내게 보이라 하시니"},{"n":16,"t":"가져왔거늘 예수께서 가라사대 이 화상과 이 글이 뉘 것이냐 가 로되 가이사의 것이니이다"},{"n":17,"t":"이에 예수께서 가라사대 가이사의 것은 가이사에게 하나님의 것은 하나님께 바치라 하시니 저희가 예수께 대하여 심히 기이히 여기더라"},{"n":18,"t":"부활이 없다 하는 사두개인들이 예수께 와서 물어 가로되"},{"n":19,"t":"선생님이여 모세가 우리에게 써 주기를 사람의 형이 자식이 없이 아내를 두고 죽거든 그 동생이 그 아내를 취하여 형을 위하여 후사를 세울찌니라 하였나이다"},{"n":20,"t":"칠 형제가 있었는데 맏이 아내를 취하였다가 후사가 없이 죽고"},{"n":21,"t":"둘째도 그 여자를 취하였다가 후사가 없이 죽고 세째도 그렇게 하여"},{"n":22,"t":"일곱이 다 후사가 없었고 최후에 여자도 죽었나이다"},{"n":23,"t":"일곱 사람이 다 그를 아내로 취하였으니 부활을 당하여 저희가 살아날 때에 그 중에 뉘 아내가 되리이까"},{"n":24,"t":"예수께서 가라사대 너희가 성경도 하나님의 능력도 알지 못하므로 오해함이 아니냐"},{"n":25,"t":"사람이 죽은 자 가운데서 살아날 때에는 장가도 아니가고 시집도 아니가고 하늘에 있는 천사들과 같으니라"},{"n":26,"t":"죽은 자의 살아난다는 것을 의논할찐대 너희가 모세의 책 중 가시나무떨기에 관한 글에 하나님께서 모세에게 이르시되 나는 아브라함의 하나님이요 이삭의 하나님이요 야곱의 하나님이로라 하신 말씀을 읽어보지 못하였느냐"},{"n":27,"t":"하나님은 죽은 자의 하나님이 아니요 산 자의 하나님이시라 너희가 크게 오해하였도다 하시니라"},{"n":28,"t":"서기관 중 한 사람이 저희의 변론하는 것을 듣고 예수께서 대답 잘하신 줄을 알고 나아와 묻되 모든 계명 중에 첫째가 무엇이니이까"},{"n":29,"t":"예수께서 대답하시되 첫째는 이것이니 이스라엘아 들으라 주 곧 우리 하나님은 유일한 주시라"},{"n":30,"t":"네 마음을 다하고 목숨을 다하고 뜻을 다하고 힘을 다하여 주 너의 하나님을 사랑하라 하신 것이요"},{"n":31,"t":"둘째는 이것이니 네 이웃을 네 몸과 같이 사랑하라 하신 것이라 이에서 더 큰 계명이 없느니라"},{"n":32,"t":"서기관이 가로되 선생님이여 옳소이다 하나님은 한 분이시요 그 외에 다른이가 없다 하신 말씀이 참이니이다"},{"n":33,"t":"또 마음을 다하고 지혜를 다하고 힘을 다하여 하나님을 사랑하는 것과 또 이웃을 제 몸과 같이 사랑하는 것이 전체로 드리는 모든 번제물과 기타 제물보다 나으니이다"},{"n":34,"t":"예수께서 그 지혜 있게 대답함을 보시고 이르시되 네가 하나님의 나라에 멀지 않도다 하시니 그 후에 감히 묻는 자가 없더라"},{"n":35,"t":"예수께서 성전에서 가르치실쌔 대답하여 가라사대 어찌하여 서기관들이 그리스도를 다윗의 자손이라 하느뇨"},{"n":36,"t":"다윗이 성령에 감동하여 친히 말하되 주께서 내 주께 이르시되 내가 네 원수를 네 발 아래 둘 때까지 내 우편에 앉았으라 하셨도다 하였느니라"},{"n":37,"t":"다윗이 그리스도를 주라 하였은즉 어찌 그의 자손이 되겠느냐 하시더라 백성이 즐겁게 듣더라"},{"n":38,"t":"예수께서 가르치실 때에 가라사대 긴 옷을 입고 다니는 것과 시장에서 문안 받는 것과"},{"n":39,"t":"회당의 상좌와 잔치의 상석을 원하는 서기관들을 삼가라"},{"n":40,"t":"저희는 과부의 가산을 삼키며 외식으로 길게 기도하는 자니 그 받는 판결이 더욱 중하리라 하시니라"},{"n":41,"t":"예수께서 연보 궤를 대하여 앉으사 무리의 연보 궤에 돈 넣는 것을 보실쌔 여러 부자는 많이 넣는데"},{"n":42,"t":"한 가난한 과부는 와서 두 렙돈 곧 한 고드란트를 넣는지라"},{"n":43,"t":"예수께서 제자들을 불러다가 이르시되 내가 진실로 너희에게 이르노니 이 가난한 과부는 연보 궤에 넣는 모든 사람보다 많이 넣었도다"},{"n":44,"t":"저희는 다 그 풍족한 중에서 넣었거니와 이 과부는 그 구차한 중에서 자기 모든 소유 곧 생활비 전부를 넣었느니라 하셨더라"}],"kids":[{"n":1,"t":"예수님이 그들에게 비유로 말씀하셨어요. \\"한 사람이 포도원을 만들고 둘레에 울타리를 치고 포도즙 짜는 곳을 파고 망대를 세운 뒤 농부들에게 빌려 주고 먼 곳으로 떠났어.\\""},{"n":2,"t":"\\"때가 되자 농부들에게 포도원 소출을 받으려고 종 하나를 보냈어.\\""},{"n":3,"t":"\\"그들이 종을 잡아 때려서 빈손으로 보냈어.\\""},{"n":4,"t":"\\"또 다른 종을 보냈는데 머리를 부수고 욕보였어.\\""},{"n":5,"t":"\\"또 보낸 종은 죽였고, 많은 다른 종들도 때리거나 죽였어.\\""},{"n":6,"t":"\\"그에게 사랑하는 외아들이 하나 있었어. 마지막에 그를 보내며 \'내 아들은 존경하겠지\' 했어.\\""},{"n":7,"t":"\\"그러나 농부들이 서로 \'이는 상속자다. 죽이고 유산을 차지하자\' 했어.\\""},{"n":8,"t":"\\"그를 잡아 죽이고 포도원 밖으로 던져 버렸어.\\""},{"n":9,"t":"\\"포도원 주인이 어떻게 할까? 와서 그 농부들을 멸하고 포도원을 다른 사람에게 줄 거야.\\""},{"n":10,"t":"\\"성경에서 \'건축자들이 버린 돌이 모퉁이의 머릿돌이 되었다.\\""},{"n":11,"t":"\\"이것은 주께서 하신 일이고 우리 눈에 놀랍다\'라는 글을 너희가 읽지 않았니?\\""},{"n":12,"t":"그들이 예수님이 자기들에 대해 비유로 말한 줄을 알았기에 그를 잡으려 했지만 무리를 두려워해 떠나 가 버렸어요."},{"n":13,"t":"그들이 바리새인과 헤롯파 사람 몇을 예수님께 보내 말로 함정에 빠뜨리게 했어요."},{"n":14,"t":"그들이 와서 \\"선생님, 주께서 진실하시고 누구를 신경 쓰지 않으시며 사람의 외모를 보지 않으시고 진리로 하나님의 길을 가르치시는 줄 안다. 가이사에게 세금 내는 것이 옳은가요, 옳지 않은가요? 우리가 낼까요, 내지 말까요?\\" 하고 물었어요."},{"n":15,"t":"예수님이 그들의 위선을 아시고 \\"왜 나를 시험하니? 데나리온을 가져와 보여 봐\\" 하셨어요."},{"n":16,"t":"그들이 가져오니 예수님이 \\"이 형상과 글자가 누구의 것이니?\\" 하시자 \\"가이사요\\" 하고 답했어요."},{"n":17,"t":"예수님이 \\"가이사의 것은 가이사에게, 하나님의 것은 하나님께 바쳐라\\" 하셨어요. 그들이 놀랐어요."},{"n":18,"t":"부활이 없다고 말하는 사두개인들이 와서 물었어요."},{"n":19,"t":"\\"선생님, 모세가 우리에게 「누가 형이 죽고 그의 아내를 남겨 두면, 자식이 없다면 그의 동생이 그 아내를 데려와 형을 위해 후사를 잇게 하라」 했어요.\\""},{"n":20,"t":"\\"일곱 형제가 있었어요. 첫째가 아내를 두었다가 죽었어요. 자식이 없었어요.\\""},{"n":21,"t":"\\"둘째가 그녀를 데려와 죽었고, 셋째도 그랬어요.\\""},{"n":22,"t":"\\"일곱이 다 자식 없이 죽었어요. 마지막으로 그 여자도 죽었어요.\\""},{"n":23,"t":"\\"부활 때 그들이 살아나면 그녀는 누구의 아내가 되나요? 일곱이 다 그녀를 아내로 두었거든요.\\""},{"n":24,"t":"예수님이 \\"너희가 잘못 알고 있어. 성경도 하나님의 능력도 모르기 때문이야.\\""},{"n":25,"t":"\\"죽은 자 가운데서 살아날 때 결혼하지도 결혼시키지도 않고 하늘에 있는 천사들과 같아.\\""},{"n":26,"t":"\\"죽은 사람의 살아남에 관해 모세의 책 가시덤불 부분에서 하나님이 「나는 아브라함의 하나님, 이삭의 하나님, 야곱의 하나님이다」라고 그에게 말씀하신 것을 너희가 읽지 않았니?\\""},{"n":27,"t":"\\"하나님은 죽은 자의 하나님이 아니라 산 자의 하나님이셔. 너희가 크게 잘못 알고 있어\\" 하셨어요."},{"n":28,"t":"율법 학자 하나가 그들의 논쟁을 듣고 예수님이 잘 답하시는 것을 보고 \\"모든 계명 중에 첫째가 무엇인가요?\\" 하고 물었어요."},{"n":29,"t":"예수님이 \\"첫째는 \'이스라엘아, 들어라. 주 우리 하나님은 한 분이신 주시다.\\""},{"n":30,"t":"\\"네 마음을 다하고 목숨을 다하고 뜻을 다하고 힘을 다해 주 너의 하나님을 사랑하라\'야.\\""},{"n":31,"t":"\\"둘째는 \'네 이웃을 네 몸처럼 사랑하라\'야. 이보다 더 큰 계명이 없어\\" 하셨어요."},{"n":32,"t":"율법 학자가 \\"선생님, 잘 말씀하셨어요. 하나님은 한 분이시고 그 외에 다른 분이 없다는 게 사실이에요.\\""},{"n":33,"t":"\\"마음과 지혜와 힘을 다해 그분을 사랑하는 것과 자기 이웃을 자기 몸처럼 사랑하는 것이 모든 번제와 제사보다 훨씬 더 나아요\\" 하고 말했어요."},{"n":34,"t":"예수님이 그가 지혜롭게 답하는 것을 보시고 \\"네가 하나님 나라에 멀지 않다\\" 하셨어요. 그 후에는 아무도 감히 그분께 묻지 못했어요."},{"n":35,"t":"예수님이 성전에서 가르치며 \\"율법 학자들이 어떻게 그리스도를 다윗의 자손이라 하니?\\""},{"n":36,"t":"\\"다윗이 친히 성령으로 말했어. \'주께서 내 주께 말씀하시되 「내가 네 원수를 네 발 아래 둘 때까지 내 오른쪽에 앉아라」 하셨다.\'\\""},{"n":37,"t":"\\"다윗이 친히 그를 주라 부르는데 어떻게 그가 그의 자손이 되겠니?\\" 큰 무리가 즐겁게 들었어요."},{"n":38,"t":"예수님이 가르치며 \\"율법 학자들을 조심해. 그들은 긴 옷을 입고 다니기를 좋아하고 시장에서 인사받기를,\\""},{"n":39,"t":"\\"회당의 높은 자리와 잔치의 윗자리를 좋아해.\\""},{"n":40,"t":"\\"그들은 과부의 집을 삼키고 길게 기도해서 보여 줘. 그들은 더 큰 심판을 받을 거야\\" 하셨어요."},{"n":41,"t":"예수님이 헌금함 맞은편에 앉아 사람들이 헌금하는 것을 보셨어요. 부자 많은 사람들이 많이 넣었어요."},{"n":42,"t":"한 가난한 과부가 와서 두 렙돈, 곧 한 고드란트를 넣었어요."},{"n":43,"t":"예수님이 제자들을 부르시고 \\"진정으로 말한다. 이 가난한 과부가 헌금함에 넣은 사람들 중 가장 많이 넣었다.\\""},{"n":44,"t":"\\"모두는 풍족한 것에서 넣었지만 이 사람은 자기의 가난한 것에서 자기가 가진 모든 것, 곧 생활비 전부를 넣었어\\" 하셨어요."}]}},{"chapter":13,"title":"마지막 때의 표징","verses":{"krv":[{"n":1,"t":"예수께서 성전에서 나가실 때에 제자 중 하나가 가로되 선생님이여 보소서 이 돌들이 어떠하며 이 건물들이 어떠하니이까"},{"n":2,"t":"예수께서 이르시되 네가 이 큰 건물들을 보느냐 돌 하나도 돌 위에 남지 않고 다 무너뜨려지리라 하시니라"},{"n":3,"t":"예수께서 감람산에서 성전을 마주 대하여 앉으셨을 때에 베드로와 야고보와 요한과 안드레가 종용히 묻자오되"},{"n":4,"t":"우리에게 이르소서 어느 때에 이런 일이 있겠사오며 이 모든 일이 이루려 할 때에 무슨 징조가 있사오리이까"},{"n":5,"t":"예수께서 이르시되 너희가 사람의 미혹을 받지 않도록 주의하라"},{"n":6,"t":"많은 사람이 내 이름으로 와서 이르되 내가 그로라 하여 많은 사람을 미혹케 하리라"},{"n":7,"t":"난리와 난리 소문을 들을 때에 두려워 말라 이런 일이 있어야 하되 끝은 아직 아니니라"},{"n":8,"t":"민족이 민족을 나라가 나라를 대적하여 일어나겠고 처처에 지진이 있으며 기근이 있으리니 이는 재난의 시작이니라"},{"n":9,"t":"너희는 스스로 조심하라 사람들이 너희를 공회에 넘겨주겠고 너희를 회당에서 매질하겠으며 나를 인하여 너희가 관장들과 임금들 앞에 서리니 이는 저희에게 증거되려 함이라"},{"n":10,"t":"또 복음이 먼저 만국에 전파되어야 할 것이니라"},{"n":11,"t":"사람들이 너희를 끌어다가 넘겨줄 때에 무슨 말을 할까 미리 염려치 말고 무엇이든지 그 시에 너희에게 주시는 그 말을 하라 말하는 이는 너희가 아니요 성령이시니라"},{"n":12,"t":"형제가 형제를 아비가 자식을 죽는데 내어주며 자식들이 부모를 대적하여 죽게 하리라"},{"n":13,"t":"또 너희가 내 이름을 인하여 모든 사람에게 미움을 받을 것이나 나중까지 견디는 자는 구원을 얻으리라"},{"n":14,"t":"멸망의 가증한 것이 서지 못할 곳에 선 것을 보거든 (읽는 자는 깨달을진저)그 때에 유대에 있는 자들은 산으로 도망할지어다"},{"n":15,"t":"지붕 위에 있는 자는 내려가지도 말고 집에 있는 무엇을 가지러 들어가지도 말며"},{"n":16,"t":"밭에 있는 자는 겉옷을 가지러 뒤로 돌이키지 말지어다"},{"n":17,"t":"그 날에는 아이 밴 자들과 젖먹이는 자들에게 화가 있으리로다"},{"n":18,"t":"이 일이 겨울에 나지 않도록 기도하라"},{"n":19,"t":"이는 그날들은 환난의 날이 되겠음이라 하나님의 창조하신 창조부터 지금까지 이런 환난이 없었고 후에도 없으리라"},{"n":20,"t":"만일 주께서 그날들을 감하지 아니하셨더면 모든 육체가 구원을 얻지 못할 것이어늘 자기의 택하신 백성을 위하여 그 날들을 감하셨느니라"},{"n":21,"t":"그 때에 사람이 너희에게 말하되 보라 그리스도가 여기 있다 보라 저기 있다 하여도 믿지 말라"},{"n":22,"t":"거짓 그리스도들과 거짓 선지자들이 일어나서 이적과 기사를 행하여 할 수만 있으면 택하신 백성을 미혹케 하려 하리라"},{"n":23,"t":"너희는 삼가라 내가 모든 일을 너희에게 미리 말하였노라"},{"n":24,"t":"그 때에 그 환난 후 해가 어두워지며 달이 빛을 내지 아니하며"},{"n":25,"t":"별들이 하늘에서 떨어지며 하늘에 있는 권능들이 흔들리리라"},{"n":26,"t":"그 때에 인자가 구름을 타고 큰 권능과 영광으로 오는 것을 사람들이 보리라"},{"n":27,"t":"또 그 때에 저가 천사들을 보내어 자기 택하신 자들을 땅 끝으로부터 하늘 끝까지 사방에서 모으리라"},{"n":28,"t":"무화과나무의 비유를 배우라 그 가지가 연하여지고 잎사귀를 내면 여름이 가까운 줄을 아나니"},{"n":29,"t":"이와 같이 너희가 이런 일이 나는 것을 보거든 인자가 가까이 곧 문 앞에 이른 줄을 알라"},{"n":30,"t":"내가 진실로 너희에게 말하노니 이 세대가 지나가기 전에 이 일이 다 이루리라"},{"n":31,"t":"천지는 없어지겠으나 내 말은 없어지지 아니하리라"},{"n":32,"t":"그러나 그 날과 그 때는 아무도 모르나니 하늘에 있는 천사들도 아들도 모르고 아버지만 아시느니라"},{"n":33,"t":"주의하라 깨어 있으라 그 때가 언제인지 알지 못함이니라"},{"n":34,"t":"가령 사람이 집을 떠나 타국으로 갈 때에 그 종들에게 권한을 주어 각각 사무를 맡기며 문지기에게 깨어 있으라 명함과 같으니"},{"n":35,"t":"그러므로 깨어 있으라 집 주인이 언제 올는지 혹 저물 때엘는지 밤중엘는지 닭 울 때엘는지 새벽엘는지 너희가 알지 못함이라"},{"n":36,"t":"그가 홀연히 와서 너희의 자는 것을 보지 않도록 하라"},{"n":37,"t":"깨어 있으라 내가 너희에게 하는 이 말이 모든 사람에게 하는 말이니라 하시니라"}],"kids":[{"n":1,"t":"예수님이 성전에서 나가실 때 제자 중 한 사람이 \\"선생님, 보세요. 이 돌들과 건물들이 얼마나 멋진가요!\\" 하고 말했어요."},{"n":2,"t":"예수님이 \\"이 큰 건물들을 보니? 여기 돌 하나도 돌 위에 남지 않고 다 무너질 거야\\" 하셨어요."},{"n":3,"t":"예수님이 감람산 위 성전 맞은편에 앉아 계실 때 베드로와 야고보와 요한과 안드레가 따로 \\""},{"n":4,"t":"\\"이 일이 언제 일어날까요? 이 모든 일이 이루어지려 할 때의 표적은 무엇이에요?\\" 하고 물었어요."},{"n":5,"t":"예수님이 \\"누가 너희를 미혹하지 못하게 조심해.\\""},{"n":6,"t":"\\"많은 사람이 내 이름으로 와서 \'내가 그다\' 하며 많은 사람을 미혹할 거야.\\""},{"n":7,"t":"\\"전쟁과 전쟁의 소문을 들어도 두려워하지 마. 그런 일이 있어야 하지만 끝은 아직이야.\\""},{"n":8,"t":"\\"민족이 민족을, 나라가 나라를 거슬러 일어나고 여러 곳에 지진과 기근이 있을 거야. 이는 재난의 시작이야.\\""},{"n":9,"t":"\\"너희는 조심해. 사람들이 너희를 공회에 넘기고 회당에서 매질할 거고 너희가 나 때문에 총독과 왕 앞에 서서 그들에게 증거가 될 거야.\\""},{"n":10,"t":"\\"먼저 복음이 모든 민족에게 전파되어야 해.\\""},{"n":11,"t":"\\"끌려갈 때 무엇을 말할까 미리 걱정하지 마. 그 시간에 너희에게 주어지는 그것을 말해. 말하는 이는 너희가 아니라 성령이셔.\\""},{"n":12,"t":"\\"형제가 형제를, 아버지가 자녀를 죽음에 넘기고 자식이 부모를 거슬러 일어나 죽게 할 거야.\\""},{"n":13,"t":"\\"내 이름 때문에 모두에게 미움받겠지만 끝까지 견디는 사람은 구원받을 거야.\\""},{"n":14,"t":"\\"멸망의 가증한 것이 서지 못할 곳에 서 있는 것을 보거든(읽는 사람은 깨달아야 해) 유대에 있는 사람들은 산으로 도망쳐라.\\""},{"n":15,"t":"\\"지붕 위에 있는 사람은 집 안의 무엇을 가지러 내려오거나 들어가지 마.\\""},{"n":16,"t":"\\"밭에 있는 사람도 옷을 가지러 돌아가지 마.\\""},{"n":17,"t":"\\"그날에 아이 밴 사람과 젖 먹이는 사람에게 화가 있을 거야!\\""},{"n":18,"t":"\\"너희가 이 일을 겨울에 만나지 않도록 기도해.\\""},{"n":19,"t":"\\"그날에 환난이 있을 거야. 하나님이 창조하신 처음부터 지금까지 없었고 다시는 없을 환난이.\\""},{"n":20,"t":"\\"주께서 그 날들을 줄이지 않으셨더라면 아무도 구원받지 못할 거야. 그러나 그가 택하신 사람들 때문에 그 날들을 줄이셨어.\\""},{"n":21,"t":"\\"그때 누가 너희에게 \'보라, 여기 그리스도가 있다, 보라, 저기다\' 해도 믿지 마.\\""},{"n":22,"t":"\\"거짓 그리스도와 거짓 예언자가 일어나 표적과 기사를 보여 가능하면 택한 사람도 미혹할 거야.\\""},{"n":23,"t":"\\"너희는 조심해. 내가 모든 것을 너희에게 미리 말했다.\\""},{"n":24,"t":"\\"그 환난 후에 해가 어두워지고 달이 빛을 내지 않으며,\\""},{"n":25,"t":"\\"별들이 하늘에서 떨어지고 하늘의 권능들이 흔들릴 거야.\\""},{"n":26,"t":"\\"그때 사람의 아들이 큰 권능과 영광으로 구름을 타고 오는 것을 보게 될 거야.\\""},{"n":27,"t":"\\"그가 천사들을 보내 사방에서 자기 택하신 사람들을 모을 거야. 땅 끝부터 하늘 끝까지.\\""},{"n":28,"t":"\\"무화과나무로부터 비유를 배워라. 가지가 부드러워지고 잎이 나면 여름이 가까운 줄 알지.\\""},{"n":29,"t":"\\"이처럼 너희도 이런 일이 일어나는 것을 보면 그가 가까이, 곧 문 앞에 있는 줄 알아라.\\""},{"n":30,"t":"\\"진정으로 말한다. 이 세대가 지나기 전에 이 모든 일이 다 일어날 거야.\\""},{"n":31,"t":"\\"하늘과 땅은 사라지지만 내 말은 결코 사라지지 않을 거야.\\""},{"n":32,"t":"\\"그러나 그날과 그때는 아무도 모르고, 하늘에 있는 천사들도 아들도 모르고 아버지만 아셔.\\""},{"n":33,"t":"\\"조심하고 깨어 있어라. 그때가 언제일지 너희가 모르기 때문이야.\\""},{"n":34,"t":"\\"사람이 멀리 떠나며 종들에게 권세를 주고 각자 일을 맡기고 문지기에게는 깨어 있으라 명한 것과 같아.\\""},{"n":35,"t":"\\"그러므로 깨어 있어라. 집주인이 언제 올지, 저녁일지 한밤중일지 닭 우는 때일지 새벽일지 모르거든.\\""},{"n":36,"t":"\\"그가 갑자기 와서 너희가 자는 것을 보지 않게 해라.\\""},{"n":37,"t":"\\"내가 너희에게 하는 말이 모두에게 하는 말이야. 깨어 있어라!\\""}]}},{"chapter":14,"title":"마지막 만찬과 잡히심","verses":{"krv":[{"n":1,"t":"이틀이 지나면 유월절과 무교절이라 대제사장들과 서기관들이 예수를 궤계로 잡아 죽일 방책을 구하며"},{"n":2,"t":"가로되 민요가 날까 하노니 명절에는 말자 하더라"},{"n":3,"t":"예수께서 베다니 문둥이 시몬의 집에서 식사하실 때에 한 여자가 매우 값진 향유 곧 순전한 나드 한 옥합을 가지고 와서 그 옥합을 깨뜨리고 예수의 머리에 부으니"},{"n":4,"t":"어떤 사람들이 분내어 서로 말하되 무슨 의사로 이 향유를 허비하였는가"},{"n":5,"t":"이 향유를 삼백 데나리온 이상에 팔아 가난한 자들에게 줄 수 있었겠도다 하며 그 여자를 책망하는지라"},{"n":6,"t":"예수께서 가라사대 가만 두어라 너희가 어찌하여 저를 괴롭게 하느냐 저가 내게 좋은 일을 하였느니라"},{"n":7,"t":"가난한 자들은 항상 너희와 함께 있으니 아무 때라도 원하는대로 도울 수 있거니와 나는 너희와 항상 함께 있지 아니하리라"},{"n":8,"t":"저가 힘을 다하여 내 몸에 향유를 부어 내 장사를 미리 준비하였느니라"},{"n":9,"t":"내가 진실로 너희에게 이르노니 온 천하에 어디서든지 복음이 전파되는 곳에는 이 여자의 행한 일도 말하여 저를 기념하리라 하시니라"},{"n":10,"t":"열 둘 중에 하나인 가룟 유다가 예수를 넘겨 주려고 대제사장들에게 가매"},{"n":11,"t":"저희가 듣고 기뻐하여 돈을 주기로 약속하니 유다가 예수를 어떻게 넘겨 줄 기회를 찾더라"},{"n":12,"t":"무교절의 첫날 곧 유월절 양 잡는 날에 제자들이 예수께 여짜오되 우리가 어디로 가서 선생님으로 유월절을 잡수시게 예비하기를 원하시나이까 하매"},{"n":13,"t":"예수께서 제자 중에 둘을 보내시며 가라사대 성내로 들어가라 그리하면 물 한 동이를 가지고 가는 사람을 만나리니 그를 따라가서"},{"n":14,"t":"어디든지 그의 들어가는 그 집 주인에게 이르되 선생님의 말씀이 내가 내 제자들과 함께 유월절을 먹을 나의 객실이 어디 있느뇨 하시더라 하라"},{"n":15,"t":"그리하면 자리를 베풀고 예비된 큰 다락방을 보이리니 거기서 우리를 위하여 예비하라 하신대"},{"n":16,"t":"제자들이 나가 성내로 들어가서 예수의 하시던 말씀대로 만나 유월절을 예비하니라"},{"n":17,"t":"저물매 그 열 둘을 데리시고 와서"},{"n":18,"t":"다 앉아 먹을 때에 예수께서 가라사대 내가 진실로 너희에게 이르노니 너희 중에 한 사람 곧 나와 함께 먹는 자가 나를 팔리라 하신대"},{"n":19,"t":"저희가 근심하여 하나씩 하나씩 여짜오되 내니이까"},{"n":20,"t":"이르시되 열 둘 중 하나 곧 나와 함께 그릇에 손을 넣는 자니라"},{"n":21,"t":"인자는 자기에게 대하여 기록된대로 가거니와 인자를 파는 그 사람에게는 화가 있으리로다 그 사람은 차라리 나지 아니하였더면 제게 좋을뻔하였느니라 하시니라"},{"n":22,"t":"저희가 먹을 때에 예수께서 떡을 가지사 축복하시고 떼어 제자들에게 주시며 가라사대 받으라 이것이 내 몸이니라 하시고"},{"n":23,"t":"또 잔을 가지사 사례하시고 저희에게 주시니 다 이를 마시매"},{"n":24,"t":"가라사대 이것은 많은 사람을 위하여 흘리는바 나의 피 곧 언약의 피니라"},{"n":25,"t":"진실로 너희에게 이르노니 내가 포도나무에서 난 것을 하나님 나라에서 새것으로 마시는 날까지 다시 마시지 아니하리라 하시니라"},{"n":26,"t":"이에 저희가 찬미하고 감람산으로 나가니라"},{"n":27,"t":"예수께서 제자들에게 이르시되 너희가 다 나를 버리리라 이는 기록된바 내가 목자를 치리니 양들이 흩어지리라 하였느니라"},{"n":28,"t":"그러나 내가 살아난 후에 너희 보다 먼저 갈릴리로 가리라"},{"n":29,"t":"베드로가 여짜오되 다 버릴찌라도 나는 그렇지 않겠나이다"},{"n":30,"t":"예수께서 가라사대 내가 진실로 네게 이르노니 오늘 이밤 닭이 두번 울기 전에 네가 세번 나를 부인하리라"},{"n":31,"t":"베드로가 힘있게 말하되 내가 주와 함께 죽을지언정 주를 부인하지 않겠나이다 하고 모든 제자도 이와 같이 말하니라"},{"n":32,"t":"저희가 겟세마네라 하는 곳에 이르매 예수께서 제자들에게 이르시되 나의 기도할 동안에 너희는 여기 앉았으라 하시고"},{"n":33,"t":"베드로와 야고보와 요한을 데리고 가실쌔 심히 놀라시며 슬퍼하사"},{"n":34,"t":"말씀하시되 내 마음이 심히 고민하여 죽게 되었으니 너희는 여기 머물러 깨어 있으라 하시고"},{"n":35,"t":"조금 나아가사 땅에 엎드리어 될 수 있는대로 이 때가 자기에게서 지나가기를 구하여"},{"n":36,"t":"가라사대 아바 아버지여 아버지께는 모든 것이 가능하오니 이 잔을 내게서 옮기시옵소서 그러나 나의 원대로 마옵시고 아버지의 원대로 하옵소서 하시고"},{"n":37,"t":"돌아오사 제자들의 자는 것을 보시고 베드로에게 말씀하시되 시몬아 자느냐 네가 한시 동안도 깨어 있을 수 없더냐"},{"n":38,"t":"시험에 들지 않게 깨어 있어 기도하라 마음에는 원이로되 육신이 약하도다 하시고"},{"n":39,"t":"다시 나아가 동일한 말씀으로 기도하시고"},{"n":40,"t":"다시 오사 보신즉 저희가 자니 이는 저희 눈이 심히 피곤함이라 저희가 예수께 무엇으로 대답할 줄을 알지 못하더라"},{"n":41,"t":"세번째 오사 저희에게 이르시되 이제는 자고 쉬라 그만이다 때가 왔도다 보라 인자가 죄인의 손에 팔리우느니라"},{"n":42,"t":"일어나라 함께 가자 보라 나를 파는 자가 가까이 왔느니라"},{"n":43,"t":"말씀하실 때에 곧 열 둘 중의 하나인 유다가 왔는데 대제사장들과 서기관들과 장로들에게서 파송된 무리가 검과 몽치를 가지고 그와 함께 하였더라"},{"n":44,"t":"예수를 파는 자가 이미 그들과 군호를 짜 가로되 내가 입맞추는 자가 그이니 그를 잡아 단단히 끌어가라 하였는지라"},{"n":45,"t":"이에 와서 곧 예수께 나아와 랍비여 하고 입을 맞추니"},{"n":46,"t":"저희가 예수께 손을 대어 잡거늘"},{"n":47,"t":"곁에 섰는 자 중에 한 사람이 검을 빼어 대제사장의 종을 쳐 그 귀를 떨어뜨리니라"},{"n":48,"t":"예수께서 무리에게 말씀하여 가라사대 너희가 강도를 잡는 것 같이 검과 몽치를 가지고 나를 잡으러 나왔느냐"},{"n":49,"t":"내가 날마다 너희와 함께 성전에 있어서 가르쳤으되 너희가 나를 잡지 아니하였도다 그러나 이는 성경을 이루려 함이니라 하시더라"},{"n":50,"t":"제자들이 다 예수를 버리고 도망하니라"},{"n":51,"t":"한 청년이 벗은 몸에 베 홑이불을 두르고 예수를 따라오다가 무리에게 잡히매"},{"n":52,"t":"베 홑이불을 버리고 벗은 몸으로 도망하니라"},{"n":53,"t":"저희가 예수를 끌고 대제사장에게로 가니 대제사장들과 장로들과 서기관들이 다 모이더라"},{"n":54,"t":"베드로가 예수를 멀찍이 좇아 대제사장의 집 뜰안까지 들어가서 하속들과 함께 앉아 불을 쬐더라"},{"n":55,"t":"대제사장들과 온 공회가 예수를 죽이려고 그를 칠 증거를 찾되 얻지 못하니"},{"n":56,"t":"이는 예수를 쳐서 거짓 증거하는 자가 많으나 그 증거가 서로 합하지 못함이라"},{"n":57,"t":"어떤 사람들이 일어나 예수를 쳐서 거짓 증거하여 가로되"},{"n":58,"t":"우리가 그의 말을 들으니 손으로 지은 이 성전을 내가 헐고 손으로 짓지 아니한 다른 성전을 사흘에 지으리라 하더라 하되"},{"n":59,"t":"오히려 그 증거도 서로 합하지 않더라"},{"n":60,"t":"대제사장이 가운데 일어서서 예수에게 물어 가로되 너는 아무 대답도 없느냐 이 사람들의 너를 치는 증거가 어떠하냐 하되"},{"n":61,"t":"잠잠하고 아무 대답도 아니하시거늘 대제사장이 다시 물어 가로되 네가 찬송 받을 자의 아들 그리스도냐"},{"n":62,"t":"예수께서 이르시되 내가 그니라 인자가 권능자의 우편에 앉은 것과 하늘 구름을 타고 오는 것을 너희가 보리라 하시니"},{"n":63,"t":"대제사장이 자기 옷을 찢으며 가로되 우리가 어찌 더 증인을 요구하리요"},{"n":64,"t":"그 참람한 말을 너희가 들었도다 너희는 어떻게 생각하느뇨 하니 저희가 다 예수를 사형에 해당한 자로 정죄하고"},{"n":65,"t":"혹은 그에게 침을 뱉으며 그의 얼굴을 가리우고 주먹으로 치며 가로되 선지자 노릇을 하라 하고 하속들은 손바닥으로 치더라"},{"n":66,"t":"베드로는 아래 뜰에 있더니 대제사장의 비자 하나가 와서"},{"n":67,"t":"베드로의 불 쬠을 보고 주목하여 가로되 너도 나사렛 예수와 함께 있었도다 하거늘"},{"n":68,"t":"베드로가 부인하여 가로되 나는 네 말하는 것이 무엇인지 알지도 못하고 깨닫지도 못하겠노라 하며 앞뜰로 나갈쌔"},{"n":69,"t":"비자가 그를 보고 곁에 서 있는 자들에게 다시 이르되 이 사람은 그 당이라 하되"},{"n":70,"t":"또 부인하더라 조금 후에 곁에 서 있는 사람들이 다시 베드로에게 말하되 너는 갈릴리 사람이니 참으로 그 당이니라"},{"n":71,"t":"베드로가 저주하며 맹세하되 나는 너희의 말하는 이 사람을 알지 못하노라 하니"},{"n":72,"t":"닭이 곧 두번째 울더라 이에 베드로가 예수께서 자기에게 하신 말씀 곧 닭이 두번 울기 전에 네가 세번 나를 부인하리라 하심이 기억되어 생각하고 울었더라"}],"kids":[{"n":1,"t":"이틀 후면 유월절과 무교절이었어요. 대제사장들과 율법 학자들이 어떻게 예수님을 속임수로 잡아 죽일까 의논했어요."},{"n":2,"t":"그들이 \\"명절에는 안 돼. 백성이 소동을 일으킬 거야\\" 했어요."},{"n":3,"t":"예수님이 베다니의 나병 환자 시몬의 집에서 식사하실 때, 한 여자가 매우 값진 순전한 나드 향유 한 옥합을 가지고 와서 옥합을 깨고 예수님의 머리에 부었어요."},{"n":4,"t":"어떤 사람들이 화를 내며 서로 \\"왜 이 향유를 낭비해?\\""},{"n":5,"t":"\\"이것을 삼백 데나리온 이상에 팔아 가난한 사람에게 줄 수 있었는데\\" 하고 그녀를 책망했어요."},{"n":6,"t":"예수님이 \\"가만 두어라. 왜 그녀를 괴롭히니? 그녀가 내게 좋은 일을 했어.\\""},{"n":7,"t":"\\"가난한 사람들은 늘 너희와 함께 있어서 너희가 원할 때 그들에게 잘할 수 있지만, 나는 늘 함께 있지 않아.\\""},{"n":8,"t":"\\"그녀가 할 수 있는 일을 했어. 내 장사를 위해 미리 내 몸에 기름을 부은 거야.\\""},{"n":9,"t":"\\"진정으로 말한다. 온 세상에 어디든 복음이 전파되는 곳마다 이 여자가 한 일도 기억되어 말해질 거야\\" 하셨어요."},{"n":10,"t":"열둘 중 하나인 가룟 유다가 대제사장들에게 가서 예수님을 그들에게 넘기려 했어요."},{"n":11,"t":"그들이 듣고 기뻐하며 돈을 주기로 약속했어요. 유다가 어떻게 그분을 잘 넘길까 기회를 찾았어요."},{"n":12,"t":"무교절 첫날, 곧 유월절 양을 잡는 날, 제자들이 \\"우리가 어디 가서 유월절을 잡수실 준비를 할까요?\\" 하고 물었어요."},{"n":13,"t":"예수님이 제자 둘을 보내며 \\"동네에 들어가면 물병을 가진 한 사람이 만날 거야. 그를 따라가라.\\""},{"n":14,"t":"\\"그가 들어가는 집의 주인에게 \'선생님이 「내가 제자들과 함께 유월절을 먹을 내 객실이 어디 있느냐?」 하셨어요\' 하고 말해라.\\""},{"n":15,"t":"\\"그가 자리가 마련된 큰 다락방을 보여 줄 거야. 거기서 우리를 위해 준비해라\\" 하셨어요."},{"n":16,"t":"제자들이 가서 동네에 들어가 보니 예수님이 말씀하신 대로였어요. 그들이 유월절을 준비했어요."},{"n":17,"t":"저녁이 되자 예수님이 열두 제자와 함께 가셨어요."},{"n":18,"t":"그들이 앉아 먹을 때 예수님이 \\"진정으로 말한다. 너희 중 하나, 곧 나와 함께 먹는 사람이 나를 넘길 거야\\" 하셨어요."},{"n":19,"t":"그들이 슬퍼하며 \\"저는 아니지요?\\" 하고 차례로 묻기 시작했어요."},{"n":20,"t":"예수님이 \\"열둘 중 하나, 나와 함께 그릇에 손을 넣는 사람이야.\\""},{"n":21,"t":"\\"사람의 아들은 자기에 대해 기록된 대로 가지만 사람의 아들을 넘기는 그 사람에게는 화가 있다. 그 사람은 태어나지 않은 게 더 좋았을 거야\\" 하셨어요."},{"n":22,"t":"그들이 먹을 때 예수님이 빵을 가져다 축복하시고 떼어 제자들에게 주며 \\"받아라. 이것은 내 몸이다\\" 하셨어요."},{"n":23,"t":"잔을 가져다 감사하시고 그들에게 주시니, 그들이 다 마셨어요."},{"n":24,"t":"예수님이 \\"이것은 많은 사람을 위해 흘리는 내 언약의 피야.\\""},{"n":25,"t":"\\"진정으로 말한다. 내가 하나님 나라에서 새것으로 마실 그날까지 포도나무의 열매로 만든 것을 다시 마시지 않을 거다\\" 하셨어요."},{"n":26,"t":"그들이 찬송을 부르고 감람산으로 나갔어요."},{"n":27,"t":"예수님이 \\"너희가 다 걸려 넘어질 거야. 기록되었기 때문이야. \'내가 목자를 칠 것이며 양들이 흩어질 거다.\'\\""},{"n":28,"t":"\\"그러나 내가 살아난 후에 너희보다 먼저 갈릴리로 갈 거야\\" 하셨어요."},{"n":29,"t":"베드로가 \\"다른 사람들이 다 걸려 넘어져도 저는 아니에요\\" 하고 말했어요."},{"n":30,"t":"예수님이 \\"진정으로 너에게 말한다. 오늘 밤 닭이 두 번 울기 전에 네가 세 번 나를 부인할 거야\\" 하셨어요."},{"n":31,"t":"베드로가 더 힘껏 \\"제가 주님과 함께 죽을지언정 결코 부인하지 않겠어요\\" 하고 말했고, 모두 그렇게 말했어요."},{"n":32,"t":"그들이 겟세마네라는 곳에 가서 예수님이 제자들에게 \\"내가 기도하는 동안 여기 앉아 있어라\\" 하셨어요."},{"n":33,"t":"베드로와 야고보와 요한을 데리고 가시며 매우 슬퍼하고 괴로워하시며,"},{"n":34,"t":"\\"내 영혼이 죽을 듯이 슬프다. 여기 머물러 깨어 있어라\\" 하셨어요."},{"n":35,"t":"조금 더 나아가 땅에 엎드려 만약 가능하면 이 시간이 자기에게서 지나가게 해 달라고 기도하셨어요."},{"n":36,"t":"\\"아빠 아버지, 모든 것이 아버지께 가능해요. 이 잔을 제게서 거두어 주세요. 그러나 제 원대로가 아니라 아버지 원대로 하세요\\" 하셨어요."},{"n":37,"t":"오셔서 그들이 자고 있는 것을 보시고 베드로에게 \\"시몬아, 자고 있니? 한 시간도 깨어 있을 수 없니?\\""},{"n":38,"t":"\\"깨어 기도해. 시험에 들지 않게 하기 위해서야. 마음은 원하지만 육체가 약해\\" 하셨어요."},{"n":39,"t":"다시 가서 같은 말씀으로 기도하셨어요."},{"n":40,"t":"오셔서 또 그들이 자고 있는 것을 보셨어요. 눈이 무거웠고 무엇이라 대답할지 알지 못했어요."},{"n":41,"t":"세 번째 와서 \\"이제 자고 쉬어라. 됐다. 때가 왔다. 보라, 사람의 아들이 죄인의 손에 넘겨진다.\\""},{"n":42,"t":"\\"일어나라, 가자. 보라, 나를 넘기는 사람이 가까이 왔다\\" 하셨어요."},{"n":43,"t":"말씀하실 때 곧 열둘 중 하나인 유다가 와서 대제사장과 율법 학자와 장로들에게서 보낸 무리가 칼과 몽둥이를 들고 함께 왔어요."},{"n":44,"t":"예수님을 넘기는 사람이 약속한 표를 주며 \\"내가 입맞추는 사람이 그분이다. 잡아 단단히 끌고 가라\\" 했어요."},{"n":45,"t":"와서 곧 예수님께 \\"랍비여\\" 하며 입을 맞췄어요."},{"n":46,"t":"그들이 예수님께 손을 대어 잡았어요."},{"n":47,"t":"옆에 서 있던 한 사람이 칼을 빼서 대제사장의 종을 쳐서 그의 귀를 잘랐어요."},{"n":48,"t":"예수님이 그들에게 \\"너희가 강도 잡듯이 칼과 몽둥이를 가지고 나를 잡으러 나왔니?\\""},{"n":49,"t":"\\"내가 날마다 너희와 함께 성전에 있어 가르쳤지만 너희가 나를 잡지 않았어. 그러나 이는 성경이 이루어지려 함이다\\" 하셨어요."},{"n":50,"t":"모두가 그를 두고 도망쳤어요."},{"n":51,"t":"한 청년이 맨몸에 베 홑이불을 두르고 예수님을 따랐어요. 사람들이 그를 잡으니,"},{"n":52,"t":"그가 홑이불을 두고 벗은 몸으로 도망쳤어요."},{"n":53,"t":"그들이 예수님을 대제사장에게 끌고 가니, 모든 대제사장과 장로와 율법 학자들이 모였어요."},{"n":54,"t":"베드로가 멀찍이서 대제사장의 뜰 안까지 따라가, 종들과 함께 앉아 불을 쬐고 있었어요."},{"n":55,"t":"대제사장과 온 공회가 예수님을 죽이려고 증거를 찾았지만 못 찾았어요."},{"n":56,"t":"많은 사람이 거짓 증언을 했지만 그 증언이 서로 맞지 않았어요."},{"n":57,"t":"어떤 사람들이 일어나 거짓 증언했어요."},{"n":58,"t":"\\"우리가 그가 \'내가 손으로 만든 이 성전을 무너뜨리고 손으로 만들지 않은 다른 성전을 사흘 만에 짓겠다\' 한 말을 들었어요.\\""},{"n":59,"t":"이 증언도 서로 맞지 않았어요."},{"n":60,"t":"대제사장이 가운데 일어나 예수님께 \\"아무 대답도 하지 않니? 이 사람들이 너에게 무엇을 증언하는지?\\" 하고 물었어요."},{"n":61,"t":"예수님은 잠잠하고 아무 답도 하지 않으셨어요. 대제사장이 다시 \\"네가 찬송받으실 분의 아들 그리스도냐?\\" 하고 물었어요."},{"n":62,"t":"예수님이 \\"내가 그다. 너희가 사람의 아들이 권능의 오른편에 앉아 있고 하늘 구름을 타고 오는 것을 볼 거야\\" 하셨어요."},{"n":63,"t":"대제사장이 자기 옷을 찢으며 \\"우리가 무슨 증인이 더 필요해?\\""},{"n":64,"t":"\\"너희가 모독을 들었다. 어떻게 생각하니?\\" 하니 모두 사형에 해당한다고 정죄했어요."},{"n":65,"t":"어떤 사람들이 그분께 침을 뱉고 얼굴을 가리고 주먹으로 치며 \\"예언해라!\\" 하고 말했고, 종들은 손바닥으로 그분을 때렸어요."},{"n":66,"t":"베드로가 뜰 아래 있을 때 대제사장의 종 여자 하나가 와서,"},{"n":67,"t":"베드로가 불을 쬐는 것을 보고 자세히 보며 \\"너도 나사렛 예수와 함께 있었어\\" 하고 말했어요."},{"n":68,"t":"베드로가 부인하며 \\"무슨 말인지 모르고 깨닫지도 못한다\\" 하고 앞뜰로 나갔어요. 닭이 울었어요."},{"n":69,"t":"종 여자가 그를 보고 옆에 서 있는 사람들에게 \\"이 사람은 그들 중 한 명이야\\" 하고 말하기 시작했어요."},{"n":70,"t":"베드로가 또 부인했어요. 잠시 후에 옆에 서 있던 사람들이 다시 \\"분명히 너도 그들 중 하나야. 너도 갈릴리 사람이야\\" 하고 말했어요."},{"n":71,"t":"베드로가 저주하며 맹세하기 시작했어요. \\"너희가 말하는 이 사람을 나는 모른다.\\""},{"n":72,"t":"곧 닭이 두 번째로 울었어요. 베드로가 예수님이 \\"닭이 두 번 울기 전에 네가 세 번 나를 부인할 거다\\" 하신 말씀이 기억나서 울었어요."}]}},{"chapter":15,"title":"십자가에 못 박히심","verses":{"krv":[{"n":1,"t":"새벽에 대제사장들이 즉시 장로들과 서기관들 곧 온 공회로 더불어 의논하고 예수를 결박하여 끌고 가서 빌라도에게 넘겨주니"},{"n":2,"t":"빌라도가 묻되 네가 유대인의 왕이냐 예수께서 대답하여 가라사대 네 말이 옳도다 하시매"},{"n":3,"t":"대제사장들이 여러가지로 고소하는지라"},{"n":4,"t":"빌라도가 또 물어 가로되 아무 대답도 없느냐 저희가 얼마나 많은 것으로 너를 고소하는가 보라 하되"},{"n":5,"t":"예수께서 다시 아무 말씀도 대답지 아니하시니 빌라도가 기이히 여기더라"},{"n":6,"t":"명절을 당하면 백성의 구하는대로 죄수 하나를 놓아 주는 전례가 있더니"},{"n":7,"t":"민란을 꾸미고 이 민란에 살인하고 포박된 자 중에 바라바라 하는 자가 있는지라"},{"n":8,"t":"무리가 나아가서 전례대로 하여주기를 구한대"},{"n":9,"t":"빌라도가 대답하여 가로되 너희는 내가 유대인의 왕을 너희에게 놓아주기를 원하느냐 하니"},{"n":10,"t":"이는 저가 대제사장들이 시기로 예수를 넘겨준줄 앎이러라"},{"n":11,"t":"그러나 대제사장들이 무리를 충동하여 도리어 바라바를 놓아 달라 하게 하니"},{"n":12,"t":"빌라도가 또 대답하여 가로되 그러면 너희가 유대인의 왕이라 하는 이는 내가 어떻게 하랴"},{"n":13,"t":"저희가 다시 소리지르되 저를 십자가에 못 박게 하소서"},{"n":14,"t":"빌라도가 가로되 어찜이뇨 무슨 악한 일을 하였느냐 하니 더욱 소리지르되 십자가에 못 박게 하소서 하는지라"},{"n":15,"t":"빌라도가 무리에게 만족을 주고자 하여 바라바는 놓아 주고 예수는 채찍질하고 십자가에 못 박히게 넘겨주니라"},{"n":16,"t":"군병들이 예수를 끌고 브라이도리온이라는 뜰 안으로 들어가서 온 군대를 모으고"},{"n":17,"t":"예수에게 자색 옷을 입히고 가시 면류관을 엮어 씌우고"},{"n":18,"t":"예하여 가로되 유대인의 왕이여 평안할지어다 하고"},{"n":19,"t":"갈대로 그의 머리를 치며 침을 뱉으며 꿇어 절하더라"},{"n":20,"t":"희롱을 다한 후 자색 옷을 벗기고 도로 그의 옷을 입히고 십자가에 못 박으려고 끌고 나가니라"},{"n":21,"t":"마침 알렉산더와 루포의 아비인 구레네 사람 시몬이 시골로서 와서 지나가는데 저희가 그를 억지로 같이 가게 하여 예수의 십자가를 지우고"},{"n":22,"t":"예수를 끌고 골고다라 하는 곳(번역하면 해골의 곳)에 이르러"},{"n":23,"t":"몰약을 탄 포도주를 주었으나 예수께서 받지 아니하시니라"},{"n":24,"t":"십자가에 못 박고 그 옷을 나눌쌔 누가 어느 것을 얻을까 하여 제비를 뽑더라"},{"n":25,"t":"때가 제 삼시가 되어 십자가에 못 박으니라"},{"n":26,"t":"그 위에 있는 죄 패에 유대인의 왕이라 썼고"},{"n":27,"t":"강도 둘을 예수와 함께 십자가에 못 박으니 하나는 그의 우편에 하나는 좌편에 있더라"},{"n":28,"t":"(없 음)"},{"n":29,"t":"지나가는 자들은 자기 머리를 흔들며 예수를 모욕하여 가로되 아하 성전을 헐고 사흘에 짓는 자여"},{"n":30,"t":"네가 너를 구원하여 십자가에서 내려 오라 하고"},{"n":31,"t":"그와 같이 대제사장들도 서기관들과 함께 희롱하며 서로 말하되 저가 남은 구원하였으되 자기는 구원할 수 없도다"},{"n":32,"t":"이스라엘의 왕 그리스도가 지금 십자가에서 내려와 우리로 보고 믿게 할찌어다 하며 함께 십자가에 못 박힌 자들도 예수를 욕하더라"},{"n":33,"t":"제 육시가 되매 온 땅에 어두움이 임하여 제 구시까지 계속하더니"},{"n":34,"t":"제 구시에 예수께서 크게 소리지르시되 엘리 엘리 라마 사박다니 하시니 이를 번역하면 나의 하나님 나의 하나님 어찌하여 나를 버리셨나이까 하는 뜻이라"},{"n":35,"t":"곁에 섰던 자 중 어떤이들이 듣고 가로되 보라 엘리야를 부른다 하고"},{"n":36,"t":"한 사람이 달려가서 해융에 신포도주를 머금게 하여 갈대에 꿰어 마시우고 가로되 가만 두어라 엘리야가 와서 저를 내려 주나 보자 하더라"},{"n":37,"t":"예수께서 큰 소리를 지르시고 운명하시다"},{"n":38,"t":"이에 성소 휘장이 위로부터 아래까지 찢어져 둘이 되니라"},{"n":39,"t":"예수를 향하여 섰던 백부장이 그렇게 운명하심을 보고 가로되 이 사람은 진실로 하나님의 아들이었도다 하더라"},{"n":40,"t":"멀리서 바라보는 여자들도 있는데 그 중에 막달라 마리아와 또 작은 야고보와 요세의 어머니 마리아와 또 살로메가 있었으니"},{"n":41,"t":"이들은 예수께서 갈릴리에 계실 때에 좇아 섬기던 자요 또 이 외에도 예수와 함께 예루살렘에 올라온 여자가 많이 있었더라"},{"n":42,"t":"이 날은 예비일 곧 안식일 전날이므로 저물었을 때에"},{"n":43,"t":"아리마대 사람 요셉이 와서 당돌히 빌라도에게 들어가 예수의 시체를 달라 하니 이 사람은 존귀한 공회원이요 하나님의 나라를 기다리는 자라"},{"n":44,"t":"빌라도는 예수께서 벌써 죽었을까 하고 이상히 여겨 백부장을 불러 죽은지 오래냐 묻고"},{"n":45,"t":"백부장에게 알아 본 후에 요셉에게 시체를 내어 주는지라"},{"n":46,"t":"요셉이 세마포를 사고 예수를 내려다가 이것으로 싸서 바위 속에 판 무덤에 넣어 두고 돌을 굴려 무덤 문에 놓으매"},{"n":47,"t":"때에 막달라 마리아와 요세의 어머니 마리아가 예수 둔 곳을 보더라"}],"kids":[{"n":1,"t":"새벽이 되자 대제사장들이 장로와 율법 학자와 온 공회와 의논한 후 곧 예수님을 묶어 끌고 빌라도에게 넘겼어요."},{"n":2,"t":"빌라도가 \\"네가 유대인의 왕이니?\\" 하고 물으니, 예수님이 \\"네 말과 같다\\" 하셨어요."},{"n":3,"t":"대제사장들이 많은 것으로 예수님을 고소했어요."},{"n":4,"t":"빌라도가 다시 \\"아무 대답도 안 하니? 그들이 너에게 얼마나 많은 일을 고소하는지 봐\\" 하고 물었어요."},{"n":5,"t":"예수님이 다시 아무 답도 하지 않으시니 빌라도가 이상하게 여겼어요."},{"n":6,"t":"명절마다 그가 사람들이 청하는 죄수 한 사람을 풀어 주는 관례가 있었어요."},{"n":7,"t":"바라바라 하는 사람이 폭동에서 살인한 자들과 함께 묶여 있었어요."},{"n":8,"t":"무리가 올라와 그에게 늘 하던 대로 해 달라고 청하기 시작했어요."},{"n":9,"t":"빌라도가 \\"너희가 유대인의 왕을 풀어 주기를 원하니?\\" 하고 답했어요."},{"n":10,"t":"그는 대제사장들이 시기로 예수님을 넘긴 줄을 알았기 때문이에요."},{"n":11,"t":"대제사장들이 무리를 부추겨 도리어 바라바를 풀어 달라고 청하게 했어요."},{"n":12,"t":"빌라도가 다시 \\"그러면 너희가 유대인의 왕이라 하는 사람은 어떻게 할까?\\" 하고 물었어요."},{"n":13,"t":"그들이 다시 \\"십자가에 못 박으세요!\\" 하고 외쳤어요."},{"n":14,"t":"빌라도가 \\"왜? 그가 무슨 악을 행했니?\\" 하니 그들이 더 크게 \\"십자가에 못 박으세요!\\" 했어요."},{"n":15,"t":"빌라도가 무리를 만족시키려고 바라바를 풀어 주고 예수님을 채찍질한 후 십자가에 못 박도록 넘겼어요."},{"n":16,"t":"군병들이 예수님을 관저 안뜰로 끌고 가서 온 부대를 불러 모았어요."},{"n":17,"t":"그분께 보라색 옷을 입히고 가시관을 엮어 씌우고,"},{"n":18,"t":"\\"유대인의 왕이여, 만세!\\" 하며 인사하기 시작했어요."},{"n":19,"t":"갈대로 그분의 머리를 때리고 침 뱉고 무릎 꿇어 절했어요."},{"n":20,"t":"조롱한 후에 보라색 옷을 벗기고 다시 그분의 옷을 입혀 십자가에 못 박으러 끌고 갔어요."},{"n":21,"t":"마침 시골에서 오는 알렉산더와 루포의 아버지인 구레네 사람 시몬을 지나갈 때, 예수님의 십자가를 강제로 지게 했어요."},{"n":22,"t":"그들이 예수님을 골고다라는 곳, 풀이하면 해골의 곳에 데리고 갔어요."},{"n":23,"t":"그들이 몰약 탄 포도주를 드렸지만 예수님이 받지 않으셨어요."},{"n":24,"t":"그들이 예수님을 십자가에 못 박은 후 제비 뽑아 그분의 옷을 나누어 누가 무엇을 가질지 정했어요."},{"n":25,"t":"제 삼시였어요. 그들이 그분을 십자가에 못 박았어요."},{"n":26,"t":"그분의 죄목 패에 \'유대인의 왕\'이라 적혀 있었어요."},{"n":27,"t":"그들이 예수님과 함께 강도 둘을 십자가에 못 박았어요. 하나는 오른쪽, 하나는 왼쪽이었어요."},{"n":28,"t":"이는 \'그가 죄인들과 함께 헤아림을 받았다\'는 성경이 이루어진 거예요."},{"n":29,"t":"지나가는 사람들이 머리를 흔들며 그분을 모욕했어요. \\"성전을 무너뜨리고 사흘에 짓는 사람아,\\""},{"n":30,"t":"\\"네 자신을 구원해라. 십자가에서 내려와 봐\\" 했어요."},{"n":31,"t":"대제사장들도 율법 학자들과 함께 서로 \\"그가 다른 사람은 구원했지만 자기는 구원하지 못해.\\""},{"n":32,"t":"\\"이스라엘의 왕 그리스도는 지금 십자가에서 내려와라. 우리가 보고 믿게.\\" 함께 못 박힌 사람들도 그분을 욕했어요."},{"n":33,"t":"제 육시부터 제 구시까지 온 땅에 어둠이 덮였어요."},{"n":34,"t":"세 시에 예수님이 큰 소리로 \\"엘로이 엘로이 라마 사박다니!\\" 하셨어요. 풀이하면 \\"내 하나님, 내 하나님, 어찌하여 나를 버리셨나요?\\"예요."},{"n":35,"t":"옆에 서 있던 사람 중 어떤 사람이 듣고 \\"보세요, 엘리야를 부르네\\" 했어요."},{"n":36,"t":"한 사람이 달려가 해면에 신 포도주를 적셔 갈대에 매서 그분께 마시게 했어요. \\"가만 둬. 엘리야가 와서 그를 내려 주는지 보자\\" 했어요."},{"n":37,"t":"예수님이 큰 소리를 지르시고 영혼이 떠나갔어요."},{"n":38,"t":"성전 휘장이 위에서 아래까지 둘로 찢어졌어요."},{"n":39,"t":"맞은편에 서 있던 백부장이 그분이 이렇게 영혼이 떠나가시는 것을 보고 \\"이분은 진실로 하나님의 아들이셨다\\" 하고 말했어요."},{"n":40,"t":"또 여자들이 멀리서 보았는데 그중에 막달라 마리아와 작은 야고보와 요세의 어머니 마리아와 살로메가 있었어요."},{"n":41,"t":"이들은 갈릴리에서 예수님이 계실 때 따르며 섬기던 사람들이고, 그분과 함께 예루살렘에 올라온 다른 많은 사람도 있었어요."},{"n":42,"t":"저녁이 됐는데, 그날은 예비일, 곧 안식일 전날이었어요."},{"n":43,"t":"존경받는 공회원이고 하나님 나라를 기다리던 아리마대 사람 요셉이 담대히 빌라도에게 들어가 예수님의 시신을 청했어요."},{"n":44,"t":"빌라도가 예수님이 벌써 죽으신 것을 이상히 여기고 백부장을 불러 그가 죽은 지 오래되었는지 물었어요."},{"n":45,"t":"백부장에게서 사실을 알고 시신을 요셉에게 내주었어요."},{"n":46,"t":"요셉이 세마포를 사서 그분을 내려 세마포에 싸고 바위에 판 무덤에 두고 무덤 입구에 돌을 굴려 막았어요."},{"n":47,"t":"막달라 마리아와 요세의 어머니 마리아가 그분이 누이신 곳을 보았어요."}]}},{"chapter":16,"title":"부활하신 예수님","verses":{"krv":[{"n":1,"t":"안식일이 지나매 막달라 마리아와 야고보의 어머니 마리아와 또 살로메가 가서 예수께 바르기 위하여 향품을 사다 두었다가"},{"n":2,"t":"안식 후 첫날 매우 일찌기 해 돋은 때에 그 무덤으로 가며"},{"n":3,"t":"서로 말하되 누가 우리를 위하여 무덤 문에서 돌을 굴려 주리요 하더니"},{"n":4,"t":"눈을 들어 본즉 돌이 벌써 굴려졌으니 그 돌이 심히 크더라"},{"n":5,"t":"무덤에 들어가서 흰 옷을 입은 한 청년이 우편에 앉은 것을 보고 놀라매"},{"n":6,"t":"청년이 이르되 놀라지 말라 너희가 십자가에 못 박히신 나사렛 예수를 찾는구나 그가 살아나셨고 여기 계시지 아니하니라 보라 그를 두었던 곳이니라"},{"n":7,"t":"가서 그의 제자들과 베드로에게 이르기를 예수께서 너희보다 먼저 갈릴리로 가시나니 전에 너희에게 말씀하신대로 너희가 거기서 뵈오리라 하라 하는지라"},{"n":8,"t":"여자들이 심히 놀라 떨며 나와 무덤에서 도망하고 무서워하여 아무에게 아무 말도 하지 못하더라"},{"n":9,"t":"예수께서 안식후 첫날 이른 아침에 살아나신 후 전에 일곱 귀신을 쫓아 내어 주신 막달라 마리아에게 먼저 보이시니"},{"n":10,"t":"마리아가 가서 예수와 함께하던 사람들의 슬퍼하며 울고 있는 중에 이 일을 고하매"},{"n":11,"t":"그들은 예수의 살으셨다는 것과 마리아에게 보이셨다는 것을 듣고도 믿지 아니하니라"},{"n":12,"t":"그 후에 저희 중 두 사람이 걸어서 시골로 갈 때에 예수께서 다른 모양으로 저희에게 나타나시니"},{"n":13,"t":"두 사람이 가서 남은 제자들에게 고하였으되 역시 믿지 아니하니라"},{"n":14,"t":"그 후에 열 한 제자가 음식 먹을 때에 예수께서 저희에게 나타나사 저희의 믿음 없는 것과 마음이 완악한 것을 꾸짖으시니 이는 자기의 살아난 것을 본 자들의 말을 믿지 아니함일러라"},{"n":15,"t":"또 가라사대 너희는 온 천하에 다니며 만민에게 복음을 전파하라"},{"n":16,"t":"믿고 세례를 받는 사람은 구원을 얻을 것이요 믿지 않는 사람은 정죄를 받으리라"},{"n":17,"t":"믿는 자들에게는 이런 표적이 따르리니 곧 저희가 내 이름으로 귀신을 쫓아 내며 새 방언을 말하며"},{"n":18,"t":"뱀을 집으며 무슨 독을 마실찌라도 해를 받지 아니하며 병든 사람에게 손을 얹은즉 나으리라 하시더라"},{"n":19,"t":"주 예수께서 말씀을 마치신 후에 하늘로 올리우사 하나님 우편에 앉으시니라"},{"n":20,"t":"제자들이 나가 두루 전파할쌔 주께서 함께 역사하사 그 따르는 표적으로 말씀을 확실히 증거하시니라)"}],"kids":[{"n":1,"t":"안식일이 지나자 막달라 마리아와 야고보의 어머니 마리아와 살로메가 예수님께 가서 바르려고 향품을 샀어요."},{"n":2,"t":"주의 첫날 매우 이른 아침 해가 뜰 때 무덤에 갔어요."},{"n":3,"t":"그들이 서로 \\"누가 우리를 위해 무덤 입구에서 돌을 굴려 내 줄까?\\" 하고 말했어요."},{"n":4,"t":"그러나 그들이 둘러보니 돌이 이미 굴려져 있었어요. 그 돌이 매우 컸어요."},{"n":5,"t":"무덤에 들어가니 흰 옷을 입은 청년이 오른쪽에 앉아 있어서 그들이 놀랐어요."},{"n":6,"t":"청년이 \\"놀라지 마. 너희가 십자가에 못 박히신 나사렛 예수를 찾는구나. 그분이 살아나셨고 여기 안 계신다. 보라, 누이셨던 곳이다.\\""},{"n":7,"t":"\\"가서 그분의 제자들과 베드로에게 \'그분이 너희보다 먼저 갈릴리로 가시니, 거기서 그분을 보게 될 거다. 그분이 너희에게 말씀하신 대로다\' 하고 알려라\\" 하고 말했어요."},{"n":8,"t":"그들이 떨고 놀라 무덤에서 나와 도망쳤어요. 아무에게도 아무 말도 못 했어요. 두려웠기 때문이에요."},{"n":9,"t":"주의 첫날 이른 아침에 살아나신 후 먼저 막달라 마리아에게 보이셨어요. 예수님이 그녀에게서 일곱 귀신을 쫓아내신 적이 있었어요."},{"n":10,"t":"마리아가 가서 함께 슬퍼하고 울고 있는 사람들에게 알렸어요."},{"n":11,"t":"그들이 예수님이 살아나셨고 그녀에게 보이셨다는 말을 듣고 믿지 않았어요."},{"n":12,"t":"이후에 그들 중 두 사람이 들로 가는 길에 예수님이 다른 모습으로 보이셨어요."},{"n":13,"t":"그들이 가서 다른 사람들에게 알렸지만 그들도 믿지 않았어요."},{"n":14,"t":"그 후 예수님이 열한 제자가 식사할 때에 보이시고 그들의 불신과 마음의 굳음을 꾸짖으셨어요. 살아나신 그분을 본 사람들의 말을 믿지 않았기 때문이에요."},{"n":15,"t":"예수님이 그들에게 \\"온 세상에 가서 모든 사람에게 복음을 전파해라.\\""},{"n":16,"t":"\\"믿고 세례 받는 사람은 구원받겠지만 믿지 않는 사람은 정죄당할 거야.\\""},{"n":17,"t":"\\"믿는 사람들에게는 이런 표적이 따를 거야. 내 이름으로 귀신을 쫓아내고 새 방언으로 말하며,\\""},{"n":18,"t":"\\"손으로 뱀을 잡거나 무엇이든 독을 마셔도 해가 없고, 병든 사람에게 손을 얹으면 나을 거야\\" 하셨어요."},{"n":19,"t":"주 예수께서 그들에게 말씀하신 후에 하늘로 올려지셔서 하나님 오른편에 앉으셨어요."},{"n":20,"t":"제자들이 나가 곳곳에 전파하니, 주께서 함께 일하시고 따르는 표적으로 그 말씀을 확증해 주셨어요. 아멘."}]}}]}');

